import type { LearningPathTranslation } from "../types";

export const spanishLearningPaths: Record<string, LearningPathTranslation> = {
  "path-1": {
    title: "Microsoft Defender XDR",
    meta: "6 módulos · 53 unidades · Defender XDR, Defender for Office 365, Entra ID Protection, Defender for Identity y Defender for Cloud Apps",
    focusAreas: [
      { title: "Operaciones de incidentes", description: "Correlacioná, investigá, buscá y corregí amenazas en Defender XDR." },
      { title: "Protección por dominio", description: "Protegé el correo, las identidades, Active Directory, las aplicaciones en la nube y los datos confidenciales." },
    ],
    modules: {
      "module-1": {
        title: "Introducción a la protección contra amenazas de Microsoft Defender XDR",
        units: {
          "xdr-unit-1": { title: "Introducción", bodyHtml: `<p>Microsoft Defender XDR es un conjunto integrado de protección contra amenazas. Detecta actividad en cuatro dominios: <strong>endpoints, identidad, correo electrónico y aplicaciones</strong>. La correlación transforma señales separadas en una historia completa de la cadena de ataque y ayuda a determinar la secuencia, el alcance, las entidades afectadas y la corrección.</p><table><thead><tr><th>Dominio</th><th>Ejemplos</th><th>Valor de seguridad</th></tr></thead><tbody><tr><td>Endpoint</td><td>Estaciones de trabajo y servidores</td><td>Detectar procesos, archivos y comportamientos malintencionados</td></tr><tr><td>Identidad</td><td>Usuarios y Active Directory</td><td>Detectar compromisos de identidad y autenticaciones sospechosas</td></tr><tr><td>Correo</td><td>Mensajes, vínculos y datos adjuntos</td><td>Detectar phishing y contenido malintencionado</td></tr><tr><td>Aplicaciones</td><td>Aplicaciones y sesiones en la nube</td><td>Detectar actividad riesgosa y uso indebido de recursos</td></tr></tbody></table><div class="takeaway"><strong>Clave para el examen:</strong> XDR conecta señales entre dominios para detectar, investigar y responder a ataques como incidentes unificados.</div><div class="resources"><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Introducción</small></span></a><a class="resource" href="https://learn.microsoft.com/en-us/training/wwl-sci/introduction-microsoft-365-threat-protection/media/defend-attack-chains.png" target="_blank" rel="noopener"><span>Diagrama oficial<small>Herramientas de Defender en las cadenas de ataque</small></span></a></div>` },
          "xdr-unit-2": { title: "Explorar casos de uso de respuesta XDR", bodyHtml: `<p>Un archivo adjunto malintencionado puede llegar por correo personal o USB y eludir el flujo protegido de la organización. Cuando se ejecuta, Defender for Endpoint todavía puede detectar la carga. Esto demuestra la defensa en profundidad: un dominio puede detectar un ataque que ingresó por otra ruta.</p><div class="flow" aria-label="Flujo de riesgo del dispositivo y acceso"><div class="flow-step"><strong>1 · Detectar</strong>MDE detecta malware y genera una alerta.</div><div class="flow-step"><strong>2 · Evaluar</strong>Intune recibe la señal de riesgo y marca el dispositivo como no compatible.</div><div class="flow-step"><strong>3 · Restringir</strong>Acceso condicional de Entra bloquea el acceso corporativo.</div><div class="flow-step"><strong>4 · Restaurar</strong>Tras la corrección, se restauran el cumplimiento y el acceso.</div></div><h3>Modos de corrección</h3><ul><li>Corrección totalmente automatizada</li><li>Corrección automatizada con aprobación del analista</li><li>Investigación y corrección manuales</li></ul><p>La información de amenazas también puede enriquecer Microsoft Threat Intelligence y ayudar a detectar variantes relacionadas. La evaluación continua de acceso (CAE) puede aplicar cambios a sesiones activas compatibles.</p><div class="takeaway"><strong>Clave para el examen:</strong> MDE detecta riesgo → Intune evalúa cumplimiento → Acceso condicional restringe o restaura el acceso.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/2-explore-extended-detection-response-use-cases" target="_blank" rel="noopener"><span>Lección oficial<small>Casos de uso de respuesta XDR</small></span></a>` },
          "xdr-unit-3": { title: "Defender XDR en un centro de operaciones de seguridad", bodyHtml: `<p>Defender XDR proporciona detección y respuesta integradas entre los dominios de seguridad de Microsoft; Microsoft Sentinel aporta visibilidad y contexto SIEM más amplios. La estructura depende del tamaño de la organización y los niveles describen funciones especializadas, no una jerarquía de valor.</p><table><thead><tr><th>Función</th><th>Enfoque</th><th>Trabajo habitual</th></tr></thead><tbody><tr><td>Nivel 1 · Triage</td><td>Alertas reactivas de gran volumen</td><td>Revisión rápida, aprobación de correcciones y escalamiento</td></tr><tr><td>Nivel 2 · Investigación</td><td>Incidentes complejos de menor volumen</td><td>Ataques de varias etapas, recursos críticos y corrección avanzada</td></tr><tr><td>Nivel 3 · Búsqueda</td><td>Análisis proactivo basado en hipótesis</td><td>Encontrar amenazas omitidas, análisis forense y mejora de detecciones</td></tr><tr><td>Inteligencia sobre amenazas</td><td>Contexto para todas las funciones</td><td>Investigar actores, campañas, tendencias, técnicas y riesgo estratégico</td></tr></tbody></table><p>Microsoft recomienda un flujo de alertas de alta calidad, aproximadamente <strong>90 % de verdaderos positivos</strong> para alertas que requieren respuesta del analista. La automatización reduce tareas repetitivas y la integración ofrece una consola única.</p><div class="takeaway"><strong>Clave para el examen:</strong> el Nivel 1 realiza triage, el Nivel 2 investiga, el Nivel 3 busca amenazas y la inteligencia enriquece todas las etapas.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/3-understand-defender-security-operations-center" target="_blank" rel="noopener"><span>Lección oficial<small>Defender XDR en un SOC</small></span></a>` },
          "xdr-unit-4": { title: "Explorar Microsoft Security Graph", bodyHtml: `<p>Microsoft Graph es un modelo de programación unificado para datos de Microsoft 365, Windows y Enterprise Mobility + Security. Las API REST y los SDK usan el endpoint <code>https://graph.microsoft.com</code>.</p><p>Microsoft Graph Security API funciona como intermediario: distribuye una solicitud a los proveedores de seguridad aplicables, agrega sus respuestas y devuelve un esquema común. Permite correlación de alertas, transmisión a SIEM, envío de indicadores, contexto de investigación, informes y automatización SecOps.</p><ul><li><strong>v1.0:</strong> superficie estable para producción.</li><li><strong>beta:</strong> capacidades en versión preliminar que pueden cambiar.</li></ul><h3>Búsqueda avanzada mediante Microsoft Graph</h3><pre><code>POST https://graph.microsoft.com/v1.0/security/runHuntingQuery
{
  "Query": "DeviceProcessEvents | where InitiatingProcessFileName =~ &quot;powershell.exe&quot; | project Timestamp, FileName, InitiatingProcessFileName | order by Timestamp desc | limit 2"
}</code></pre><p>La consulta KQL busca eventos de proceso, filtra PowerShell como proceso iniciador, selecciona tres campos, ordena del más reciente al más antiguo y devuelve dos filas.</p><div class="takeaway"><strong>Clave para el examen:</strong> Microsoft Graph es el modelo amplio de API; Graph Security API unifica proveedores; <code>runHuntingQuery</code> ejecuta búsqueda avanzada con KQL.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/4-explore-microsoft-security-graph" target="_blank" rel="noopener"><span>Lección oficial<small>Microsoft Security Graph</small></span></a>` },
          "xdr-unit-5": { title: "Investigar incidentes de seguridad en Defender XDR", bodyHtml: `<p>Esta unidad delega su contenido práctico en una guía interactiva de Microsoft. Demuestra cómo Defender XDR y Microsoft Sentinel trabajan juntos durante una investigación en un entorno híbrido.</p><ol><li>Revisá el incidente unificado y sus alertas.</li><li>Examiná la escala de tiempo, la evidencia y las entidades afectadas.</li><li>Determiná alcance, punto de entrada y estado actual.</li><li>Usá datos de Sentinel cuando necesites contexto híbrido más amplio.</li><li>Contené y corregí la amenaza, documentá hallazgos y cerrá o escalá.</li></ol><div class="takeaway"><strong>Clave para el examen:</strong> Defender XDR aporta detección y respuesta entre dominios; Sentinel aporta contexto SIEM y orquestación más amplios.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/5-investigate-security-incident-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación de incidentes</small></span></a>` },
          "xdr-unit-6": { title: "Evaluación del módulo", bodyHtml: `<div class="answer"><strong>Compromiso de un dominio de Active Directory → Microsoft Defender for Identity</strong><br>Monitorea señales de identidad y actividad asociada a Active Directory local.</div><div class="answer"><strong>Correo de phishing → Microsoft Defender for Office 365</strong><br>Protege el correo y la colaboración frente a vínculos, adjuntos y phishing.</div><div class="answer"><strong>Instalación de malware → Microsoft Defender for Endpoint</strong><br>Detecta y responde a comportamientos malintencionados en endpoints.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/6-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Tres preguntas de comprobación</small></span></a>` },
          "xdr-unit-7": { title: "Resumen y recursos", bodyHtml: `<ul><li>Defender XDR correlaciona señales de endpoints, identidades, correo y aplicaciones.</li><li>Los incidentes unificados ofrecen una historia más clara y mejoran la respuesta.</li><li>Un SOC moderno combina triage, investigación, búsqueda e inteligencia sobre amenazas.</li><li>Sentinel puede agregar visibilidad SIEM más amplia.</li><li>Microsoft Graph habilita integración y automatización programáticas.</li></ul><div class="resources"><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/introduction-microsoft-365-threat-protection/7-summary-resources" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen y recursos</small></span></a><a class="resource" href="https://learn.microsoft.com/en-us/security/adoption/mcra" target="_blank" rel="noopener"><span>Arquitecturas de referencia de ciberseguridad<small>Microsoft MCRA</small></span></a></div>` },
        },
      },
      "module-2": {
        title: "Mitigar incidentes mediante Microsoft Defender",
        focus: "Enfoque: administración unificada de incidentes, investigación y respuesta automatizadas, búsqueda avanzada, informes y configuración del portal de Defender.",
        units: {
          "m2-u1": { title: "Introducción", bodyHtml: `<p>Defender XDR coordina la detección, prevención, investigación y respuesta antes y después de una vulneración. El portal correlaciona alertas de Endpoint, Identity, Cloud Apps y otras cargas en incidentes para mostrar el punto de entrada, alcance, impacto y causa raíz.</p><div class="takeaway"><strong>Clave para el examen:</strong> un incidente es la historia del ataque entre productos; una alerta es una detección dentro de esa historia.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Introducción</small></span></a>` },
          "m2-u2": { title: "Usar el portal de Microsoft Defender", bodyHtml: `<p><code>security.microsoft.com</code> es el área central para seguridad de correo, colaboración, identidad, endpoints, aplicaciones, vulnerabilidades, IoT y Sentinel. El contenido de inicio se adapta al rol mediante RBAC.</p><ul><li>RBAC unificado asigna permisos heredados a grupos comunes para datos, respuesta, postura y configuración.</li><li>Aplicá privilegios mínimos; reservá Administrador global para emergencias.</li><li>La integración con Sentinel sincroniza incidentes y eventos de búsqueda avanzada.</li><li>Los portales relacionados siguen accesibles desde Más recursos.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> distinguí la unificación del portal de los permisos específicos de cada carga.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/2-use-microsoft-security-center-portal" target="_blank" rel="noopener"><span>Lección oficial<small>Portal y RBAC unificado</small></span></a>` },
          "m2-u3": { title: "Administrar incidentes", bodyHtml: `<p>Un incidente agrega alertas correlacionadas que afectan dispositivos, usuarios, buzones y aplicaciones. La cola suele mostrar los últimos 30 días y permite priorizar por gravedad, recursos afectados, orígenes, tácticas, estado y asignación.</p><ul><li>Administrá responsable, estado, etiquetas, nombre, clasificación y determinación.</li><li>Las clasificaciones incluyen verdadero positivo, falso positivo y actividad informativa o esperada.</li><li>La investigación automática puede resolver alertas compatibles; los analistas pueden agregar correcciones.</li><li>El nombre resume endpoints, usuarios, fuentes o categorías afectados.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> una clasificación precisa mejora la calidad y la correlación futuras.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/3-manage-incidents" target="_blank" rel="noopener"><span>Lección oficial<small>Administración de incidentes</small></span></a>` },
          "m2-u4": { title: "Investigar incidentes", bodyHtml: `<p>El resumen muestra categorías asociadas a MITRE ATT&amp;CK, recursos afectados, cronología de alertas, evidencia y estado de corrección. Usá Alertas, Dispositivos, Usuarios, Buzones, Aplicaciones, Investigaciones, Evidencia y respuestas y el grafo del incidente.</p><ul><li>Veredictos de evidencia: Malintencionado, Sospechoso o Limpio.</li><li>El grafo muestra punto de entrada, indicadores, entidades y relaciones.</li><li>El radio de impacto combina el impacto posterior con la posible propagación previa hacia recursos críticos.</li><li>Requiere el lago/grafo de datos de Sentinel y RBAC unificado apropiado.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> usá escala de tiempo y grafo para la secuencia; evidencia y entidades para alcance y corrección.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/4-investigate-incidents" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación y radio de impacto</small></span></a>` },
          "m2-u5": { title: "Administrar e investigar alertas", bodyHtml: `<p>La administración incluye gravedad, categoría, vínculo al incidente, asignación, estado, clasificación, determinación, comentarios e historial. La gravedad refleja el impacto organizacional, no solo la gravedad absoluta del malware en un dispositivo.</p><ul><li>Estados: Nuevo, En curso y Resuelto.</li><li>Las categorías se alinean con tácticas de MITRE ATT&amp;CK e incluyen Malware, Ransomware y Software no deseado.</li><li>La supresión puede aplicarse a un dispositivo o a la organización y afecta coincidencias futuras.</li><li>La historia explica por qué se activó y muestra entidades y eventos.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> resolvé y clasificá después de investigar; usá supresión limitada para actividad benigna conocida.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/5-manage-investigate-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Metadatos, historia, acciones y supresión</small></span></a>` },
          "m2-u6": { title: "Administrar investigaciones automatizadas", bodyHtml: `<p>La investigación y corrección automatizadas (AIR) aplican cuadernos similares al trabajo del analista para inspeccionar alertas, expandirse a dispositivos relacionados, asignar veredictos y ejecutar o recomendar correcciones.</p><ul><li>Vistas: grafo, alertas, dispositivos, evidencia, entidades, registro y acciones pendientes.</li><li>Veredictos: Malintencionado, Sospechoso o No se encontraron amenazas.</li><li>Puede poner archivos en cuarentena, detener servicios y quitar tareas programadas.</li><li>Se recomienda automatización completa; la semiautomática requiere aprobación según el alcance configurado.</li><li>Expandirse a diez o más dispositivos desde la misma entidad requiere aprobación.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> el nivel de automatización determina si AIR corrige automáticamente o espera aprobación.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/6-manage-automated-investigations" target="_blank" rel="noopener"><span>Lección oficial<small>Flujo AIR y niveles de automatización</small></span></a>` },
          "m2-u7": { title: "Usar el centro de acciones", bodyHtml: `<p>El Centro de acciones unificado realiza seguimiento de las correcciones para dispositivos, contenido de correo y colaboración e identidades. <strong>Pendiente</strong> contiene acciones que esperan aprobación; <strong>Historial</strong> es el registro de auditoría de acciones automatizadas, aprobadas, de Live Response y antivirus.</p><ul><li>Aprobá o rechazá correcciones tras revisar evidencia y contexto.</li><li>Algunas acciones completadas, como la cuarentena, pueden deshacerse.</li><li>Verificá siempre si la acción está pendiente, completada, fallida o es reversible.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/7-use-action-center" target="_blank" rel="noopener"><span>Lección oficial<small>Acciones pendientes e históricas</small></span></a>` },
          "m2-u8": { title: "Explorar la búsqueda avanzada", bodyHtml: `<p>La búsqueda avanzada usa KQL para consultar hasta 30 días de datos sin procesar de Defender XDR en Endpoint, Office 365, Cloud Apps e Identity. Los eventos llegan casi en tiempo real; los datos de entidades se actualizan incrementalmente y se consolidan a diario. Las marcas de tiempo están en UTC.</p><ul><li>Familias: <code>Device*</code>, <code>Email*</code>, <code>Identity*</code>, <code>CloudAppEvents</code>, <code>AlertInfo</code> y <code>AlertEvidence</code>.</li><li>Las detecciones personalizadas deben devolver <code>Timestamp</code>, <code>DeviceId</code> y <code>ReportId</code> para acciones sobre dispositivos.</li><li>Las reglas pueden ejecutarse cada 24/12/3/1 horas o continuamente (NRT), crear alertas y actuar sobre dispositivos o archivos.</li><li>El grafo visualiza nodos y relaciones para movimiento lateral y exposición.</li></ul><pre><code>DeviceEvents
| where Timestamp &gt; ago(7d)
| where ActionType == "AntivirusDetection"
| summarize (Timestamp, ReportId)=arg_max(Timestamp, ReportId), count() by DeviceId
| where count_ &gt; 5</code></pre><div class="takeaway"><strong>Clave para el examen:</strong> elegí la tabla correcta, conservá identificadores requeridos, ajustá resultados y configurá frecuencia, entidades, acciones y alcance.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/8-explore-advanced-hunting" target="_blank" rel="noopener"><span>Lección oficial<small>KQL, detecciones personalizadas y grafo</small></span></a>` },
          "m2-u9": { title: "Investigar los registros de inicio de sesión de Microsoft Entra", bodyHtml: `<table><thead><tr><th>Ubicación</th><th>Tabla KQL</th></tr></thead><tbody><tr><td>Búsqueda avanzada de Defender XDR</td><td><code>AADSignInEventsBeta</code></td></tr><tr><td>Log Analytics de Entra ID</td><td><code>SigninLogs</code></td></tr></tbody></table><p>Revisá fecha, usuario, aplicación, estado, resultado de Acceso condicional, ubicación, dispositivo y detalles de autenticación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/9-investigate-azure-ad-sign-in-logs" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación de inicios de sesión</small></span></a>` },
          "m2-u10": { title: "Comprender la Puntuación de seguridad de Microsoft", bodyHtml: `<p>La Puntuación de seguridad mide la postura y la implementación de acciones recomendadas en identidades, aplicaciones, dispositivos, correo e integraciones de terceros. Es una herramienta de Administración de exposición, no prueba que la organización esté libre de vulneraciones.</p><p>Los estados incluyen Pendiente, Planeado, Riesgo aceptado, Resuelto mediante terceros, Resuelto mediante mitigación alternativa y Completado.</p><div class="takeaway"><strong>Clave para el examen:</strong> una puntuación mayor significa más recomendaciones abordadas; usalas para priorizar mejoras.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/10-understand-microsoft-secure-score" target="_blank" rel="noopener"><span>Lección oficial<small>Puntuación y acciones recomendadas</small></span></a>` },
          "m2-u11": { title: "Agente de resumen de inteligencia sobre amenazas", bodyHtml: `<p>El agente integrado de Security Copilot genera informes priorizados a partir de actividad reciente de actores y del contexto de vulnerabilidades de la organización. Resume amenazas, exposiciones e impacto empresarial, conserva informes en Actividad de Security Copilot y permite revisar su actividad.</p><ul><li>Requiere Security Copilot, complementos de Microsoft Threat Intelligence, acceso a Defender Vulnerability Management y permisos adecuados.</li><li>Los informes pueden copiarse o descargarse como Markdown.</li><li>Los analistas deben revisar el razonamiento y aportar comentarios.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/11-analyze-threat-analytics" target="_blank" rel="noopener"><span>Lección oficial<small>Agente de resumen de inteligencia</small></span></a>` },
          "m2-u12": { title: "Analizar informes", bodyHtml: `<p>La sección Informes centraliza tendencias de seguridad e informes de endpoints, correo y colaboración. Los informes de endpoints cubren protección contra amenazas, estado de dispositivos, vulnerabilidades, protección web, firewall, control de dispositivos y reducción de superficie de ataque. Los de correo pueden programarse o descargarse.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/12-analyze-reports" target="_blank" rel="noopener"><span>Lección oficial<small>Informes de Defender</small></span></a>` },
          "m2-u13": { title: "Configurar el portal de Microsoft Defender", bodyHtml: `<p>Las notificaciones por correo de Defender XDR tienen dos tipos principales: <strong>Incidentes</strong> para incidentes nuevos e <strong>Inteligencia sobre amenazas</strong> para informes nuevos. Configurá criterios y destinatarios en Configuración → Microsoft Defender XDR → Notificaciones por correo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/13-configure-microsoft-365-defender-portal" target="_blank" rel="noopener"><span>Lección oficial<small>Reglas de notificación por correo</small></span></a>` },
          "m2-u14": { title: "Evaluación del módulo", bodyHtml: `<div class="answer"><strong>Pestaña de la página del incidente → Recursos</strong></div><div class="answer"><strong>Clasificación del incidente → Verdadero positivo</strong></div><div class="answer"><strong>Origen de la página Dispositivos → Microsoft Defender for Endpoint</strong></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/14-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Tres preguntas</small></span></a>` },
          "m2-u15": { title: "Resumen y recursos", bodyHtml: `<p>Deberías poder administrar e investigar incidentes y alertas de Defender XDR, revisar acciones automatizadas, buscar con KQL y configurar el portal.</p><div class="resources"><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/mitigate-incidents-microsoft-365-defender/15-summary-resources" target="_blank" rel="noopener"><span>Resumen oficial<small>Recursos del módulo</small></span></a><a class="resource" href="https://attack.mitre.org/matrices/enterprise/" target="_blank" rel="noopener"><span>MITRE ATT&amp;CK Enterprise<small>Marco externo referenciado por Microsoft</small></span></a></div>` },
        },
      },
      "module-3": {
        title: "Corregir amenazas mediante Microsoft Defender",
        focus: "Enfoque: Defender for Office 365, AIR, Safe Attachments, Safe Links, protección contra phishing, triage con Security Copilot y simulación de ataques.",
        units: {
          "m3-u1": { title: "Introducción a Defender for Office 365", bodyHtml: `<p>Defender for Office 365 es un servicio de seguridad de correo en la nube que proporciona protección contra malware de día cero, defensa de URL al hacer clic, investigación, informes, respuesta automatizada y capacitación de usuarios. Puede proteger Exchange Online, entornos SMTP locales e implementaciones híbridas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Capacidades de Defender for Office 365</small></span></a>` },
          "m3-u2": { title: "Automatizar, investigar y corregir", bodyHtml: `<p>Los cuadernos de AIR de Office 365 comienzan automáticamente desde alertas o manualmente desde Explorer. El grafo de investigación correlaciona URL, mensajes, usuarios, inicios de sesión, dispositivos y actividades.</p><ul><li>Acciones posibles: eliminación temporal de mensajes o clústeres, bloqueo de URL al hacer clic, deshabilitación del reenvío externo y eliminación de delegación.</li><li>Los flujos de usuarios comprometidos pueden iniciar el restablecimiento de contraseña y MFA.</li><li>Las acciones pueden ejecutarse automáticamente o esperar aprobación en Acciones pendientes.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/automate-investigate-remediate" target="_blank" rel="noopener"><span>Lección oficial<small>AIR y corrección de Office 365</small></span></a>` },
          "m3-u3": { title: "Configurar, proteger y detectar", bodyHtml: `<h3>Safe Attachments</h3><p>Los datos adjuntos desconocidos se detonan en un entorno aislado. Las acciones incluyen Desactivado, Monitorear, Bloquear, Reemplazar y Entrega dinámica. Esta última libera primero el cuerpo y adjunta el archivo después de un veredicto seguro.</p><h3>Safe Links</h3><p>Las URL se reescriben y comprueban al hacer clic en correo, aplicaciones de Office y Teams. Las directivas pueden examinar descargas, proteger mensajes internos, realizar seguimiento, impedir que el usuario continúe y excluir URL confiables.</p><h3>Protección contra phishing</h3><p>Las directivas detectan suplantación de usuarios o dominios y spoofing mediante ML, usuarios y dominios protegidos, acciones, sugerencias de seguridad y remitentes confiables.</p><div class="takeaway"><strong>Clave para el examen:</strong> Safe Attachments protege archivos; Safe Links protege URL; la protección contra phishing combate spoofing y suplantación.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/configure-protect-detect" target="_blank" rel="noopener"><span>Lección oficial<small>Directivas y guía interactiva</small></span></a>` },
          "m3-u4": { title: "Agente de triage de phishing de Security Copilot", bodyHtml: `<p>El agente analiza mensajes sospechosos informados por usuarios, aplica razonamiento contextual con LLM y clasifica las alertas como phishing verdadero o falsos positivos. Registra el motivo, se asigna, etiqueta incidentes, resuelve falsos positivos y deja abiertos los verdaderos positivos.</p><ul><li>Requiere capacidad de Security Copilot, Defender for Office 365 Plan 2, RBAC unificado, monitoreo de mensajes informados y la directiva de alertas correspondiente.</li><li>El agente no clasifica alertas suprimidas.</li><li>Los comentarios del analista ayudan a mejorar clasificaciones futuras.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/phishing-triage-agent" target="_blank" rel="noopener"><span>Lección oficial<small>Agente de triage de phishing</small></span></a>` },
          "m3-u5": { title: "Simular ataques", bodyHtml: `<p>Explorador de amenazas analiza amenazas recientes, familias, usuarios objetivo, remitentes, acciones de entrega e interacción. Entrenamiento de simulación de ataque ejecuta escenarios como spear phishing, recolección de credenciales, adjuntos malintencionados, password spray y fuerza bruta para identificar debilidades y capacitar usuarios.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/simulate-attacks" target="_blank" rel="noopener"><span>Lección oficial<small>Explorador y simulaciones de ataque</small></span></a>` },
          "m3-u6": { title: "Resumen y comprobación de conocimientos", bodyHtml: `<div class="answer"><strong>Requiere agente de endpoint → Falso</strong><br>Defender for Office 365 es un servicio de seguridad de correo en la nube.</div><div class="answer"><strong>Safe Attachments → enruta mensajes y adjuntos a un entorno de análisis aislado</strong></div><div class="answer"><strong>No es un escenario del simulador → Minería de Bitcoin</strong></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-remediate/summary-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Resumen y tres preguntas</small></span></a>` },
        },
      },
      "module-4": {
        title: "Administrar Microsoft Entra ID Protection",
        focus: "Enfoque: detección de riesgo de identidad, Acceso condicional basado en riesgo, registro de MFA, investigación de usuarios riesgosos, identidades de carga de trabajo y agentes de riesgo.",
        units: {
          "m4-u1": { title: "Introducción", bodyHtml: `<p>Identity Protection analiza el comportamiento y los patrones de inicio de sesión para detectar riesgo de identidad. El módulo cubre detecciones, directivas de riesgo de usuario e inicio de sesión, registro de MFA, investigación, identidades de carga de trabajo, Defender for Identity y el agente de administración de riesgos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Introducción a Identity Protection</small></span></a>` },
          "m4-u2": { title: "Revisar los conceptos básicos de Identity Protection", bodyHtml: `<p>Identity Protection automatiza la detección y corrección, permite investigar desde el portal y exporta datos de riesgo a SIEM y herramientas de terceros. Las capacidades completas requieren Microsoft Entra ID Premium P2.</p><table><thead><tr><th>Detección</th><th>Significado</th></tr></thead><tbody><tr><td>IP anónima o malintencionada</td><td>Inicio desde anonimizadores o infraestructura malintencionada</td></tr><tr><td>Viaje atípico / propiedades desconocidas</td><td>Difiere de la ubicación, dispositivo, navegador o red habituales</td></tr><tr><td>Credenciales filtradas / password spray</td><td>Credenciales expuestas o contraseñas comunes probadas entre cuentas</td></tr><tr><td>Token anómalo / emisor anómalo</td><td>Propiedades, reproducción o comportamiento SAML sospechosos</td></tr><tr><td>Inteligencia sobre amenazas</td><td>Coincide con patrones o actores conocidos por Microsoft</td></tr></tbody></table><p>Administrador de seguridad tiene acceso amplio; Operador puede investigar y confirmar actividad segura o comprometida, pero no configurar directivas ni restablecer contraseñas; Lector es de solo lectura.</p><div class="takeaway"><strong>Clave para el examen:</strong> las señales de riesgo alimentan Acceso condicional; P2 habilita directivas e informes completos.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/2-review-identity-protection-basics" target="_blank" rel="noopener"><span>Lección oficial<small>Riesgos, roles y licencias</small></span></a>` },
          "m4-u3": { title: "Implementar y administrar la directiva de riesgo de usuario", bodyHtml: `<ul><li><strong>Riesgo de inicio de sesión</strong> estima si una autenticación fue realizada por alguien distinto del usuario legítimo.</li><li><strong>Riesgo de usuario</strong> estima si la cuenta está comprometida.</li></ul><p>Para autocorregirse, los usuarios deben estar registrados en MFA y SSPR. Microsoft recomienda riesgo de usuario Alto y riesgo de inicio de sesión Medio o superior. Excluí cuentas de acceso de emergencia y revisá las exclusiones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/3-implement-manage-user-risk-policy" target="_blank" rel="noopener"><span>Lección oficial<small>Diseño e implementación de directivas</small></span></a>` },
          "m4-u4": { title: "Ejercicio: habilitar directivas de riesgo", bodyHtml: `<div class="flow" aria-label="Controles de directivas de riesgo"><div class="flow-step"><strong>Riesgo de usuario</strong>Alto → exigir cambio de contraseña seguro.</div><div class="flow-step"><strong>Riesgo de inicio</strong>Medio o superior → exigir MFA.</div><div class="flow-step"><strong>Asignaciones</strong>Definir usuarios/grupos y excluir cuentas de emergencia.</div><div class="flow-step"><strong>Implementación</strong>Probar, habilitar, monitorear y ajustar.</div></div><p>Usá el Centro de administración de Entra en Identidad → Protección → Identity Protection. Aunque la interfaz también muestra controles de bloqueo, Microsoft recomienda permitir acceso con cambio de contraseña para riesgo de usuario y MFA para riesgo de inicio.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/4-exercise-enable-sign-risk-policy" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Directivas de usuario e inicio de sesión</small></span></a>` },
          "m4-u5": { title: "Ejercicio: directiva de registro de MFA", bodyHtml: `<p>La directiva garantiza que los usuarios registren un segundo factor antes de un evento riesgoso. En Identity Protection, asigná usuarios o grupos, conservá el control fijo <em>Requerir registro de autenticación multifactor de Microsoft Entra ID</em>, habilitá y guardá.</p><div class="takeaway"><strong>Clave para el examen:</strong> el registro es requisito previo para satisfacer MFA y autocorregir riesgos.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/5-exercise-configure-multi-factor-authentication-registration-policy" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Directiva de registro de MFA</small></span></a>` },
          "m4-u6": { title: "Monitorear, investigar y corregir usuarios riesgosos", bodyHtml: `<table><thead><tr><th>Informe</th><th>Propósito</th><th>Retención mostrada</th></tr></thead><tbody><tr><td>Usuarios riesgosos</td><td>Estado, historial, detecciones y corrección</td><td>Vista actual/histórica</td></tr><tr><td>Inicios riesgosos</td><td>Riesgo, Acceso condicional, MFA, dispositivo, aplicación y ubicación</td><td>Hasta 30 días</td></tr><tr><td>Detecciones de riesgo</td><td>Tipos individuales, ubicación y riesgos relacionados</td><td>Hasta 90 días</td></tr></tbody></table><p>Las opciones incluyen autocorrección por directiva, restablecimiento de contraseña, confirmar compromiso o seguridad, descartar riesgo, bloquear inicio o cerrar detecciones. Descartar no cambia una contraseña expuesta: hacelo solo cuando el riesgo sea falso o ya esté tratado.</p><div class="takeaway"><strong>Clave para el examen:</strong> MFA + SSPR habilitan autocorrección; investigá antes de descartar.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/6-monitor-investigate-remediate-elevated-risky-users" target="_blank" rel="noopener"><span>Lección oficial<small>Informes, investigación y corrección</small></span></a>` },
          "m4-u7": { title: "Implementar seguridad para identidades de carga de trabajo", bodyHtml: `<p>Las identidades de carga de trabajo representan aplicaciones, entidades de servicio e identidades administradas. No pueden realizar MFA, suelen carecer de gobernanza de ciclo de vida y deben almacenar credenciales, lo que aumenta el riesgo.</p><ul><li>Las detecciones incluyen inteligencia sobre amenazas, inicios sospechosos, adiciones inusuales de credenciales OAuth, compromiso confirmado y credenciales filtradas.</li><li>Requiere Entra ID Premium P2 y un rol de seguridad apropiado.</li><li>Acceso condicional puede bloquear entidades de servicio de un solo tenant riesgosas; aplicaciones multi-tenant, SaaS de terceros e identidades administradas quedan fuera de ese alcance.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/7-implement-security-workload-identities" target="_blank" rel="noopener"><span>Lección oficial<small>Riesgo de identidades de carga de trabajo</small></span></a>` },
          "m4-u8": { title: "Explorar Microsoft Defender for Identity", bodyHtml: `<p>Defender for Identity usa señales de Active Directory local para detectar identidades comprometidas y amenazas internas. Sensores en controladores de dominio y AD FS observan tráfico y autenticaciones, envían datos analizados al servicio en la nube y muestran incidentes en el portal de Defender.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/8-explore-microsoft-defender-identity" target="_blank" rel="noopener"><span>Lección oficial<small>Flujo y componentes de MDI</small></span></a>` },
          "m4-u9": { title: "Explorar el agente de administración de riesgos de identidad", bodyHtml: `<p>El agente de Security Copilot examina usuarios en riesgo, investiga inicios y detecciones, genera un resumen y veredicto y sugiere correcciones como descartar riesgo o restablecer contraseña.</p><ul><li>Requiere Entra ID P2, unidades de proceso de seguridad y roles apropiados.</li><li>Desencadenadores: continuo cada cinco minutos, diario o manual.</li><li>Alcance: usuarios/grupos, nivel de riesgo, hasta 100 usuarios recientes y 90 días.</li><li>Lector puede ver; Administrador de seguridad activa y ejecuta acciones.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> las sugerencias aceleran la revisión, pero siguen gobernadas por alcance, permisos y acción del analista.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/8a-identity-risk-management-agent" target="_blank" rel="noopener"><span>Lección oficial<small>Agente de administración de riesgos</small></span></a>` },
          "m4-u10": { title: "Evaluación del módulo", bodyHtml: `<div class="answer"><strong>Tarea del Operador de seguridad → Confirmar inicio de sesión seguro</strong></div><div class="answer"><strong>Segunda directiva de riesgo → Directiva de riesgo de inicio de sesión</strong></div><div class="answer"><strong>API de Graph → riskDetection, riskyUsers, signIns</strong></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/9-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Tres preguntas</small></span></a>` },
          "m4-u11": { title: "Resumen y recursos", bodyHtml: `<p>Revisá directivas de riesgo, registro combinado de MFA/SSPR, cuentas de emergencia, identidades administradas, corrección de riesgos, notificaciones y Defender for Identity.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-azure-active-directory-identity-protection/10-summary-resources" target="_blank" rel="noopener"><span>Resumen oficial<small>Ocho recursos de Microsoft</small></span></a>` },
        },
      },
      "module-5": {
        title: "Proteger el entorno con Microsoft Defender for Identity",
        focus: "Enfoque: postura de identidad, sensores, detección de ataques a Active Directory, investigación, corrección e integraciones XDR.",
        units: {
          "m5-u1": { title: "Introducción a Defender for Identity", bodyHtml: `<p>Defender for Identity monitorea señales de identidad de AD local, Entra ID y proveedores compatibles. Crea líneas base, detecta anomalías, muestra debilidades de postura en Puntuación de seguridad e identifica etapas desde reconocimiento hasta dominio del entorno.</p><ul><li>Reconocimiento: enumeración LDAP o SMB sospechosa.</li><li>Compromiso de credenciales: fuerza bruta y password spray.</li><li>Movimiento lateral: pass-the-ticket y overpass-the-hash.</li><li>Dominio: DCShadow o controlador de dominio malintencionado.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> MDI combina evaluación de postura con detección en toda la cadena de ataque de identidad.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-safeguard/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Capacidades, postura y técnicas</small></span></a>` },
          "m5-u2": { title: "Configurar sensores de Defender for Identity", bodyHtml: `<p>Los sensores capturan tráfico de controladores de dominio, reciben eventos de Windows y RADIUS, resuelven usuarios, grupos y equipos y envían datos analizados al servicio en la nube.</p><ul><li>Administrá en Portal de Defender → Configuración → Identidades → Local → Sensores.</li><li>Tipos: controlador de dominio, AD FS, independiente, Entra Connect y AD CS.</li><li>Los independientes requieren FQDN de DC y adaptadores de captura; incluí al menos un catálogo global.</li><li>Validá el servicio y el registro de errores; verificá consultas DNS como <code>MdiDnsQuery</code>.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-safeguard/configure-sensors" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura, configuración y validación</small></span></a>` },
          "m5-u3": { title: "Revisar cuentas o datos comprometidos", bodyHtml: `<p>Las alertas de MDI incluyen título, descripción, evidencia, entidades afectadas y exportación a Excel. La investigación sigue reconocimiento → compromiso de credenciales → movimiento lateral → dominio → filtración.</p><p>El escenario conecta reconocimiento SMB, overpass-the-hash, pass-the-ticket, ejecución remota y creación de una cuenta privilegiada. La habilidad clave es correlacionar alertas separadas en una secuencia coherente e identificar dónde contener.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-safeguard/review-compromised-accounts" target="_blank" rel="noopener"><span>Lección oficial<small>Escenario de dominio comprometido</small></span></a>` },
          "m5-u4": { title: "Integrar con otras herramientas de Microsoft", bodyHtml: `<p>MDI aporta señales de identidad local y de Entra a los incidentes y grafos unificados de Defender XDR. Defender for Endpoint agrega contexto de procesos; Cloud Apps agrega actividad en la nube; Security Copilot permite triage en lenguaje natural.</p><p>También admite plataformas PAM como CyberArk, Delinea y BeyondTrust, además de actividad de Okta.</p><div class="takeaway"><strong>Clave para el examen:</strong> MDI se integra de forma nativa en Defender XDR y correlaciona automáticamente alertas de identidad, endpoints y nube.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-safeguard/integrate-microsoft-tools" target="_blank" rel="noopener"><span>Lección oficial<small>XDR, Endpoint, Cloud Apps, PAM, Okta y Copilot</small></span></a>` },
          "m5-u5": { title: "Resumen y comprobación de conocimientos", bodyHtml: `<div class="answer"><strong>Requiere Active Directory local → Verdadero</strong><br>La protección basada en sensores monitorea la infraestructura de identidad local.</div><div class="answer"><strong>Categoría de amenaza avanzada → Reconocimiento</strong></div><div class="answer"><strong>No figura como integración de MDI → Intune</strong></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-threat-safeguard/summary-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Resumen y tres preguntas</small></span></a>` },
        },
      },
      "module-6": {
        title: "Proteger aplicaciones y servicios en la nube con Microsoft Defender for Cloud Apps",
        focus: "Enfoque: arquitectura CASB, Cloud Discovery, control de aplicaciones de Acceso condicional, protección de información y detección de anomalías.",
        units: {
          "m6-u1": { title: "Introducción", bodyHtml: `<p>Defender for Cloud Apps equilibra productividad con visibilidad, control del movimiento de datos y análisis de amenazas. Cubre detección de Shadow IT, controles de acceso y sesión en tiempo real, protección de información confidencial y detección de anomalías.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de Cloud Apps</small></span></a>` },
          "m6-u2": { title: "Comprender el marco de Defender for Cloud Apps", bodyHtml: `<p>Defender for Cloud Apps es un agente de seguridad de acceso a la nube (CASB), un punto de aplicación entre usuarios y proveedores. Sus cuatro pilares son:</p><ol><li><strong>Detectar y controlar Shadow IT</strong> en SaaS, IaaS y PaaS.</li><li><strong>Proteger información confidencial</strong> con clasificación y DLP.</li><li><strong>Proteger frente a amenazas y anomalías</strong> con UEBA, ML y reglas.</li><li><strong>Evaluar el cumplimiento de aplicaciones</strong> frente a requisitos organizacionales y regulatorios.</li></ol><div class="takeaway"><strong>Clave para el examen:</strong> recordá los cuatro pilares y el rol intermediario de CASB.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/cloud-app-security-framework" target="_blank" rel="noopener"><span>Lección oficial<small>CASB y el marco de cuatro partes</small></span></a>` },
          "m6-u3": { title: "Explorar aplicaciones en la nube con Cloud Discovery", bodyHtml: `<p>Cloud Discovery analiza registros de tráfico frente a un catálogo de más de 16.000 aplicaciones y las puntúa usando más de 80 factores de riesgo. El panel resume uso, alertas, riesgo, usuarios, IP, categorías y sede de la aplicación.</p><ol><li>Revisá uso y principales usuarios o IP.</li><li>Analizá categorías y uso autorizado.</li><li>Inspeccioná aplicaciones y puntuaciones de 1 a 10.</li><li>Marcá aplicaciones riesgosas como No autorizadas.</li><li>Usá la integración con Endpoint para bloquearlas automáticamente.</li></ol><div class="takeaway"><strong>Clave para el examen:</strong> Cloud Discovery aporta visibilidad retrospectiva; la autorización controla el riesgo conocido.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/cloud-discovery" target="_blank" rel="noopener"><span>Lección oficial<small>Shadow IT y riesgo de aplicaciones</small></span></a>` },
          "m6-u4": { title: "Control de aplicaciones de Acceso condicional", bodyHtml: `<p>El control de aplicaciones usa una sesión de proxy inverso para aplicar controles en tiempo real. Acceso condicional de Entra decide quién, qué y dónde; las sesiones aptas se enrutan por Cloud Apps para aplicar directivas.</p><ul><li>Bloquear descarga, copia, corte o impresión en dispositivos no administrados.</li><li>Proteger archivos al descargarlos con clasificación y cifrado.</li><li>Bloquear carga de archivos sin etiqueta.</li><li>Monitorear sesiones y acciones riesgosas.</li><li>Bloquear acceso o actividades específicas, como mensajes de Teams con datos confidenciales.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> Acceso condicional determina el enrutamiento; Cloud Apps aplica controles de sesión.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/conditional-access-app-control" target="_blank" rel="noopener"><span>Lección oficial<small>Directivas de acceso y sesión</small></span></a>` },
          "m6-u5": { title: "Recorrido por detección y control de acceso", bodyHtml: `<p>El recorrido demuestra Cloud Discovery y el control de aplicaciones en Defender XDR: detectar uso, evaluar riesgo, enrutar sesiones mediante el proxy y aplicar controles a actividad confidencial.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/walkthrough" target="_blank" rel="noopener"><span>Lección oficial<small>Recorrido de protección de aplicaciones</small></span></a>` },
          "m6-u6": { title: "Clasificar y proteger información confidencial", bodyHtml: `<div class="flow" aria-label="Fases de protección de información"><div class="flow-step"><strong>1 · Detectar</strong>Conectar aplicaciones y examinar datos.</div><div class="flow-step"><strong>2 · Clasificar</strong>Usar tipos de información y etiquetas.</div><div class="flow-step"><strong>3 · Proteger</strong>Aplicar directivas y acciones de gobernanza.</div><div class="flow-step"><strong>4 · Monitorear</strong>Investigar alertas e informar.</div></div><p>Las directivas pueden alertar, cambiar el uso compartido, poner en cuarentena, quitar permisos o enviar contenido a la papelera. DLP y los Servicios de clasificación inspeccionan contenido; Microsoft recomienda DCS para unificar etiquetas de Microsoft 365.</p><p>Etiquetas comunes: Personal, Público, General, Confidencial y Altamente confidencial. Usá filtros limitados para reducir falsos positivos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/classify-protect-sensitive-information" target="_blank" rel="noopener"><span>Lección oficial<small>Detección, clasificación, protección y monitoreo</small></span></a>` },
          "m6-u7": { title: "Detectar amenazas", bodyHtml: `<p>Las directivas de anomalías usan UEBA y ML para comparar actividad con líneas base. El servicio aprende el entorno durante los primeros siete días. La detección no es determinista y debe ajustarse para controlar falsos positivos.</p><ul><li>Factores: reputación de IP, errores, actividad administrativa, cuentas inactivas, ubicación, viaje imposible, dispositivo o agente y velocidad de actividad.</li><li>Detecciones: viaje imposible, país infrecuente, malware, ransomware, IP sospechosas, reenvío de bandeja, descargas masivas y administración inusual.</li><li>Las anomalías de Discovery comparan aumentos repentinos de uso, carga, descarga, transacciones o usuarios con la línea base.</li><li>Supresión y sensibilidad ayudan a controlar la fatiga.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> la detección depende del desvío respecto del comportamiento aprendido, no solo de una firma fija.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/detect-threats" target="_blank" rel="noopener"><span>Lección oficial<small>UEBA, anomalías y ajuste</small></span></a>` },
          "m6-u8": { title: "Evaluación del módulo", bodyHtml: `<div class="answer"><strong>Uso de aplicaciones de un vistazo → Panel de Cloud Discovery</strong></div><div class="answer"><strong>Elemento del marco → Detectar y controlar Shadow IT</strong></div><div class="answer"><strong>Función de control → Proteger al descargar</strong></div><div class="answer"><strong>Enviar archivo a revisión → Poner en cuarentena administrativa</strong></div><div class="answer"><strong>Ubicaciones distantes en poco tiempo → Viaje imposible</strong></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Cinco preguntas</small></span></a>` },
          "m6-u9": { title: "Resumen", bodyHtml: `<p>Deberías poder explicar el marco CASB, detectar y puntuar Shadow IT, aplicar el control de aplicaciones de Acceso condicional, clasificar y proteger información confidencial y detectar anomalías en la nube.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/microsoft-cloud-app-security/summary" target="_blank" rel="noopener"><span>Resumen oficial<small>Recapitulación de Cloud Apps</small></span></a>` },
        },
      },
    },
  },
  "path-2": {
    title: "Microsoft Defender for Endpoint",
    meta: "9 módulos · 60 unidades · 5 h 49 min · Implementación, reducción de superficie de ataque, investigaciones, respuesta, automatización, detecciones y administración de vulnerabilidades",
    focusAreas: [
      { title: "Preparación de endpoints", description: "Implementá, incorporá, configurá y protegé dispositivos con Microsoft Defender for Endpoint." },
      { title: "Investigación y respuesta", description: "Investigá dispositivos y evidencia, ejecutá acciones de respuesta, automatizá la corrección y ajustá las detecciones." },
    ],
    modules: {
      "p2-module-1": {
        title: "Proteger frente a amenazas con Microsoft Defender for Endpoint",
        focus: "Enfoque: arquitectura, pila de seguridad, administración y búsqueda avanzada de Defender for Endpoint.",
        units: {
          "p2m1-u1": { title: "Introducción a Microsoft Defender for Endpoint", bodyHtml: `<p>Microsoft Defender for Endpoint es una plataforma empresarial para prevención, detección, investigación y respuesta. Su canal de telemetría combina sensores de comportamiento integrados, análisis de seguridad en la nube e inteligencia sobre amenazas de Microsoft.</p><ul><li><strong>Sensores:</strong> recopilan señales del sistema operativo y las envían al servicio aislado del tenant.</li><li><strong>Análisis en la nube:</strong> convierten telemetría en detecciones, conclusiones y acciones recomendadas.</li><li><strong>Inteligencia:</strong> reconoce herramientas, técnicas, procedimientos e infraestructura de atacantes.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> recordá la pila: Vulnerability Management, reducción de superficie, protección de próxima generación, EDR, AIR y expertos en amenazas.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-security-threat-protect/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura y capacidades de MDE</small></span></a>` },
          "p2m1-u2": { title: "Practicar la administración de seguridad", bodyHtml: `<table><thead><tr><th>Capacidad</th><th>Propósito</th></tr></thead><tbody><tr><td>Vulnerability Management</td><td>Detectar, priorizar y corregir continuamente vulnerabilidades y errores de configuración.</td></tr><tr><td>Reducción de superficie</td><td>Reducir rutas explotables con control de aplicaciones, protección contra vulnerabilidades de seguridad, red, carpetas controladas, ASR y firewall.</td></tr><tr><td>Protección de próxima generación</td><td>Usar protección en la nube, ML, examen en tiempo real y actualizaciones de inteligencia.</td></tr><tr><td>EDR</td><td>Recopilar telemetría, correlacionar alertas e investigar.</td></tr><tr><td>AIR</td><td>Automatizar investigación y corrección para reducir alertas.</td></tr></tbody></table><p>El sensor se comunica como LocalSystem mediante WinHTTP. La configuración de proxy WinHTTP es independiente de WinINet del navegador.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-security-threat-protect/practice-security-administration" target="_blank" rel="noopener"><span>Lección oficial<small>Capacidades de administración</small></span></a>` },
          "p2m1-u3": { title: "Buscar amenazas en la red", bodyHtml: `<p>La búsqueda avanzada usa KQL para consultar proactivamente telemetría de endpoints y otros dominios. Los resultados revelan indicadores, entidades, patrones y candidatos para reglas de detección personalizadas.</p><pre><code>DeviceProcessEvents
| where Timestamp &gt; ago(7d)
| where FileName =~ "powershell.exe"
| where ProcessCommandLine has_any ("downloadstring", "invoke-webrequest")
| project Timestamp, DeviceName, AccountName, ProcessCommandLine
| top 100 by Timestamp desc</code></pre><ul><li>Filtrá pronto por tiempo y columnas selectivas.</li><li>Preferí <code>has</code> para tokens completos frente a <code>contains</code>.</li><li>Proyectá solo las columnas necesarias antes de joins.</li><li>Colocá la tabla más pequeña a la izquierda del join.</li></ul><div class="takeaway"><strong>Clave para el examen:</strong> la búsqueda es proactiva; las detecciones personalizadas operacionalizan una consulta para ejecutarla automáticamente.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-security-threat-protect/hunt-threats-within-network" target="_blank" rel="noopener"><span>Lección oficial<small>Búsqueda con KQL y rendimiento</small></span></a>` },
          "p2m1-u4": { title: "Resumen y comprobación de conocimientos", bodyHtml: `<p>Revisá la arquitectura sensor-nube-inteligencia, las seis áreas principales de MDE, la correlación de incidentes y el rol de KQL en la búsqueda avanzada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/m365-security-threat-protect/" target="_blank" rel="noopener"><span>Módulo oficial<small>Evaluación y resumen</small></span></a>` },
        },
      },
      "p2-module-2": {
        title: "Implementar el entorno de Microsoft Defender for Endpoint",
        focus: "Enfoque: creación del tenant, compatibilidad de plataformas, incorporación, control de acceso, grupos de dispositivos y funciones avanzadas.",
        units: {
          "p2m2-u1": { title: "Introducción", bodyHtml: `<p>La implementación tiene tres líneas conectadas: preparar el tenant y la red, incorporar endpoints compatibles con un método adecuado y aplicar privilegios mínimos junto con alcance por grupos de dispositivos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p2m2-u2": { title: "Crear el entorno", bodyHtml: `<p>La primera visita a la configuración establece preferencias. Un Administrador de seguridad selecciona geografía de almacenamiento, retención y funciones en vista previa. La geografía no puede cambiarse después; la retención predeterminada de la lección es seis meses.</p><p>El sensor se ejecuta como LocalSystem y se comunica mediante WinHTTP. El proxy transparente y WPAD permiten detección automática.</p><div class="takeaway"><strong>Clave para el examen:</strong> usá el rol con menor privilegio y reservá Administrador global para emergencias.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/2-create-your-environment" target="_blank" rel="noopener"><span>Lección oficial<small>Configuración del tenant y la red</small></span></a>` },
          "p2m2-u3": { title: "Comprender la compatibilidad y las funciones de los sistemas operativos", bodyHtml: `<p>MDE admite Windows, macOS, Linux, Android e iOS, pero las capacidades y herramientas difieren. macOS incluye AV, EDR y vulnerabilidades y puede administrarse con Intune o Jamf. Linux admite esas capacidades mediante línea de comandos y herramientas comunes. Las plataformas móviles priorizan protección web, antiphishing, bloqueo de conexiones e integración con Intune y Acceso condicional.</p><div class="takeaway"><strong>Clave para el examen:</strong> verificá requisitos actuales de plataforma y versión antes de diseñar grupos de implementación.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/3-understand-operating-systems-compatibility-features" target="_blank" rel="noopener"><span>Lección oficial<small>Compatibilidad de plataformas</small></span></a>` },
          "p2m2-u4": { title: "Incorporar dispositivos", bodyHtml: `<ol><li>Configurá Detección de dispositivos, normalmente en modo Estándar.</li><li>Verificá requisitos del SO y conectividad.</li><li>Seleccioná paquete y método según la plataforma.</li><li>Implementá con Intune/MDM, Directiva de grupo, Configuration Manager, scripts o herramientas compatibles.</li><li>Ejecutá la prueba de detección y confirmá los informes del sensor.</li></ol><p>El script local sirve para evaluación limitada, no para escala empresarial. VDI no persistente requiere su método específico. Los paquetes de retirada dependen de la plataforma.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/4-onboard-devices" target="_blank" rel="noopener"><span>Lección oficial<small>Incorporación y retirada</small></span></a>` },
          "p2m2-u5": { title: "Administrar el acceso", bodyHtml: `<p>RBAC controla acciones y visibilidad. Los roles definen capacidades; los grupos de seguridad de Entra reciben roles; los grupos de dispositivos definen qué datos y alertas ven esos usuarios. Los clientes nuevos usan RBAC unificado.</p><table><thead><tr><th>Rol de Entra</th><th>Acceso inicial</th></tr></thead><tbody><tr><td>Administrador de seguridad / global</td><td>Acceso completo</td></tr><tr><td>Lector de seguridad</td><td>Solo lectura</td></tr></tbody></table><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/5-manage-access" target="_blank" rel="noopener"><span>Lección oficial<small>RBAC y grupos de dispositivos</small></span></a>` },
          "p2m2-u6": { title: "Crear y administrar roles para RBAC", bodyHtml: `<p>Creá roles en Configuración &gt; Endpoints &gt; Permisos, elegí permisos granulares y asigná un grupo de seguridad existente. Las familias incluyen visualización, corrección activa, investigación, configuración, vulnerabilidades, seguridad de endpoints de Intune y Live Response básico o avanzado.</p><div class="takeaway"><strong>Clave para el examen:</strong> un rol solo está incompleto: asocialo con un grupo de Entra y asignale alcance mediante grupos de dispositivos.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/6-create-manage-roles-for-role-based-access-control" target="_blank" rel="noopener"><span>Lección oficial<small>Creación de roles y permisos</small></span></a>` },
          "p2m2-u7": { title: "Configurar grupos de dispositivos", bodyHtml: `<p>Los grupos organizan endpoints por nombre, dominio, etiqueta o SO. Limitan visibilidad y acciones y pueden aplicar distintos niveles de corrección automática. Si las reglas se superponen, el dispositivo pertenece al grupo coincidente de mayor prioridad.</p><ol><li>Elegí nombre y nivel de corrección.</li><li>Definí y previsualizá la regla.</li><li>Concedé acceso a grupos de Entra con roles RBAC.</li><li>Clasificá el grupo frente a los demás.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/7-configure-device-groups" target="_blank" rel="noopener"><span>Lección oficial<small>Coincidencia, alcance y prioridad</small></span></a>` },
          "p2m2-u8": { title: "Configurar funciones avanzadas del entorno", bodyHtml: `<p>Las funciones avanzadas son interruptores del tenant. Incluyen Live Response, scripts sin firmar, indicadores de red personalizados, conexión con Intune, integración con Cloud Apps, filtrado web, vistas previas y detección de dispositivos. Habilitá solo las capacidades respaldadas por procesos operativos y de gobernanza.</p><div class="takeaway"><strong>Clave para el examen:</strong> una función puede requerir el interruptor y además RBAC, endpoint, licencia o red.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/8-configure-environment-advanced-features" target="_blank" rel="noopener"><span>Lección oficial<small>Interruptores de funciones avanzadas</small></span></a>` },
          "p2m2-u9": { title: "Evaluación del módulo", bodyHtml: `<p>Comprobá que distinguís configuración del tenant, incorporación por plataforma, roles de Entra, roles RBAC de MDE, grupos de dispositivos y requisitos de funciones avanzadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de implementación</small></span></a>` },
          "p2m2-u10": { title: "Resumen y recursos", bodyHtml: `<p>La implementación es exitosa cuando los dispositivos compatibles informan, el servicio alcanza los endpoints de nube requeridos, el acceso tiene privilegios mínimos y alcance por dispositivo y las capacidades avanzadas se habilitan deliberadamente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/deploy-microsoft-defender-for-endpoints-environment/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-3": {
        title: "Implementar mejoras de seguridad de Windows con Microsoft Defender for Endpoint",
        focus: "Enfoque: reducción de superficie de ataque, implementación de reglas, modos operativos, exclusiones y validación.",
        units: {
          "p2m3-u1": { title: "Introducción", bodyHtml: `<p>La reducción de la superficie expuesta a ataques (ASR) limita comportamientos y rutas que los atacantes suelen abusar, especialmente aplicaciones de Office, scripts, correo, robo de credenciales y contenido ejecutable.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/implement-windows-10-security-enhancements-with-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de ASR</small></span></a>` },
          "p2m3-u2": { title: "Comprender la reducción de superficie de ataque", bodyHtml: `<p>Las reglas ASR apuntan a comportamientos riesgosos, no solo a firmas conocidas. Complementan antivirus, EDR, protección contra vulnerabilidades, control de aplicaciones, protección de red y carpetas controladas. Cada regla tiene un GUID único.</p><ul><li><strong>Bloquear:</strong> impide y genera un evento.</li><li><strong>Auditar:</strong> permite y registra lo que habría bloqueado.</li><li><strong>Advertir:</strong> muestra una advertencia que puede omitirse.</li><li><strong>Deshabilitada / no configurada:</strong> no aplica la regla.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/implement-windows-10-security-enhancements-with-microsoft-defender-for-endpoint/2-understand-attack-surface-reduction" target="_blank" rel="noopener"><span>Lección oficial<small>Conceptos y modos de ASR</small></span></a>` },
          "p2m3-u3": { title: "Habilitar reglas de reducción de superficie de ataque", bodyHtml: `<p>Implementá reglas con Intune, Configuration Manager, Directiva de grupo, PowerShell o MDM CSP. Un despliegue seguro comienza en auditoría, revisa telemetría e impacto, agrega exclusiones limitadas y justificadas y pasa reglas seleccionadas a advertencia o bloqueo en anillos controlados.</p><pre><code>Set-MpPreference -AttackSurfaceReductionRules_Ids &lt;rule-guid&gt; \
  -AttackSurfaceReductionRules_Actions AuditMode</code></pre><div class="takeaway"><strong>Clave para el examen:</strong> las exclusiones reducen protección; deben ser limitadas, documentadas y probadas. Monitoreá eventos mediante informes y búsqueda avanzada.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/implement-windows-10-security-enhancements-with-microsoft-defender-for-endpoint/3-enable-attack-surface-reduction-rules" target="_blank" rel="noopener"><span>Lección oficial<small>Implementación, modos y exclusiones</small></span></a>` },
          "p2m3-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Elegí el modo ASR correcto para evaluación frente a aplicación y reconocé los canales de administración usados para implementar reglas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/implement-windows-10-security-enhancements-with-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de ASR</small></span></a>` },
          "p2m3-u5": { title: "Resumen y recursos", bodyHtml: `<p>ASR reduce oportunidades antes de que EDR deba responder. Tratá la implementación como un cambio medido: auditar, analizar, probar, aplicar y ajustar continuamente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/implement-windows-10-security-enhancements-with-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-4": {
        title: "Realizar investigaciones de dispositivos en Microsoft Defender for Endpoint",
        focus: "Enfoque: inventario, evidencia de la página del dispositivo, bloqueo por comportamiento y detección de dispositivos.",
        units: {
          "p2m4-u1": { title: "Introducción", bodyHtml: `<p>Las investigaciones pasan desde una alerta o incidente al contexto del endpoint: identidad, estado, exposición, alertas, escala de tiempo, software, vulnerabilidades y acciones de respuesta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de investigación</small></span></a>` },
          "p2m4-u2": { title: "Usar la lista de inventario de dispositivos", bodyHtml: `<p>El inventario permite triage basado en riesgo. El <strong>nivel de riesgo</strong> refleja gravedad y estado de alertas activas; el <strong>nivel de exposición</strong> refleja el impacto acumulado de recomendaciones pendientes. Los estados incluyen activo, inactivo y mal configurado, con problemas de comunicación y sensor separados.</p><p>Usá filtros y CSV para validar incorporación, detectar endpoints que no informan y priorizar dispositivos riesgosos o expuestos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/2-use-device-inventory-list" target="_blank" rel="noopener"><span>Lección oficial<small>Inventario, riesgo, exposición y estado</small></span></a>` },
          "p2m4-u3": { title: "Investigar el dispositivo", bodyHtml: `<p>La página ofrece Información general, Alertas, Escala de tiempo, Recomendaciones, Inventario de software, Vulnerabilidades y KB faltantes. La escala es la evidencia cronológica principal y se puede buscar, filtrar, exportar o marcar para construir la secuencia.</p><ul><li>Pasá de un evento a entidades relacionadas.</li><li>Usá <strong>Buscar eventos relacionados</strong> para abrir KQL predefinido.</li><li>Revisá usuarios conectados, alertas, software, recomendaciones y vulnerabilidades.</li><li>Elegí acciones después de establecer alcance e impacto.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/3-investigate-device" target="_blank" rel="noopener"><span>Lección oficial<small>Página y escala de tiempo</small></span></a>` },
          "p2m4-u4": { title: "Usar el bloqueo por comportamiento", bodyHtml: `<p>El bloqueo y la contención usan telemetría, análisis en la nube, inteligencia y contexto EDR para detener comportamientos sospechosos aunque el archivo exacto no sea conocido. Puede bloquear robo de credenciales, persistencia, inyección, scripts y cadenas observadas.</p><div class="takeaway"><strong>Clave para el examen:</strong> el bloqueo posterior a la vulneración forma parte de EDR y funciona junto al antivirus para contener después de iniciado el ataque.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/4-use-behavioral-blocking" target="_blank" rel="noopener"><span>Lección oficial<small>Bloqueo y contención</small></span></a>` },
          "p2m4-u5": { title: "Detectar dispositivos mediante detección de dispositivos", bodyHtml: `<p>La detección encuentra dispositivos no administrados observando actividad de red desde endpoints incorporados. Se recomienda el modo Estándar. Los recursos descubiertos deben evaluarse, clasificarse e incorporarse o controlarse para reducir puntos ciegos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/5-detect-devices-with-device-discovery" target="_blank" rel="noopener"><span>Lección oficial<small>Detección de dispositivos no administrados</small></span></a>` },
          "p2m4-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Distinguí riesgo de exposición, identificá la pestaña para evidencia cronológica y comprendé cómo la detección encuentra recursos no administrados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de investigación</small></span></a>` },
          "p2m4-u7": { title: "Resumen y recursos", bodyHtml: `<p>Una investigación sólida conecta la alerta con escala de tiempo, usuarios, software, vulnerabilidades y otras entidades antes de contener o corregir.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-device-investigations-microsoft-defender-for-endpoints/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-5": {
        title: "Realizar acciones en un dispositivo con Microsoft Defender for Endpoint",
        focus: "Enfoque: contención, exámenes antivirus, paquetes forenses y Live Response.",
        units: {
          "p2m5-u1": { title: "Introducción", bodyHtml: `<p>Las acciones tienen tres objetivos: contener el acceso activo, recopilar evidencia forense y corregir artefactos malintencionados. Se registran en el Centro de acciones y la escala de tiempo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de respuesta</small></span></a>` },
          "p2m5-u2": { title: "Explicar las acciones de dispositivo", bodyHtml: `<table><thead><tr><th>Acción</th><th>Uso</th></tr></thead><tbody><tr><td>Aislar</td><td>Desconectar la red conservando MDE; limita C2, filtración y movimiento lateral.</td></tr><tr><td>Restringir ejecución</td><td>Permitir solo archivos firmados por Microsoft.</td></tr><tr><td>Ejecutar examen</td><td>Ejecutar examen rápido o completo remotamente.</td></tr><tr><td>Investigación automática</td><td>Iniciar investigación y corrección similares al analista.</td></tr><tr><td>Recopilar paquete</td><td>Obtener un ZIP forense puntual.</td></tr><tr><td>Live Response</td><td>Abrir un shell remoto autorizado.</td></tr></tbody></table><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/2-understand-device-actions" target="_blank" rel="noopener"><span>Lección oficial<small>Acciones de contención e investigación</small></span></a>` },
          "p2m5-u3": { title: "Ejecutar un examen de Microsoft Defender Antivirus", bodyHtml: `<p>Elegí examen rápido o completo y documentá el motivo. Los envíos y detecciones aparecen en el Centro de acciones, la escala de tiempo y la cola. Defender Antivirus puede examinar en modo pasivo junto a otro antivirus; se aplican límites de CPU.</p><p>También se puede iniciar una investigación automatizada general; puede agregar alertas y dispositivos relacionados mientras se ejecuta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/3-run-microsoft-defender-antivirus-scan-on-devices" target="_blank" rel="noopener"><span>Lección oficial<small>Examen remoto e investigación automática</small></span></a>` },
          "p2m5-u4": { title: "Recopilar un paquete de investigación", bodyHtml: `<p>El paquete captura estado forense actual: ejecuciones automáticas, programas, conexiones y datos DNS/ARP, prefetch, procesos, tareas, registros, servicios, sesiones SMB, sistema, temporales, usuarios y grupos, registros de Defender y resumen.</p><div class="takeaway"><strong>Clave para el examen:</strong> preserva estado para análisis sin conexión; no es lo mismo que la escala de tiempo recopilada continuamente.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/4-collect-investigation-package-from-devices" target="_blank" rel="noopener"><span>Lección oficial<small>Contenido del paquete</small></span></a>` },
          "p2m5-u5": { title: "Iniciar una sesión de Live Response", bodyHtml: `<p>Live Response es un shell remoto en la nube para investigación y corrección inmediatas. Habilitalo en Funciones avanzadas, asigná un nivel de corrección al grupo y permisos RBAC básicos o avanzados. Los scripts sin firmar requieren otra opción y aumentan el riesgo.</p><table><thead><tr><th>Ejemplos básicos</th><th>Ejemplos avanzados</th></tr></thead><tbody><tr><td><code>processes</code>, <code>services</code>, <code>scheduledtasks</code>, <code>persistence</code>, <code>registry</code>, <code>findfile</code></td><td><code>analyze</code>, <code>getfile</code>, <code>putfile</code>, <code>run</code>, <code>remediate</code>, <code>undo</code></td></tr></tbody></table><p>Usá <code>-auto</code> cuando corresponda. Los comandos se auditan. No admite ejecución masiva y se aplican límites de concurrencia e inactividad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/5-initiate-live-response-session" target="_blank" rel="noopener"><span>Lección oficial<small>Requisitos y comandos de Live Response</small></span></a>` },
          "p2m5-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Elegí acciones según el objetivo: aislar red, restringir ejecución, examinar malware, recopilar evidencia, automatizar investigación o usar Live Response.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de acciones</small></span></a>` },
          "p2m5-u7": { title: "Resumen y recursos", bodyHtml: `<p>Cada acción debe tener motivo documentado, autorización con privilegios mínimos, verificación en el Centro de acciones y plan claro de reversión o recuperación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-actions-device-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-6": {
        title: "Investigar evidencia y entidades con Microsoft Defender for Endpoint",
        focus: "Enfoque: páginas de entidades de archivo, usuario, dirección IP y dominio y los pivotes entre ellas.",
        units: {
          "p2m6-u1": { title: "Introducción", bodyHtml: `<p>La investigación de entidades determina el alcance pasando desde evidencia a alertas, incidentes, dispositivos, usuarios, procesos, destinos de red, prevalencia e inteligencia relacionados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de investigación de entidades</small></span></a>` },
          "p2m6-u2": { title: "Investigar un archivo", bodyHtml: `<p>La página usa un hash como clave y muestra veredicto, prevalencia, primera y última observación, firmante y certificado, dispositivos, alertas, nombres, rutas y comportamiento. Baja prevalencia, ausencia de firma, origen sospechoso o alertas activas aumentan la preocupación.</p><p>Las acciones pueden incluir detener y poner en cuarentena, agregar indicador, descargar, análisis profundo o buscar. Validá alcance e impacto antes de bloquear un hash.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/2-investigate-file" target="_blank" rel="noopener"><span>Lección oficial<small>Evidencia, prevalencia y respuesta</small></span></a>` },
          "p2m6-u3": { title: "Investigar una cuenta de usuario", bodyHtml: `<p>La página muestra identidad, riesgo, contexto, alertas e incidentes, dispositivos observados y actividad. Usala para determinar si la actividad se limita a un endpoint o sigue a la identidad entre dispositivos y servicios.</p><div class="takeaway"><strong>Clave para el examen:</strong> el pivote de usuario amplía una investigación a identidad; correlacioná señales de Entra ID y Defender for Identity en XDR.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/3-investigate-user-account" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación de usuario</small></span></a>` },
          "p2m6-u4": { title: "Investigar una dirección IP", bodyHtml: `<p>La página combina inteligencia de Microsoft con observaciones internas: reputación, registro, ubicación, alertas, dispositivos contactados y eventos de red. Distinguí infraestructura externa de direcciones internas y proxies antes de crear un indicador.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/4-investigate-ip-addresses" target="_blank" rel="noopener"><span>Lección oficial<small>Reputación IP y observaciones</small></span></a>` },
          "p2m6-u5": { title: "Investigar un dominio", bodyHtml: `<p>La página muestra veredicto y reputación, alertas, IP resueltas, dispositivos comunicados y URL o eventos. Comprobá si es nuevo, infrecuente, está conectado con procesos sospechosos o pertenece a infraestructura conocida.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/5-investigate-domain" target="_blank" rel="noopener"><span>Lección oficial<small>Evidencia y pivotes de dominio</small></span></a>` },
          "p2m6-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Reconocé qué página responde cada pregunta: prevalencia y firmante, relaciones usuario-dispositivo, reputación IP y dispositivos contactados o resolución y comunicaciones del dominio.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de evidencia y entidades</small></span></a>` },
          "p2m6-u7": { title: "Resumen y recursos", bodyHtml: `<p>Los pivotes convierten una alerta en una investigación con alcance. Construí relaciones, establecé prevalencia y reputación, buscá observaciones adicionales y contené el menor alcance justificado.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-evidence-entities-investigations-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-7": {
        title: "Configurar y administrar la automatización con Microsoft Defender for Endpoint",
        focus: "Enfoque: funciones avanzadas, tratamiento de muestras, investigación y corrección automatizadas y control de acceso de dispositivos riesgosos.",
        units: {
          "p2m7-u1": { title: "Introducción", bodyHtml: `<p>La automatización reduce el análisis repetitivo y conserva la gobernanza mediante permisos, niveles de corrección, tratamiento de evidencia, auditoría del Centro de acciones y flujos de aprobación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de automatización</small></span></a>` },
          "p2m7-u2": { title: "Configurar funciones avanzadas", bodyHtml: `<p>Habilitá integraciones y automatización en Configuración &gt; Endpoints &gt; Funciones avanzadas. Ejemplos: investigación automática, Live Response, Intune, uso compartido autenticado de telemetría, indicadores de red personalizados y vistas previas.</p><p>Validá licencias, intercambio de datos, RBAC y requisitos de endpoints antes de habilitar un interruptor global.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/2-configure-advanced-features" target="_blank" rel="noopener"><span>Lección oficial<small>Funciones del tenant relacionadas con automatización</small></span></a>` },
          "p2m7-u3": { title: "Administrar la carga automática y la configuración de carpetas", bodyHtml: `<p>El envío de muestras permite que Microsoft analice archivos sospechosos y mejore veredictos. Configurá el envío automático y exclusiones para carpetas o extensiones confidenciales cuando se justifique. Las exclusiones reducen la calidad de investigación: mantenelas limitadas y revisalas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/3-manage-automation-upload-folder-settings" target="_blank" rel="noopener"><span>Lección oficial<small>Uso compartido de muestras y exclusiones</small></span></a>` },
          "p2m7-u4": { title: "Configurar investigación y corrección automatizadas", bodyHtml: `<p>AIR inspecciona evidencia, asigna veredictos y aplica o propone correcciones. Los niveles de automatización de grupos determinan si la corrección es automática, requiere aprobación o está limitada. Las acciones pendientes se revisan en el Centro de acciones.</p><div class="flow" aria-label="Flujo de investigación automatizada"><div class="flow-step"><strong>1 · Desencadenar</strong>Una alerta o acción inicia la investigación.</div><div class="flow-step"><strong>2 · Inspeccionar</strong>AIR examina dispositivos, archivos, procesos, servicios y persistencia.</div><div class="flow-step"><strong>3 · Veredicto</strong>Clasifica evidencia como malintencionada, sospechosa o limpia.</div><div class="flow-step"><strong>4 · Corregir</strong>Ejecuta automáticamente o espera aprobación.</div></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/4-configure-automated-investigation-remediation-capabilities" target="_blank" rel="noopener"><span>Lección oficial<small>Proceso AIR y niveles de corrección</small></span></a>` },
          "p2m7-u5": { title: "Bloquear dispositivos en riesgo", bodyHtml: `<p>MDE envía riesgo a Intune. La directiva de cumplimiento de Intune lo evalúa y Acceso condicional de Entra puede bloquear recursos hasta que el endpoint se corrija y vuelva a cumplir.</p><div class="flow" aria-label="Flujo de acceso basado en riesgo"><div class="flow-step"><strong>1 · Detectar</strong>MDE calcula el riesgo.</div><div class="flow-step"><strong>2 · Evaluar</strong>Intune marca cumplimiento.</div><div class="flow-step"><strong>3 · Aplicar</strong>Acceso condicional permite o bloquea.</div><div class="flow-step"><strong>4 · Restaurar</strong>La corrección reduce riesgo y restaura cumplimiento.</div></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/5-block-risk-devices" target="_blank" rel="noopener"><span>Lección oficial<small>MDE, Intune y Acceso condicional</small></span></a>` },
          "p2m7-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Distinguí interruptor del tenant, nivel de corrección del grupo, aprobación del Centro de acciones, envío de muestras y flujo de aplicación de Intune/Acceso condicional.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de automatización</small></span></a>` },
          "p2m7-u7": { title: "Resumen y recursos", bodyHtml: `<p>La automatización efectiva combina telemetría amplia con privilegios mínimos, niveles controlados, historial transparente y procesos claros de aprobación y excepciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-manage-automation-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-8": {
        title: "Configurar alertas y detecciones en Microsoft Defender for Endpoint",
        focus: "Enfoque: funciones relacionadas con alertas, notificaciones, ajuste e indicadores personalizados.",
        units: {
          "p2m8-u1": { title: "Introducción", bodyHtml: `<p>La configuración de detecciones debe mejorar la calidad de las señales sin crear puntos ciegos. Los controles principales son funciones del tenant, reglas de notificación, ajuste de alertas e indicadores.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de alertas y detecciones</small></span></a>` },
          "p2m8-u2": { title: "Configurar funciones avanzadas", bodyHtml: `<p>Las funciones relacionadas con alertas incluyen Live Response, ejecución de scripts sin firmar e indicadores de red personalizados. Estos deben habilitarse antes de aplicar reglas de permitir o bloquear IP, URL o dominios.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/2-configure-advanced-features" target="_blank" rel="noopener"><span>Lección oficial<small>Interruptores relacionados con detección</small></span></a>` },
          "p2m8-u3": { title: "Configurar notificaciones de alertas", bodyHtml: `<p>Las reglas de correo seleccionan alcance de dispositivos, gravedad, destinatarios, nombre, vínculo al tenant y detalles opcionales. RBAC limita destinatarios y administradores a sus grupos; solo administradores apropiados crean reglas globales.</p><ol><li>Creá y nombrá la regla.</li><li>Elegí todos los dispositivos o grupos.</li><li>Elegí umbrales de gravedad.</li><li>Agregá destinatarios y enviá una prueba.</li><li>Guardá y validá periódicamente.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/3-configure-alert-notifications" target="_blank" rel="noopener"><span>Lección oficial<small>Reglas de notificación por correo</small></span></a>` },
          "p2m8-u4": { title: "Administrar la supresión de alertas", bodyHtml: `<p>El ajuste suprime patrones benignos conocidos, como herramientas aprobadas. Las reglas se habilitan, deshabilitan, editan o eliminan en Configuración &gt; Microsoft Defender XDR &gt; Reglas &gt; Ajuste de alertas. Los cambios pueden liberar alertas suprimidas previamente.</p><div class="takeaway"><strong>Clave para el examen:</strong> ajustá un patrón de falso positivo bien entendido; nunca suprimas ampliamente solo para reducir volumen.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/4-manage-alert-suppression" target="_blank" rel="noopener"><span>Lección oficial<small>Reglas de ajuste</small></span></a>` },
          "p2m8-u5": { title: "Administrar indicadores", bodyHtml: `<p>Los indicadores definen permitir, auditar, advertir, bloquear o bloquear y corregir según la entidad. Admiten hashes, IP externas, URL/dominios y certificados. Alcance y vencimiento reducen riesgo.</p><table><thead><tr><th>Indicador</th><th>Acciones / requisitos</th></tr></thead><tbody><tr><td>Archivo</td><td>Permitir, auditar, advertir, bloquear o corregir; requiere protección en la nube y AV compatible.</td></tr><tr><td>IP / URL / dominio</td><td>Permitir, auditar, advertir o bloquear; requiere Protección de red e indicadores personalizados. La lección no admite IP internas ni CIDR.</td></tr><tr><td>Certificado</td><td>Permitir o bloquear certificados finales; requiere AV y nube.</td></tr></tbody></table><p>Se aplican en detección en la nube, prevención e investigación automática. Se crean contextualmente, manualmente o por CSV.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/5-manage-indicators" target="_blank" rel="noopener"><span>Lección oficial<small>Tipos de IoC, acciones y requisitos</small></span></a>` },
          "p2m8-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Elegí el control correcto: regla de notificación para informar, ajuste para un patrón benigno recurrente o indicador para comportamiento explícito de detección y prevención.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de alertas e indicadores</small></span></a>` },
          "p2m8-u7": { title: "Resumen y recursos", bodyHtml: `<p>Una buena ingeniería equilibra cobertura y precisión: notifica a quienes corresponde, ajusta falsos positivos verificados y limita indicadores temporales con intención documentada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/configure-settings-for-alerts-detections-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p2-module-9": {
        title: "Usar Vulnerability Management en Microsoft Defender for Endpoint",
        focus: "Enfoque: detección continua, priorización basada en inteligencia, análisis de exposición y flujo de corrección.",
        units: {
          "p2m9-u1": { title: "Introducción", bodyHtml: `<p>Defender Vulnerability Management identifica debilidades de endpoints y las conecta con contexto de dispositivos, amenazas y negocio para priorizar y realizar seguimiento de la corrección.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de Vulnerability Management</small></span></a>` },
          "p2m9-u2": { title: "Comprender la administración de vulnerabilidades", bodyHtml: `<p>El sensor integrado detecta continuamente software, vulnerabilidades y errores de configuración sin exámenes periódicos de red. La prioridad combina explotación, vulneraciones activas, valor del dispositivo, datos confidenciales, ejecución de aplicaciones y contexto organizacional.</p><div class="flow" aria-label="Ciclo de administración de vulnerabilidades"><div class="flow-step"><strong>1 · Detectar</strong>Inventariar software y configuración continuamente.</div><div class="flow-step"><strong>2 · Priorizar</strong>Combinar gravedad técnica con contexto de amenaza y negocio.</div><div class="flow-step"><strong>3 · Corregir</strong>Crear tareas de TI o mitigaciones alternativas.</div><div class="flow-step"><strong>4 · Seguir</strong>Monitorear progreso y reducción de exposición.</div></div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/2-understand-threat-vulnerability-management" target="_blank" rel="noopener"><span>Lección oficial<small>Detección y priorización en tiempo real</small></span></a>` },
          "p2m9-u3": { title: "Explorar vulnerabilidades en los dispositivos", bodyHtml: `<p>El área incluye panel, recomendaciones, actividades de corrección, inventarios, debilidades y escala de eventos. MDE Plan 2 incluye detección, inventario, evaluación, priorización, seguimiento, monitoreo y evaluación de software; licencias adicionales agregan líneas base, evaluación de extensiones y certificados, bloqueo de aplicaciones vulnerables y análisis de recursos compartidos.</p><div class="takeaway"><strong>Clave para el examen:</strong> exposición no equivale a riesgo de incidente. Exposición refleja debilidades; riesgo refleja alertas activas y posible compromiso.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/3-explore-vulnerabilities-devices" target="_blank" rel="noopener"><span>Lección oficial<small>Áreas del portal y licencias</small></span></a>` },
          "p2m9-u4": { title: "Administrar la corrección", bodyHtml: `<p>Creá actividades desde recomendaciones, asignalas al flujo de TI, definí fechas y prioridad y monitoreá el estado. Si no hay revisión, usá mitigaciones como cambios de configuración, restricciones o controles compensatorios.</p><p>Validá mediante telemetría actualizada y menor exposición, no solo por el estado del ticket.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/4-manage-remediation" target="_blank" rel="noopener"><span>Lección oficial<small>Solicitudes y seguimiento de corrección</small></span></a>` },
          "p2m9-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Comprendé cómo los datos continuos, inteligencia, importancia del dispositivo, recomendaciones, tareas de Intune/TI y seguimiento forman un flujo basado en riesgo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de vulnerabilidades</small></span></a>` },
          "p2m9-u6": { title: "Resumen y recursos", bodyHtml: `<p>Priorizá lo explotable e importante ahora, coordiná con TI, aplicá controles compensatorios cuando sea necesario y verificá continuamente la reducción de exposición.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-threat-vulnerability-management-microsoft-defender-for-endpoint/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-3": {
    title: "Microsoft Defender for Cloud",
    meta: "6 módulos · 48 unidades · 4 h 17 min · Postura de seguridad en la nube, incorporación multinube, protección de cargas de trabajo, alertas y respuesta",
    focusAreas: [
      { title: "Postura y cobertura de nube", description: "Conectá recursos de Azure e híbridos, ampliá la cobertura multinube y administrá la postura de seguridad." },
      { title: "Respuesta ante amenazas de cargas de trabajo", description: "Habilitá protecciones, investigá alertas y corregí riesgos en los recursos de nube." },
    ],
    modules: {
      "p3-module-1": {
        title: "Planificar la protección de cargas de trabajo con Microsoft Defender for Cloud",
        focus: "Enfoque: arquitectura de Defender for Cloud, CSPM, protección de cargas de trabajo, planes y habilitación inicial.",
        units: {
          "p3m1-u1": { title: "Introducción", bodyHtml: `<p>Microsoft Defender for Cloud protege entornos de Azure, híbridos y multinube mediante administración de postura y protección contra amenazas. Este módulo establece el modelo de servicio y las decisiones previas a la implementación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p3m1-u2": { title: "Explicar Microsoft Defender for Cloud", bodyHtml: `<p>Defender for Cloud tiene dos pilares: <strong>CSPM</strong> descubre debilidades, mide la Puntuación de seguridad y recomienda protección; <strong>CWP</strong> detecta y responde a amenazas contra tipos específicos de recursos.</p><div class="flow"><div class="flow-step"><strong>1 · Evaluar</strong>Inventariar recursos y configuraciones.</div><div class="flow-step"><strong>2 · Proteger</strong>Priorizar recomendaciones.</div><div class="flow-step"><strong>3 · Defender</strong>Detectar ataques.</div><div class="flow-step"><strong>4 · Responder</strong>Investigar y corregir.</div></div><div class="takeaway"><strong>Clave:</strong> CSPM reduce la probabilidad de compromiso; CWP detecta amenazas activas.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/2-what-is-azure-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Introducción a CSPM y CWP</small></span></a>` },
          "p3m1-u3": { title: "Describir las protecciones de cargas de trabajo", bodyHtml: `<p>Los planes específicos cubren Servers, App Service, Storage, Databases, Containers, Key Vault, Resource Manager y API. Azure Arc extiende protecciones a servidores y Kubernetes fuera de Azure.</p><ul><li><strong>Prevenir:</strong> puntuación, recomendaciones, cumplimiento y controles adaptativos.</li><li><strong>Detectar:</strong> comportamiento, inteligencia y anomalías.</li><li><strong>Integrar:</strong> exportar alertas a Sentinel u otro SIEM/SOAR y Defender XDR.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/3-understand-azure-secure-center" target="_blank" rel="noopener"><span>Lección oficial<small>Planes y capacidades</small></span></a>` },
          "p3m1-u4": { title: "Ejercicio: guía interactiva de Microsoft Defender for Cloud", bodyHtml: `<p>Reconocé las áreas Información general, Recomendaciones, Inventario, Cumplimiento normativo, Protecciones de cargas, Alertas y Configuración del entorno. Relacioná cada una con evaluar, proteger, defender o responder.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/4-exercise-azure-security-center-interactive-guide" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Recorrido guiado</small></span></a>` },
          "p3m1-u5": { title: "Habilitar Microsoft Defender for Cloud", bodyHtml: `<p>En <strong>Configuración del entorno</strong>, elegí grupo de administración, suscripción o cuenta conectada y habilitá todos los planes o solo los necesarios.</p><ol><li>Definí entorno y alcance normativo.</li><li>Elegí CSPM y planes según riesgo y licencia.</li><li>Configurá componentes y recopilación.</li><li>Verificá cobertura, recomendaciones y alertas.</li></ol><div class="takeaway"><strong>Clave:</strong> no es un único interruptor global; los planes se configuran por entorno.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/5-enable-azure-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Habilitar planes y monitoreo</small></span></a>` },
          "p3m1-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá CSPM frente a CWP, el ciclo evaluar-proteger-defender, planes específicos, cobertura de Azure Arc y Configuración del entorno.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de planificación</small></span></a>` },
          "p3m1-u7": { title: "Resumen y recursos", bodyHtml: `<p>Planificá identificando entornos y cargas, midiendo postura, eligiendo planes y definiendo cómo fluyen las alertas hacia operaciones de seguridad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p3-module-2": {
        title: "Conectar recursos de Azure a Microsoft Defender for Cloud",
        focus: "Enfoque: inventario, aprovisionamiento automático y manual, Azure Monitor Agent y reglas de recopilación de datos.",
        units: {
          "p3m2-u1": { title: "Introducción", bodyHtml: `<p>Los recursos deben ser visibles y proporcionar telemetría antes de que funcionen la postura y las protecciones. Este módulo cubre inventario y métodos de aprovisionamiento.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p3m2-u2": { title: "Explorar y administrar recursos con el inventario", bodyHtml: `<p>El inventario ofrece una vista consultable. Filtrá por suscripción, tipo, estado, recomendación, etiqueta o entorno; revisá recursos incorrectos o no monitoreados; exportá CSV o abrí Azure Resource Graph. Aplicá etiquetas, iniciá Logic Apps, incorporá servidores y revisá hallazgos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/2-explore-manage-resources-with-asset-inventory" target="_blank" rel="noopener"><span>Lección oficial<small>Inventario, filtros y acciones masivas</small></span></a>` },
          "p3m2-u3": { title: "Configurar el aprovisionamiento automático", bodyHtml: `<p>El aprovisionamiento implementa componentes mediante Azure Policy <code>DeployIfNotExists</code> y Configuración y monitoreo. Azure Monitor Agent (AMA) es el agente recomendado. La integración con Defender for Endpoint incorpora servidores compatibles. El agente heredado de Log Analytics se retiró en agosto de 2024.</p><div class="takeaway"><strong>Clave:</strong> preferí aprovisionamiento automático centralizado; usá manual solo para excepciones.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/3-configure-auto-provisioning" target="_blank" rel="noopener"><span>Lección oficial<small>Aprovisionamiento basado en directivas</small></span></a>` },
          "p3m2-u4": { title: "Aprovisionamiento manual del agente", bodyHtml: `<p>La implementación manual de AMA usa una <strong>DCR</strong> para definir qué recursos recopilan qué datos y a dónde se envían.</p><ol><li>Creá la DCR y elegí plataforma y región.</li><li>Agregá recursos.</li><li>Agregá eventos, contadores, Syslog, texto o IIS.</li><li>Elegí el área de Log Analytics.</li><li>Verificá estado y heartbeat.</li></ol><p>Evitá DCR superpuestas. La incorporación directa a MDE no aporta las capacidades de administración de Arc.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/4-manual-azure-monitor-agent-provisioning" target="_blank" rel="noopener"><span>Lección oficial<small>AMA y DCR</small></span></a>` },
          "p3m2-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Distinguí inventario de Resource Graph, automático de manual, AMA del agente retirado y el modelo origen-recurso-destino de una DCR.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de conexión</small></span></a>` },
          "p3m2-u6": { title: "Resumen y recursos", bodyHtml: `<p>Usá inventario para brechas de cobertura, aprovisionamiento automático para consistencia y DCR acotadas cuando AMA manual sea necesario.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-azure-assets-to-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p3-module-3": {
        title: "Conectar recursos que no son de Azure a Microsoft Defender for Cloud",
        focus: "Enfoque: Azure Arc, servidores fuera de Azure, cuentas de AWS, proyectos de GCP y permisos multinube.",
        units: {
          "p3m3-u1": { title: "Introducción", bodyHtml: `<p>Defender for Cloud proporciona una vista en Azure, entorno local, AWS y Google Cloud. Cada conexión debe establecer inventario, permisos y componentes necesarios.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos multinube</small></span></a>` },
          "p3m3-u2": { title: "Proteger recursos que no son de Azure", bodyHtml: `<p>Azure Arc proyecta servidores y Kubernetes externos al plano de control de Azure. Habilita identidad de recurso, directivas, extensiones, etiquetas, inventario y protecciones compatibles.</p><div class="takeaway"><strong>Clave:</strong> Arc hace que la máquina externa sea administrable como recurso de Azure; es más que incorporar un agente.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/2-protect-non-azure-resources" target="_blank" rel="noopener"><span>Lección oficial<small>Azure Arc y protección híbrida</small></span></a>` },
          "p3m3-u3": { title: "Conectar máquinas que no son de Azure", bodyHtml: `<p>Incorporá a Arc con script, herramientas compatibles o implementación a escala mediante entidad de servicio; luego habilitá planes y extensiones. La incorporación directa a MDE protege endpoints, pero no aporta administración, directivas ni extensiones de Arc.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/3-connect-non-azure-machines" target="_blank" rel="noopener"><span>Lección oficial<small>Opciones de servidores híbridos</small></span></a>` },
          "p3m3-u4": { title: "Conectar cuentas de AWS", bodyHtml: `<p>El conector integra inventario y hallazgos de AWS Security Hub y puede agregar recomendaciones, cumplimiento, vulnerabilidades, MDE/EDR y capacidades de Arc.</p><ol><li>Agregá un entorno AWS.</li><li>Elegí cuentas u organización, regiones e intervalo de 4, 6, 12 o 24 horas.</li><li>Elegí planes y aprovisionamiento.</li><li>Implementá CloudFormation y permisos.</li><li>Verificá estado y recomendaciones.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/4-connect-aws-accounts" target="_blank" rel="noopener"><span>Lección oficial<small>Configuración de AWS</small></span></a>` },
          "p3m3-u5": { title: "Conectar cuentas de GCP", bodyHtml: `<p>El conector importa recursos y hallazgos de Security Command Center, luego evalúa recomendaciones, puntuación y estándares como CIS.</p><ol><li>Ingresá organización o proyecto y planes.</li><li>Ejecutá el script <code>gcloud</code> para identidad, cuentas y directivas.</li><li>Habilitá API de IAM, STS, Resource Manager, IAM Credentials y Compute.</li><li>Creá y verificá; los resultados pueden tardar seis horas.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/5-connect-gcp-accounts" target="_blank" rel="noopener"><span>Lección oficial<small>Conector y permisos de GCP</small></span></a>` },
          "p3m3-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá Arc frente a MDE directo, Security Hub frente a Security Command Center, scripts generados, intervalos y permisos necesarios.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación multinube</small></span></a>` },
          "p3m3-u7": { title: "Resumen y recursos", bodyHtml: `<p>Elegí un modelo que aporte inventario, identidad, telemetría y acceso suficientes con permisos mínimos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-non-azure-machines-to-azure-defender/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p3-module-4": {
        title: "Administrar la postura de seguridad en la nube",
        focus: "Enfoque: Puntuación de seguridad, recomendaciones, cumplimiento normativo, Azure Policy y libros de seguridad.",
        units: {
          "p3m4-u1": { title: "Introducción", bodyHtml: `<p>CSPM identifica continuamente riesgo de configuración y lo convierte en mejora priorizada y medible. Las vistas centrales son puntuación, recomendaciones, cumplimiento y libros.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de CSPM</small></span></a>` },
          "p3m4-u2": { title: "Explorar la Puntuación de seguridad", bodyHtml: `<p>Resume qué tan bien se cumplen las recomendaciones, agrupadas en controles. Un control otorga sus puntos cuando todos los recursos aplicables satisfacen sus recomendaciones. Priorizá combinando impacto, recursos, amenaza y esfuerzo. Una puntuación alta no prueba ausencia de vulneraciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/2-explore-secure-score" target="_blank" rel="noopener"><span>Lección oficial<small>Modelo de puntuación</small></span></a>` },
          "p3m4-u3": { title: "Explorar recomendaciones", bodyHtml: `<p>Las recomendaciones evalúan recursos frente al Microsoft Cloud Security Benchmark y directivas asignadas. Los hallazgos son correctos, incorrectos o no aplicables. Abrí una recomendación para ver motivo, recursos, corrección y exenciones; <strong>Corregir</strong> permite corrección masiva cuando está disponible.</p><div class="takeaway"><strong>Clave:</strong> las recomendaciones son evaluaciones accionables; la puntuación es su medida agregada.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/3-explore-recommendations" target="_blank" rel="noopener"><span>Lección oficial<small>Recomendaciones y corrección</small></span></a>` },
          "p3m4-u4": { title: "Medir y aplicar el cumplimiento normativo", bodyHtml: `<p>Los estándares son iniciativas de Azure Policy asignadas a un grupo o suscripción. El panel asigna evaluaciones a controles. Microsoft Cloud Security Benchmark es predeterminado.</p><ol><li>Asigná la iniciativa al alcance correcto.</li><li>Esperá la evaluación.</li><li>Revisá controles y evaluaciones fallidas.</li><li>Corregí, goberná exenciones y exportá evidencia.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/4-measure-enforce-regulatory-compliance" target="_blank" rel="noopener"><span>Lección oficial<small>Estándares e iniciativas</small></span></a>` },
          "p3m4-u5": { title: "Comprender los libros", bodyHtml: `<p>Los libros de Azure Monitor convierten datos en informes interactivos. Ejemplos: Puntuación a lo largo del tiempo, Actualizaciones, Vulnerabilidades, Cumplimiento y Alertas activas. Personalizá o cloná sin alterar los datos de origen.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/5-understand-workbooks" target="_blank" rel="noopener"><span>Lección oficial<small>Libros de seguridad</small></span></a>` },
          "p3m4-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Distinguí puntuación, estado de recomendación, corrección masiva, iniciativas, exenciones y libros; identificá qué vista responde medición, acción, garantía o informes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de CSPM</small></span></a>` },
          "p3m4-u7": { title: "Resumen y recursos", bodyHtml: `<p>Operá CSPM como ciclo: medir, priorizar, corregir o gobernar excepciones, validar cumplimiento y seguir la mejora.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-cloud-security-posture-management/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p3-module-5": {
        title: "Explicar la protección de cargas de trabajo en Microsoft Defender for Cloud",
        focus: "Enfoque: planes específicos, fuentes de telemetría, cobertura de detección y contexto de investigación.",
        units: {
          "p3m5-u1": { title: "Introducción", bodyHtml: `<p>La protección aplica detección adaptada al servicio. Cada plan usa señales nativas, inteligencia de Microsoft y análisis de comportamiento para detectar rutas diferentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de protección</small></span></a>` },
          "p3m5-u2": { title: "Comprender Microsoft Defender for Servers", bodyHtml: `<table><thead><tr><th>Plan</th><th>Cobertura</th></tr></thead><tbody><tr><td>Plan 1</td><td>Incorporación a MDE, EDR, alertas y evaluación de vulnerabilidades.</td></tr><tr><td>Plan 2</td><td>Plan 1 más detección sin agente, exámenes, secretos, líneas base, actualizaciones, integridad de archivos, JIT, mapa de red y más detecciones.</td></tr></tbody></table><p>Se extiende a VM de Azure, servidores Arc y máquinas multinube compatibles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/2-understand-azure-defender-for-servers" target="_blank" rel="noopener"><span>Lección oficial<small>Planes de Servers</small></span></a>` },
          "p3m5-u3": { title: "Comprender Microsoft Defender for App Service", bodyHtml: `<p>Proporciona protección nativa y sin agente para App Service. Analiza señales de plataforma y aplicación, solicitudes entrantes y operaciones de administración para detectar ataques web, acceso sospechoso y actividad posterior.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/3-understand-azure-defender-for-app-service" target="_blank" rel="noopener"><span>Lección oficial<small>Protección de App Service</small></span></a>` },
          "p3m5-u4": { title: "Comprender Microsoft Defender for Storage", bodyHtml: `<p>Protege Blob, Files y Data Lake frente a acceso sospechoso, filtración, cambios de permisos y cargas malintencionadas. La reputación por hash no equivale a inspeccionar contenido; configurá examen de malware cuando sea necesario.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/4-understand-azure-defender-for-storage" target="_blank" rel="noopener"><span>Lección oficial<small>Detección en Storage</small></span></a>` },
          "p3m5-u5": { title: "Comprender Microsoft Defender for SQL", bodyHtml: `<p>Combina evaluación de vulnerabilidades con protección para Azure SQL Database, Managed Instance, Synapse SQL y SQL en máquinas. Detecta inyección, acceso anómalo, fuerza bruta, abuso de privilegios y consultas sospechosas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/5-understand-azure-defender-for-sql" target="_blank" rel="noopener"><span>Lección oficial<small>Evaluación y protección de SQL</small></span></a>` },
          "p3m5-u6": { title: "Comprender Defender para bases de datos de código abierto", bodyHtml: `<p>Monitorea PostgreSQL, MySQL y servicios relacionados frente a acceso inusual, consultas anómalas, fuerza bruta, aplicaciones sospechosas y credenciales posiblemente comprometidas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/6-understand-azure-defender-for-open-source-databases" target="_blank" rel="noopener"><span>Lección oficial<small>Detecciones de bases abiertas</small></span></a>` },
          "p3m5-u7": { title: "Comprender Microsoft Defender for Key Vault", bodyHtml: `<p>Detecta intentos inusuales o dañinos de acceder a claves, secretos y certificados. Las alertas incluyen principal, IP, operación e identificador. Una identidad conocida no vuelve benigna una operación anómala.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/7-understand-azure-defender-for-key-vault" target="_blank" rel="noopener"><span>Lección oficial<small>Anomalías de Key Vault</small></span></a>` },
          "p3m5-u8": { title: "Comprender Microsoft Defender for Resource Manager", bodyHtml: `<p>Analiza operaciones del plano de control mediante portal, API, CLI o automatización. Detecta IP sospechosas, deshabilitación antimalware, extensiones malintencionadas, PowerZure/MicroBurst y movimiento al plano de datos. Investigá con Azure Activity, inicios de identidad, configuración y acciones posteriores.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/8-understand-azure-defender-for-resource-manager" target="_blank" rel="noopener"><span>Lección oficial<small>Detección del plano de control</small></span></a>` },
          "p3m5-u9": { title: "Comprender Microsoft Defender for DNS", bodyHtml: `<p>La telemetría DNS revela comunicaciones incluso con tráfico cifrado. Detecta túneles, C2, dominios malintencionados o de phishing, minería y resolvers sospechosos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/9-understand-azure-defender-for-dns" target="_blank" rel="noopener"><span>Lección oficial<small>Detecciones basadas en DNS</small></span></a>` },
          "p3m5-u10": { title: "Comprender Microsoft Defender for Containers", bodyHtml: `<p>Cubre AKS, EKS y Kubernetes con Arc. Combina recomendaciones, vulnerabilidades de imágenes, directivas, señales de nodos y control, auditoría y detecciones en ejecución.</p><ul><li>Encontrá imágenes vulnerables y dónde se ejecutan.</li><li>Evaluá configuración y admisión.</li><li>Detectá comandos, escalamiento, paneles expuestos y API anómalas.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/11-understand-azure-defender-for-container-registries" target="_blank" rel="noopener"><span>Lección oficial<small>Postura y ejecución de contenedores</small></span></a>` },
          "p3m5-u11": { title: "Comprender protecciones adicionales", bodyHtml: `<p>La cobertura adicional incluye análisis de red, Cosmos DB, alertas de WAF y DDoS e integración con Cloud Apps. Estas señales enriquecen investigaciones entre identidad, aplicación, red y datos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/12-understand-azure-defender-additional-protection" target="_blank" rel="noopener"><span>Lección oficial<small>Protecciones adicionales</small></span></a>` },
          "p3m5-u12": { title: "Evaluación del módulo", bodyHtml: `<p>Relacioná cada carga con su telemetría: endpoint, plataforma de App Service, Storage, consultas de base, objetos de Key Vault, ARM, DNS o auditoría y ejecución de Kubernetes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de cargas</small></span></a>` },
          "p3m5-u13": { title: "Resumen y recursos", bodyHtml: `<p>Elegí planes según servicios, riesgo y profundidad requerida. Investigá con registros nativos y contexto de entidades apropiados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/understand-azure-defender-cloud-workload-protection/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p3-module-6": {
        title: "Corregir alertas de seguridad con Microsoft Defender for Cloud",
        focus: "Enfoque: triage, incidentes, automatización, supresión, inteligencia y respuesta específica por recurso.",
        units: {
          "p3m6-u1": { title: "Introducción", bodyHtml: `<p>Defender for Cloud convierte telemetría en alertas priorizadas e incidentes correlacionados. Una respuesta efectiva valida, contiene, corrige recursos y reduce recurrencia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de respuesta</small></span></a>` },
          "p3m6-u2": { title: "Comprender las alertas de seguridad", bodyHtml: `<p>Las detecciones usan inteligencia, comportamiento y anomalías. Las alertas tienen gravedad y tácticas MITRE; Cloud Smart Alert Correlation agrupa alertas en un <strong>incidente</strong>. La página muestra recursos, entidades, contexto y Tomar medidas.</p><div class="takeaway"><strong>Clave:</strong> una alerta es una detección; un incidente es un conjunto correlacionado.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/2-understand-security-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Alertas e incidentes</small></span></a>` },
          "p3m6-u3": { title: "Corregir alertas y automatizar respuestas", bodyHtml: `<p>Tomar medidas permite mitigar, prevenir, ejecutar Logic Apps o crear supresión. La automatización invoca Logic Apps según suscripción, recurso, alerta o gravedad.</p><ol><li>Validá y determiná alcance.</li><li>Contené identidades, recursos o red.</li><li>Eliminá persistencia y debilidades.</li><li>Restaurá y monitoreá.</li><li>Automatizá acciones deterministas y probadas.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/3-remediate-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Respuesta y Logic Apps</small></span></a>` },
          "p3m6-u4": { title: "Suprimir alertas de Defender for Cloud", bodyHtml: `<p>Usá supresión solo para falsos positivos validados o patrones benignos. Las reglas pueden coincidir con IP, proceso, usuario, recurso o ubicación y vencer hasta en seis meses según la lección. Simulá antes de activar. La alerta se genera, pero se descarta automáticamente. Mantené alcance y motivo documentados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/4-suppress-alerts-from-azure-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Alcance y ciclo de supresión</small></span></a>` },
          "p3m6-u5": { title: "Generar informes de inteligencia sobre amenazas", bodyHtml: `<p>Los informes aportan contexto más allá de una alerta. Los tipos Grupo de actividad, Campaña y Resumen describen actor, objetivos, campañas, TTP, indicadores, víctimas y defensas recomendadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/5-manage-security-incidents" target="_blank" rel="noopener"><span>Lección oficial<small>Tipos de informes</small></span></a>` },
          "p3m6-u6": { title: "Responder a alertas de recursos de Azure", bodyHtml: `<p>Combiná contexto con registros nativos. Para Key Vault, validá principal, IP, operación y objeto; revocá o rotá credenciales; restringí red; revisá Activity y diagnósticos y aplicá recomendaciones. Para otros recursos: validá actor y acción, contené, preservá evidencia, corregí y monitoreá.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/6-respond-alerts-from-azure-resources" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación específica por recurso</small></span></a>` },
          "p3m6-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá alerta frente a incidente, gravedad y MITRE, acciones, automatización, simulación y vencimiento de supresión, informes e investigación nativa.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de corrección</small></span></a>` },
          "p3m6-u8": { title: "Resumen y recursos", bodyHtml: `<p>Realizá triage con contexto, correlacioná el incidente, contené rápido, corregí causas, automatizá acciones deterministas y suprimí solo patrones benignos comprendidos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/remediate-azure-defender-security-alerts/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-4": {
    title: "Crear consultas para Microsoft Sentinel mediante KQL",
    meta: "4 módulos · 29 unidades · Construcción de consultas, agregación, visualización, análisis entre tablas, análisis sintáctico y funciones reutilizables",
    focusAreas: [
      { title: "Fundamentos de KQL", description: "Creá instrucciones con filtrado, proyección, agregación, operaciones temporales y visualización." },
      { title: "Consultas de investigación", description: "Analizá datos entre tablas con joins, unions, análisis, funciones reutilizables y contexto de seguridad de Sentinel." },
    ],
    modules: {
      "p4-module-1": {
        title: "Construir instrucciones KQL para Microsoft Sentinel",
        focus: "Enfoque: canalización tabular, búsquedas amplias, filtros precisos, variables, columnas calculadas, orden y control de salida.",
        units: {
          "p4m1-u1": { title: "Introducción", bodyHtml: `<p>Kusto Query Language (KQL) es el lenguaje de solo lectura detrás de los registros, reglas de análisis, libros y búsqueda de Sentinel. Este módulo presenta operadores para recuperar, filtrar, transformar, ordenar y dar forma a los datos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p4m1-u2": { title: "Comprender la estructura de una instrucción KQL", bodyHtml: `<p>Una consulta es una secuencia de instrucciones. Una expresión tabular comienza con un origen y envía filas por operadores separados por <code>|</code>; cada operador recibe el resultado completo de su izquierda.</p><pre><code>SecurityEvent
| where TimeGenerated &gt; ago(1d)
| summarize Events = count() by Account
| top 10 by Events desc</code></pre><div class="takeaway"><strong>Clave:</strong> el orden cambia significado y rendimiento: origen → filtrar → transformar → agregar → presentar.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/2-understand-kusto-query-language-statement-structure" target="_blank" rel="noopener"><span>Lección oficial<small>Canalización KQL</small></span></a>` },
          "p4m1-u3": { title: "Usar el operador search", bodyHtml: `<p><code>search</code> busca texto entre tablas y columnas. Sirve para descubrir el esquema, pero es menos eficiente que consultar una tabla y columna conocidas.</p><pre><code>search "err"

search in (SecurityEvent, SecurityAlert, A*) "err"</code></pre><div class="takeaway"><strong>Clave:</strong> usá <code>search</code> para descubrir dónde viven los datos y pasá a <code>where</code> en consultas operativas.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/3-use-search-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Búsqueda de texto entre tablas</small></span></a>` },
          "p4m1-u4": { title: "Usar el operador where", bodyHtml: `<p><code>where</code> devuelve filas cuyo predicado booleano es verdadero. Filtrá pronto por tiempo y campos selectivos.</p><pre><code>SecurityEvent
| where TimeGenerated &gt; ago(1h)
| where EventID in (4624, 4625)
| where AccountType =~ "user"</code></pre><ul><li><code>==</code> distingue mayúsculas; <code>=~</code> no.</li><li><code>in (...)</code> prueba contra una lista.</li><li>Varios <code>where</code> mejoran legibilidad.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/4-use-where-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Predicados y filtros</small></span></a>` },
          "p4m1-u5": { title: "Usar la instrucción let", bodyHtml: `<p><code>let</code> vincula un nombre a un escalar, expresión tabular, lista dinámica, vista o función. Mejora legibilidad, reutilización y umbrales consistentes; cada declaración termina en punto y coma.</p><pre><code>let timeframe = 7d;
let suspiciousEvents = dynamic([4625, 4672]);
SecurityEvent
| where TimeGenerated &gt; ago(timeframe)
| where EventID in (suspiciousEvents)</code></pre><p>Una expresión tabular puede referenciarse como tabla. <code>ago()</code> calcula tiempo relativo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/5-use-let-statement" target="_blank" rel="noopener"><span>Lección oficial<small>Variables, listas y reutilización</small></span></a>` },
          "p4m1-u6": { title: "Usar el operador extend", bodyHtml: `<p><code>extend</code> calcula columnas y las agrega al resultado; las existentes permanecen salvo que un operador project las quite.</p><pre><code>SecurityEvent
| where ProcessName != "" and Process != ""
| extend StartDir = substring(ProcessName, 0, string_size(ProcessName) - string_size(Process))</code></pre><p>Usalo para normalizar, convertir tipos, calcular riesgo o derivar campos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/6-use-extend-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Columnas calculadas</small></span></a>` },
          "p4m1-u7": { title: "Usar el operador order by", bodyHtml: `<p><code>order by</code> o <code>sort by</code> ordena por una o más columnas. La dirección predeterminada es descendente; especificá <code>asc</code> o <code>desc</code>.</p><pre><code>SecurityEvent
| order by TimeGenerated desc, Computer asc</code></pre><p>Ordenar es costoso; filtrá y proyectá antes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/7-use-order-by-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Orden de columnas</small></span></a>` },
          "p4m1-u8": { title: "Usar los operadores project", bodyHtml: `<table><thead><tr><th>Operador</th><th>Propósito</th></tr></thead><tbody><tr><td><code>project</code></td><td>Seleccionar, renombrar o calcular salida.</td></tr><tr><td><code>project-away</code></td><td>Quitar columnas.</td></tr><tr><td><code>project-keep</code></td><td>Conservar columnas.</td></tr><tr><td><code>project-rename</code></td><td>Renombrar sin quitar el resto.</td></tr><tr><td><code>project-reorder</code></td><td>Definir el orden visible.</td></tr></tbody></table><pre><code>SecurityEvent
| where EventID == 4625
| project TimeGenerated, Computer, User = Account, IpAddress</code></pre><div class="takeaway"><strong>Clave:</strong> <code>extend</code> agrega columnas; <code>project</code> define el esquema final y reduce ancho.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/8-use-project-operators" target="_blank" rel="noopener"><span>Lección oficial<small>Selección de columnas</small></span></a>` },
          "p4m1-u9": { title: "Evaluación del módulo", bodyHtml: `<p>Elegí el operador correcto: <code>search</code> para ubicación desconocida, <code>where</code> para filas, <code>let</code> para reutilización, <code>extend</code> para cálculos, <code>order by</code> para ordenar y <code>project</code> para la salida.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de construcción</small></span></a>` },
          "p4m1-u10": { title: "Resumen y recursos", bodyHtml: `<p>Creá consultas de izquierda a derecha, filtrá pronto, nombrá lógica reutilizable, derivá solo campos necesarios y terminá con un esquema limitado.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/construct-kusto-query-language-statements/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p4-module-2": {
        title: "Analizar resultados de consultas mediante KQL",
        focus: "Enfoque: agregación, registros más recientes o antiguos, matrices dinámicas, intervalos temporales y visualizaciones.",
        units: {
          "p4m2-u1": { title: "Introducción", bodyHtml: `<p>Las detecciones convierten eventos en recuentos, entidades distintas, umbrales, tendencias y patrones visuales. Este módulo se centra en <code>summarize</code> y <code>render</code>.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p4m2-u2": { title: "Usar el operador summarize", bodyHtml: `<p><code>summarize</code> agrupa filas y calcula agregados. Sin <code>by</code> produce un grupo; con <code>by</code>, una fila por combinación.</p><pre><code>SecurityEvent
| where EventID == 4688
| summarize ProcessStarts = count() by Process, Computer</code></pre><p>Funciones: <code>count/countif</code>, <code>dcount</code>, <code>sum/avg</code>, <code>min/max</code>, <code>percentile/stdev</code>.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/2-use-summarize-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Agrupación y agregados</small></span></a>` },
          "p4m2-u3": { title: "Usar summarize para filtrar resultados", bodyHtml: `<p><code>arg_max()</code> y <code>arg_min()</code> devuelven la fila completa asociada al máximo o mínimo de cada grupo.</p><pre><code>SecurityEvent
| summarize arg_max(TimeGenerated, *) by Account</code></pre><p>Filtrar 4624 antes devuelve el último inicio; después devuelve cuentas cuyo último evento cualquiera fue un inicio.</p><div class="takeaway"><strong>Clave:</strong> usá <code>max</code> para el valor y <code>arg_max</code> para columnas de la fila correspondiente.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/3-use-summarize-operator-to-filter-results" target="_blank" rel="noopener"><span>Lección oficial<small>Filas más recientes y antiguas</small></span></a>` },
          "p4m2-u4": { title: "Usar summarize para preparar datos", bodyHtml: `<p><code>make_list()</code> crea una matriz JSON con todos los valores, incluidos duplicados; <code>make_set()</code> crea valores distintos.</p><pre><code>SecurityEvent
| where EventID == 4624
| summarize Accounts = make_set(Account) by Computer</code></pre><p>Sirven para contexto de entidades, agrupación y expansión posterior con <code>mv-expand</code>.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/4-use-summarize-operator-to-prepare-data" target="_blank" rel="noopener"><span>Lección oficial<small>Listas y conjuntos dinámicos</small></span></a>` },
          "p4m2-u5": { title: "Usar render para crear visualizaciones", bodyHtml: `<p><code>render</code> convierte resultados en gráficos de área, barras, columnas, circular, dispersión o tiempo. Prepará columnas con <code>summarize</code>.</p><pre><code>SecurityEvent
| summarize Events = count() by bin(TimeGenerated, 1d)
| render timechart</code></pre><p><code>bin()</code> redondea a intervalos fijos. Los gráficos sirven para análisis y libros; las reglas evalúan la lógica tabular.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/5-use-render-operator-to-create-visualizations" target="_blank" rel="noopener"><span>Lección oficial<small>Gráficos, series e intervalos</small></span></a>` },
          "p4m2-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá agrupación frente a filtrado, <code>count/dcount</code>, <code>max/arg_max</code>, <code>make_list/make_set</code> y la relación <code>bin</code>, <code>summarize</code>, <code>render</code>.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de análisis</small></span></a>` },
          "p4m2-u7": { title: "Resumen y recursos", bodyHtml: `<p>Transformá eventos en evidencia agrupando con la granularidad correcta, conservando filas representativas y visualizando resultados bien formados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-results-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p4-module-3": {
        title: "Crear instrucciones entre varias tablas mediante KQL",
        focus: "Enfoque: anexar filas de esquemas relacionados y correlacionarlas mediante claves coincidentes.",
        units: {
          "p4m3-u1": { title: "Introducción", bodyHtml: `<p>Las investigaciones rara vez permanecen en una tabla. <code>union</code> combina verticalmente flujos y <code>join</code> correlaciona horizontalmente por atributos compartidos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/build-multi-table-statements-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos entre tablas</small></span></a>` },
          "p4m3-u2": { title: "Usar el operador union", bodyHtml: `<p><code>union</code> anexa filas. Las columnas compatibles se alinean y las ausentes quedan nulas.</p><pre><code>union withsource=SourceTable Security*
| summarize Events = count() by SourceTable</code></pre><p>Los comodines incluyen tablas; <code>withsource</code> conserva procedencia. Los paréntesis permiten subconsultas por rama.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/build-multi-table-statements-kusto-query-language/2-use-union-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Anexar y preservar origen</small></span></a>` },
          "p4m3-u3": { title: "Usar el operador join", bodyHtml: `<p><code>join</code> relaciona filas de expresiones izquierda y derecha por claves y devuelve columnas según el tipo.</p><pre><code>SigninLogs
| where ResultType != 0
| project UserPrincipalName, IPAddress, TimeGenerated
| join kind=inner (IdentityInfo | project AccountUPN, Department)
  on $left.UserPrincipalName == $right.AccountUPN</code></pre><p>Tipos: <code>inner</code> todas las coincidencias; <code>innerunique</code> deduplica izquierda y es predeterminado; <code>leftouter</code> conserva izquierda; <code>leftsemi</code> las que coinciden; <code>leftanti</code> las que no; <code>fullouter</code> todas.</p><div class="takeaway"><strong>Clave:</strong> filtrá y proyectá ambos lados y colocá el conjunto más pequeño a la izquierda.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/build-multi-table-statements-kusto-query-language/3-use-join-operator" target="_blank" rel="noopener"><span>Lección oficial<small>Claves y tipos de join</small></span></a>` },
          "p4m3-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Elegí <code>union</code> para filas de varias fuentes y <code>join</code> para enriquecer o correlacionar por clave. Comprendé cómo el tipo controla registros sin coincidencia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/build-multi-table-statements-kusto-query-language/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación entre tablas</small></span></a>` },
          "p4m3-u5": { title: "Resumen y recursos", bodyHtml: `<p>Combiná tablas intencionalmente: anexá eventos comparables con procedencia o correlacioná conjuntos reducidos mediante claves confiables.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/build-multi-table-statements-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p4-module-4": {
        title: "Trabajar con datos de Microsoft Sentinel mediante KQL",
        focus: "Enfoque: análisis de texto no estructurado, JSON dinámico, datos externos y funciones de análisis reutilizables.",
        units: {
          "p4m4-u1": { title: "Introducción", bodyHtml: `<p>Los registros suelen almacenar valores en mensajes libres, objetos JSON, matrices o archivos externos. KQL los extrae y normaliza en esquemas tabulares reutilizables.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de manipulación</small></span></a>` },
          "p4m4-u2": { title: "Extraer datos de cadenas no estructuradas", bodyHtml: `<p><code>extract()</code> usa regex y grupo de captura para devolver una subcadena, opcionalmente tipada; devuelve nulo si falla.</p><pre><code>SecurityEvent
| extend AccountName = extract(@"^(.*\\)?([^@]*)(@.*)?$", 2, tolower(Account))</code></pre><p><code>parse</code> coincide con un patrón mayor y crea varias columnas. Modos: <code>simple</code>, <code>regex</code> y <code>relaxed</code>.</p><div class="takeaway"><strong>Clave:</strong> <code>extract</code> para una captura; <code>parse</code> para varios campos en un formato predecible.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/2-extract-data-from-unstructured-string-fields" target="_blank" rel="noopener"><span>Lección oficial<small>Regex y patrones</small></span></a>` },
          "p4m4-u3": { title: "Extraer datos de cadenas estructuradas", bodyHtml: `<p>El tipo <code>dynamic</code> almacena matrices y property bags. Accedé con punto o corchetes y convertí a escalar cuando corresponda.</p><pre><code>SigninLogs
| extend OS = tostring(DeviceDetail.operatingSystem), StatusCode = tostring(Status.errorCode)</code></pre><p><code>parse_json()/todynamic()</code> interpreta JSON; <code>mv-expand</code> crea una fila por elemento; <code>mv-apply</code> ejecuta una subconsulta por elemento y une resultados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/3-extract-data-from-structured-string-data" target="_blank" rel="noopener"><span>Lección oficial<small>Campos dinámicos, JSON y matrices</small></span></a>` },
          "p4m4-u4": { title: "Integrar datos externos", bodyHtml: `<p><code>externaldata</code> define un esquema y lee filas de Blob o Data Lake. Sirve para referencias pequeñas, no ingesta continua.</p><pre><code>let KnownIPs = externaldata(IPAddress:string)
[
  h@"https://storage.example/known.csv?...SAS..."
]
with (format="csv", ignoreFirstRecord=true);
SigninLogs
| where IPAddress in (KnownIPs)</code></pre><p>Protegé credenciales y SAS; no pongas secretos en consultas compartidas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/4-integrate-external-data" target="_blank" rel="noopener"><span>Lección oficial<small>Tablas de referencia externas</small></span></a>` },
          "p4m4-u5": { title: "Crear analizadores mediante funciones", bodyHtml: `<p>Un analizador es una función KQL que convierte datos no estructurados en una tabla virtual estable. Creá y probá la consulta, elegí Guardar como función y asigná nombre y parámetros.</p><pre><code>// Saved as function: PrivLogins
SecurityEvent
| where EventID == 4672
| where AccountType == "User"

PrivLogins
| summarize Events = count() by Account</code></pre><p>Las funciones centralizan normalización para reglas, libros y búsquedas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/5-create-parsers-functions" target="_blank" rel="noopener"><span>Lección oficial<small>Funciones de análisis guardadas</small></span></a>` },
          "p4m4-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Distinguí <code>extract/parse</code>, escalares de <code>dynamic</code>, <code>mv-expand/mv-apply</code>, datos externos de registros ingeridos y consulta ad hoc de función guardada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de manipulación</small></span></a>` },
          "p4m4-u7": { title: "Resumen y recursos", bodyHtml: `<p>Normalizá al consultar: extraé campos estables, expandí matrices cuidadosamente, enriquecé con datos gobernados y guardá lógica repetida como funciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/work-with-data-kusto-query-language/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-5": {
    title: "Configurar el entorno de Microsoft Sentinel",
    meta: "6 módulos · 42 unidades · Arquitectura SIEM, áreas de trabajo, registros, listas de seguimiento, inteligencia sobre amenazas y SIEM/XDR unificados",
    focusAreas: [
      { title: "Base de Sentinel", description: "Comprendé el flujo SIEM y diseñá áreas de trabajo, permisos, retención y niveles de datos." },
      { title: "Contexto de seguridad", description: "Usá registros, listas de seguimiento, inteligencia e integración con Defender XDR para apoyar las operaciones." },
    ],
    modules: {
      "p5-module-1": {
        title: "Introducción a Microsoft Sentinel",
        focus: "Enfoque: SIEM y SOAR nativos de nube, flujo integral y casos de uso apropiados.",
        units: {
          "p5m1-u1": { title: "Introducción", bodyHtml: `<p>Microsoft Sentinel es una plataforma SIEM y SOAR nativa de nube. Recopila señales de entornos de nube, locales y multinube para detección, investigación, búsqueda y respuesta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p5m1-u2": { title: "¿Qué es Microsoft Sentinel?", bodyHtml: `<p>Un SIEM centraliza registros, consultas, correlación, anomalías, alertas, visualización e incidentes. Sentinel lo ofrece como servicio sin servidores SIEM dedicados.</p><ul><li><strong>Recopilar:</strong> datos de Microsoft y terceros.</li><li><strong>Detectar:</strong> análisis, ML e inteligencia.</li><li><strong>Investigar:</strong> correlacionar alertas en incidentes y entidades.</li><li><strong>Responder:</strong> reglas de automatización y Logic Apps.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/2-what-is-azure-sentinel" target="_blank" rel="noopener"><span>Lección oficial<small>SIEM y Sentinel</small></span></a>` },
          "p5m1-u3": { title: "Cómo funciona Microsoft Sentinel", bodyHtml: `<div class="flow"><div class="flow-step"><strong>1 · Ingerir</strong>Soluciones y conectores llevan datos al área.</div><div class="flow-step"><strong>2 · Analizar</strong>KQL, reglas, UEBA e inteligencia detectan.</div><div class="flow-step"><strong>3 · Investigar</strong>Alertas se correlacionan en incidentes.</div><div class="flow-step"><strong>4 · Responder</strong>Reglas y cuadernos enriquecen, enrutan o contienen.</div></div><p>Los libros visualizan KQL; consultas y notebooks permiten búsqueda proactiva. El Centro de contenido empaqueta conectores, análisis, libros, búsquedas y automatización.</p><div class="takeaway"><strong>Clave:</strong> conector → tabla → alerta → incidente → automatización.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/3-how-azure-sentinel-works" target="_blank" rel="noopener"><span>Lección oficial<small>Componentes y flujo</small></span></a>` },
          "p5m1-u4": { title: "Cuándo usar Microsoft Sentinel", bodyHtml: `<p>Usalo cuando el SOC necesite recopilación y análisis de fuentes diversas, búsqueda, investigación y respuesta automática sin administrar infraestructura SIEM. Admite datos híbridos, multinube y cientos de conectores de Logic Apps.</p><p>Usá Azure Monitor/Log Analytics para monitoreo operativo; Defender for Cloud para postura y cargas; enviá sus alertas a Sentinel para correlación central.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/4-when-to-use-azure-sentinel" target="_blank" rel="noopener"><span>Lección oficial<small>Casos de uso y servicios adyacentes</small></span></a>` },
          "p5m1-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá SIEM frente a SOAR, el modelo nativo y qué componentes realizan ingesta, visualización, detección, investigación, búsqueda y respuesta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Fundamentos de Sentinel</small></span></a>` },
          "p5m1-u6": { title: "Resumen", bodyHtml: `<p>Sentinel ofrece operaciones integrales: ingerir ampliamente, detectar, investigar incidentes correlacionados, buscar proactivamente y automatizar respuesta repetible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/intro-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p5-module-2": {
        title: "Crear y administrar áreas de trabajo de Microsoft Sentinel",
        focus: "Enfoque: arquitectura, región y tenant, incorporación, RBAC, retención, planes de tablas y niveles de datos.",
        units: {
          "p5m2-u1": { title: "Introducción", bodyHtml: `<p>Sentinel se habilita en un área de Log Analytics. Su arquitectura determina residencia, alcance de consultas, acceso, retención, costos y administración del contenido.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de áreas de trabajo</small></span></a>` },
          "p5m2-u2": { title: "Planificar el área de trabajo", bodyHtml: `<table><thead><tr><th>Arquitectura</th><th>Ventaja</th><th>Compensación</th></tr></thead><tbody><tr><td>Un tenant, un área</td><td>Vista central y contenido simple.</td><td>Ancho de banda y residencia.</td></tr><tr><td>Áreas regionales</td><td>Gobernanza, retención, acceso y facturación regionales.</td><td>Contenido repetido y consultas entre áreas.</td></tr><tr><td>Varios tenants</td><td>Proveedores y organizaciones distribuidas.</td><td>Administración delegada como Lighthouse.</td></tr></tbody></table><pre><code>SecurityEvent
| union workspace("Regional-SOC").SecurityEvent</code></pre><p><strong>La región es crítica:</strong> determina residencia y no puede cambiarse. Un área creada deliberadamente puede compartirse con Defender for Cloud; la predeterminada de este no admite incorporación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/2-plan-for-azure-sentinel-workspace" target="_blank" rel="noopener"><span>Lección oficial<small>Diseños de áreas</small></span></a>` },
          "p5m2-u3": { title: "Crear un área de trabajo de Microsoft Sentinel", bodyHtml: `<ol><li>Creá o elegí Log Analytics con suscripción, grupo, nombre y región correctos.</li><li>Abrí Sentinel, elegí <strong>Agregar</strong>, seleccioná y habilitá.</li><li>Verificá Información general, Centro de contenido, conectores, análisis, incidentes y configuración.</li></ol><p>Habilitar requiere Colaborador de suscripción y usarlo permisos apropiados en el grupo. Puede generar costos.</p><div class="takeaway"><strong>Clave:</strong> nombre y región provienen del área de Log Analytics.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/3-create-azure-sentinel-workspace" target="_blank" rel="noopener"><span>Lección oficial<small>Crear y habilitar</small></span></a>` },
          "p5m2-u4": { title: "Administrar áreas entre tenants con Azure Lighthouse", bodyHtml: `<p><strong>Workspace manager</strong> publica contenido desde un área central a áreas miembro. <strong>Azure Lighthouse</strong> delega acceso a recursos entre tenants para administrar clientes sin cambiar cuentas. Uno centraliza contenido; el otro delega administración y pueden complementarse.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/4-manage-workspaces-across-tenants-using-azure-lighthouse" target="_blank" rel="noopener"><span>Lección oficial<small>Workspace manager y Lighthouse</small></span></a>` },
          "p5m2-u5": { title: "Comprender los permisos y roles de Microsoft Sentinel", bodyHtml: `<table><thead><tr><th>Rol</th><th>Capacidad</th></tr></thead><tbody><tr><td>Reader</td><td>Ver datos, incidentes, libros y recursos.</td></tr><tr><td>Responder</td><td>Reader más asignar y administrar incidentes.</td></tr><tr><td>Contributor</td><td>Crear y editar análisis, libros y contenido; administrar incidentes.</td></tr><tr><td>Automation Contributor</td><td>Rol de servicio para agregar cuadernos a reglas; no para usuarios.</td></tr></tbody></table><p>Autores pueden necesitar Logic App Contributor; la cuenta de servicio necesita permiso en el grupo del cuaderno; invitados necesitan Directory Readers; crear libros puede requerir Workbook Contributor.</p><div class="takeaway"><strong>Clave:</strong> RBAC hereda desde suscripción y grupo; un rol Azure amplio puede otorgar más acceso.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/5-understand-azure-sentinel-permissions-roles" target="_blank" rel="noopener"><span>Lección oficial<small>RBAC y roles complementarios</small></span></a>` },
          "p5m2-u6": { title: "Administrar la configuración de Microsoft Sentinel", bodyHtml: `<p>Configuración específica de Sentinel y del área de Log Analytics gobiernan el entorno. Precios, funciones y vínculos aparecen en Sentinel; ingesta, uso, retención y tablas se administran en Log Analytics o el portal de Defender. La lección muestra retención de 30 a 730 días; las tablas pueden reemplazar el valor del área.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/6-manage-azure-sentinel-settings" target="_blank" rel="noopener"><span>Lección oficial<small>Área y retención</small></span></a>` },
          "p5m2-u7": { title: "Configurar registros", bodyHtml: `<p>Planificá por estado, plan y nivel. <strong>Retención analítica</strong> admite consultas, alertas, búsqueda y libros. <strong>Largo plazo</strong> reduce costo y se accede por trabajos de búsqueda, restauración o lago.</p><table><thead><tr><th>Plan/nivel</th><th>Uso</th><th>Límite</th></tr></thead><tbody><tr><td>Analytics</td><td>Monitoreo, detecciones, joins, búsqueda y libros.</td><td>Mayor costo.</td></tr><tr><td>Basic</td><td>Solución ocasional en una tabla.</td><td>KQL restringido.</td></tr><tr><td>Auxiliary</td><td>Auditoría detallada de poco uso.</td><td>Acceso no optimizado.</td></tr><tr><td>Data lake</td><td>Datos secundarios y a largo plazo.</td><td>Sin análisis en tiempo real; trabajos KQL/Spark.</td></tr><tr><td>XDR predeterminado</td><td>Datos de búsqueda XDR por 30 días.</td><td>No se almacena en niveles Sentinel sin extensión.</td></tr></tbody></table><p>Analytics puede retener 30 días a dos años y el lago hasta 12 años donde se admita. Sacar una tabla de Analytics puede detener alertas, búsquedas y detecciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/7-configure-logs" target="_blank" rel="noopener"><span>Lección oficial<small>Planes, niveles y retención</small></span></a>` },
          "p5m2-u8": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá región y residencia, diseños, Workspace manager frente a Lighthouse, RBAC y consecuencias operativas de planes y niveles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de áreas</small></span></a>` },
          "p5m2-u9": { title: "Resumen y recursos", bodyHtml: `<p>Un buen diseño ubica datos en la región correcta, equilibra visibilidad con gobernanza, aplica privilegios mínimos y alinea costo y retención con detección e investigación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/create-manage-azure-sentinel-workspaces/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p5-module-3": {
        title: "Consultar registros en Microsoft Sentinel",
        focus: "Enfoque: superficies de consulta, tablas de Sentinel, tablas comunes de conectores y esquemas de búsqueda de Defender XDR.",
        units: {
          "p5m3-u1": { title: "Introducción", bodyHtml: `<p>Los analistas deben reconocer dónde se almacenan los datos y qué tabla responde cada pregunta. Nombres, esquemas, retención y superficies determinan qué puede consultar KQL.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de consultas</small></span></a>` },
          "p5m3-u2": { title: "Consultar registros en la página Registros", bodyHtml: `<p>En Defender, usá <strong>Búsqueda avanzada</strong> para consultas interactivas en Analytics y <strong>Exploración del lago</strong> para largo plazo. En Azure, usá <strong>Registros</strong> y cambiá a modo KQL. Confirmá área e intervalo antes de interpretar. La ventana muestra tablas, campos, consultas, resultados, exportación, creación de reglas y vínculo a incidentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/2-query-logs-page" target="_blank" rel="noopener"><span>Lección oficial<small>Búsqueda, lago y Registros</small></span></a>` },
          "p5m3-u3": { title: "Comprender las tablas de Microsoft Sentinel", bodyHtml: `<table><thead><tr><th>Tabla</th><th>Propósito</th></tr></thead><tbody><tr><td><code>SecurityAlert</code></td><td>Alertas de reglas o conectores.</td></tr><tr><td><code>SecurityIncident</code></td><td>Incidentes que agrupan alertas.</td></tr><tr><td><code>ThreatIntelligenceIndicator</code></td><td>Indicadores importados o manuales.</td></tr><tr><td><code>Watchlist</code></td><td>Registros de listas para enriquecimiento.</td></tr></tbody></table><p>Las reglas consultan tablas para crear alertas y la agrupación crea incidentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/3-understand-azure-sentinel-tables" target="_blank" rel="noopener"><span>Lección oficial<small>Tablas de funciones</small></span></a>` },
          "p5m3-u4": { title: "Comprender las tablas comunes", bodyHtml: `<table><thead><tr><th>Origen</th><th>Tabla</th></tr></thead><tbody><tr><td>Plano de control Azure</td><td><code>AzureActivity</code></td></tr><tr><td>Registros de recursos</td><td><code>AzureDiagnostics</code></td></tr><tr><td>Auditoría/inicios Entra</td><td><code>AuditLogs</code>, <code>SigninLogs</code></td></tr><tr><td>Windows/Sysmon</td><td><code>SecurityEvent</code>, <code>Event</code></td></tr><tr><td>Linux/red</td><td><code>Syslog</code>, <code>CommonSecurityLog</code></td></tr><tr><td>Microsoft 365</td><td><code>OfficeActivity</code></td></tr><tr><td>Firewall Windows</td><td><code>WindowsFirewall</code></td></tr></tbody></table><div class="takeaway"><strong>Clave:</strong> elegí la tabla por origen y conector, no solo por entidad investigada.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/4-understand-common-tables" target="_blank" rel="noopener"><span>Lección oficial<small>Tablas frecuentes</small></span></a>` },
          "p5m3-u5": { title: "Comprender las tablas de Microsoft Defender XDR", bodyHtml: `<p>Endpoint: <code>DeviceProcessEvents</code>, <code>DeviceNetworkEvents</code>, <code>DeviceFileEvents</code>, <code>DeviceLogonEvents</code> y <code>DeviceRegistryEvents</code>. Correo: <code>EmailEvents</code>, <code>EmailAttachmentInfo</code>, <code>EmailUrlInfo</code> y <code>UrlClickEvents</code>. <code>CloudAppEvents</code> cubre nube; tablas de identidad cubren directorio; <code>AlertInfo</code> y <code>AlertEvidence</code> conectan detecciones. En el portal unificado se correlacionan con tablas Sentinel según incorporación y retención.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/5-understand-microsoft-365-defender-tables" target="_blank" rel="noopener"><span>Lección oficial<small>Esquemas de búsqueda XDR</small></span></a>` },
          "p5m3-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Relacioná superficies y tablas con alertas, incidentes, Entra, Azure, Windows, red, endpoints, identidades, aplicaciones y correo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de tablas</small></span></a>` },
          "p5m3-u7": { title: "Resumen y recursos", bodyHtml: `<p>Confirmá área, nivel, intervalo, conector y esquema. Consultá la tabla más limitada y correlacioná dominios cuando la evidencia lo exija.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-logs-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p5-module-4": {
        title: "Usar listas de seguimiento en Microsoft Sentinel",
        focus: "Enfoque: conjuntos externos, claves de búsqueda, acceso KQL y flujos de actualización controlados.",
        units: {
          "p5m4-u1": { title: "Introducción", bodyHtml: `<p>Una lista de seguimiento es un conjunto con nombre importado para enriquecimiento, filtrado, correlación, búsqueda, análisis, libros, notebooks y cuadernos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de listas</small></span></a>` },
          "p5m4-u2": { title: "Planificar listas de seguimiento", bodyHtml: `<p>Contienen recursos valiosos, usuarios privilegiados o desvinculados, IP aprobadas, cuentas de servicio, hashes, propietarios o listas de permitir/bloquear. Elegí una columna <strong>SearchKey</strong> estable y completa para filtros, lookups o joins. Se almacenan en caché para baja latencia, pero no reemplazan ingesta continua.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/2-plan-for-azure-watchlists" target="_blank" rel="noopener"><span>Lección oficial<small>Escenarios y diseño</small></span></a>` },
          "p5m4-u3": { title: "Crear una lista de seguimiento", bodyHtml: `<ol><li>Abrí Sentinel &gt; Configuración &gt; Listas y Agregar nueva.</li><li>Indicá nombre, descripción y alias.</li><li>Cargá datos, elegí clave y creá.</li><li>Esperá disponibilidad y probá con KQL.</li></ol><pre><code>_GetWatchlist('HighValueMachines')</code></pre><p>La lección indica límite de 3,8 MB. Usá el alias y protegé datos mediante acceso al área.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/3-create-watchlist" target="_blank" rel="noopener"><span>Lección oficial<small>Crear y consultar</small></span></a>` },
          "p5m4-u4": { title: "Administrar listas de seguimiento", bodyHtml: `<p>Editá elementos para cambios pequeños. La actualización masiva anexa y deduplica solo filas idénticas; no elimina elementos omitidos. La clave debe existir y no estar vacía. Preferí editar frente a eliminar y recrear; el SLA de ingesta de cinco minutos puede mostrar registros antiguos y nuevos.</p><div class="takeaway"><strong>Clave:</strong> la actualización masiva anexa y deduplica, no sincroniza completamente.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/4-manage-watchlists" target="_blank" rel="noopener"><span>Lección oficial<small>Edición y actualizaciones</small></span></a>` },
          "p5m4-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá casos de uso, alias, clave, <code>_GetWatchlist()</code>, límites y diferencias entre editar, actualizar masivamente y recrear.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de listas</small></span></a>` },
          "p5m4-u6": { title: "Resumen y recursos", bodyHtml: `<p>Usá listas gobernadas para contexto externo compacto y mantenelas con esquemas, claves, responsables y procesos documentados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-watchlists-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p5-module-5": {
        title: "Usar inteligencia sobre amenazas en Microsoft Sentinel",
        focus: "Enfoque: fuentes CTI, ciclo de indicadores, etiquetas, KQL, análisis y búsqueda.",
        units: {
          "p5m5-u1": { title: "Introducción", bodyHtml: `<p>Sentinel puede ingerir, crear, administrar, consultar y operacionalizar indicadores para correlacionar telemetría con infraestructura y artefactos malintencionados conocidos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de inteligencia</small></span></a>` },
          "p5m5-u2": { title: "Definir inteligencia sobre amenazas", bodyHtml: `<p>CTI proviene de fuentes abiertas, comunidades, proveedores o investigaciones internas. Informes estratégicos y operativos describen actores, motivos, campañas y técnicas; indicadores tácticos describen IP, dominios, URL, hashes e IoC. Sentinel importa mediante conectores, administra, correlaciona con reglas, visualiza y usa en búsquedas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/2-define-threat-intelligence" target="_blank" rel="noopener"><span>Lección oficial<small>Fuentes y usos de CTI</small></span></a>` },
          "p5m5-u3": { title: "Administrar indicadores de amenazas", bodyHtml: `<p>El área permite ver, filtrar, buscar, crear, editar y etiquetar sin KQL. Las propiedades incluyen observable, confianza, descripción, origen, validez, tipo y etiquetas. Usá convenciones consistentes para actor, campaña, incidente, origen o clasificación; aplicá varias etiquetas y edición masiva.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/3-manage-threat-indicators" target="_blank" rel="noopener"><span>Lección oficial<small>Creación, filtros y etiquetas</small></span></a>` },
          "p5m5-u4": { title: "Ver indicadores mediante KQL", bodyHtml: `<p>Consultá la tabla para validar ingesta, encontrar indicadores activos, agrupar y correlacionar. Filtrá vencidos o revocados.</p><pre><code>ThreatIntelligenceIndicator
| where Active == true
| where ExpirationDateTime &gt; now()
| summarize Indicators = count() by ThreatType, SourceSystem</code></pre><p>Normalizá observables, limitá intervalos de indicadores y eventos y usá el esquema actual del área.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/4-view-threat-indicators-with-kql" target="_blank" rel="noopener"><span>Lección oficial<small>Consultar y correlacionar</small></span></a>` },
          "p5m5-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá fuentes CTI, informes frente a IoC, conectores, propiedades y etiquetas, filtros de actividad/vencimiento y operacionalización mediante análisis, búsqueda y libros.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de inteligencia</small></span></a>` },
          "p5m5-u6": { title: "Resumen y recursos", bodyHtml: `<p>La inteligencia aporta valor cuando los indicadores tienen origen, normalización, límites temporales, etiquetas, control de calidad y correlación relevante.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/utilize-threat-intelligence-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p5-module-6": {
        title: "Integrar Microsoft Defender XDR con Microsoft Sentinel",
        focus: "Enfoque: SIEM/XDR unificado, diferencias de portales, requisitos, conexión y modelo operativo integrado.",
        units: {
          "p5m6-u1": { title: "Introducción", bodyHtml: `<p>Incorporar un área de Sentinel al portal de Defender combina la recopilación y contenido SIEM con incidentes, detecciones, entidades, búsqueda y respuesta XDR en una experiencia unificada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos</small></span></a>` },
          "p5m6-u2": { title: "Comprender los beneficios de integrar Sentinel con Defender XDR", bodyHtml: `<ul><li>Una cola unificada correlaciona evidencia XDR y Sentinel.</li><li>Búsqueda avanzada consulta telemetría XDR y tablas del área.</li><li>Un portal reúne triage, investigación, búsqueda, automatización, contenido, conectores y configuración.</li><li>La correlación de Microsoft reemplaza rutas duplicadas.</li></ul><p>La integración conserva RBAC de Azure y lleva datos y capacidades al portal.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/2-benefits-of-integration" target="_blank" rel="noopener"><span>Lección oficial<small>Beneficios de SIEM/XDR unificado</small></span></a>` },
          "p5m6-u3": { title: "Explorar diferencias entre portales", bodyHtml: `<p>La mayoría de funciones existe en ambos, pero algunas son específicas o se comportan distinto. La lección cita marcadores en búsqueda, edición de comentarios y tareas solo en Azure; interrupción de ataques SAP y ciertas operaciones solo en Defender; y procedimientos de automatización distintos.</p><p>Tras incorporar, la correlación XDR reemplaza Fusion para alertas de seguridad de Microsoft y cambian comportamientos de creación o reapertura. Verificá el portal requerido.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/3-capability-differences-between-portals" target="_blank" rel="noopener"><span>Lección oficial<small>Diferencias Azure/Defender</small></span></a>` },
          "p5m6-u4": { title: "Incorporar Microsoft Sentinel a Microsoft Defender XDR", bodyHtml: `<p>Requiere un área con Sentinel, solución y conector de Defender XDR con incidentes/alertas, acceso XDR en el mismo tenant y roles adecuados.</p><ol><li>En Defender, elegí <strong>Conectar un área</strong>.</li><li>Seleccioná y revisá cambios.</li><li>Confirmá tablas y funciones en búsqueda avanzada.</li><li>Conectá y verificá métricas, incidentes, conectores y automatización.</li></ol><p>Owner o User Access Administrator más Sentinel Contributor conectan/desconectan; Reader ve y consulta; Contributor actúa. RBAC continúa en Azure.</p><div class="takeaway"><strong>Clave:</strong> la incorporación puede desactivar reglas de creación de incidentes para evitar duplicados.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/4-onboarding-sentinel-to-defender-xdr" target="_blank" rel="noopener"><span>Lección oficial<small>Requisitos, roles y conexión</small></span></a>` },
          "p5m6-u5": { title: "Explorar funciones de Sentinel en Microsoft Defender XDR", bodyHtml: `<p>Información general, Incidentes y Búsqueda avanzada combinan datos. La navegación específica incluye Búsqueda, Administración de amenazas, Contenido y Configuración.</p><ul><li><strong>Amenazas:</strong> libros, búsqueda, marcadores, livestream, notebooks, TI y MITRE.</li><li><strong>Contenido:</strong> Centro y repositorios.</li><li><strong>Configuración:</strong> conectores, reglas, listas, automatización y cuadernos.</li><li><strong>Sistema:</strong> área e integración.</li></ul><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/5-exploring-sentinel-features-in-defender-xdr" target="_blank" rel="noopener"><span>Lección oficial<small>Mapa del portal unificado</small></span></a>` },
          "p5m6-u6": { title: "Ejercicio: conectar Microsoft Sentinel con Microsoft Defender XDR", bodyHtml: `<p>Practicá localizar el flujo, seleccionar un área, revisar requisitos y cambios, completar la incorporación y confirmar que las funciones aparecen en Defender.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/simulation-exercise-deploy-sentinel-to-defender" target="_blank" rel="noopener"><span>Simulación oficial<small>Conectar Sentinel</small></span></a>` },
          "p5m6-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá beneficios, capacidades específicas, requisitos de conector y RBAC, efectos de incorporación, conexión/desconexión y ubicación de funciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación SIEM/XDR</small></span></a>` },
          "p5m6-u8": { title: "Resumen", bodyHtml: `<p>El portal unifica amplitud SIEM y telemetría/correlación XDR, mientras datos, retención y RBAC siguen gobernados por recursos de Azure.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/integrate-microsoft-defender-xdr-with-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-6": {
    title: "Conectar registros a Microsoft Sentinel",
    meta: "7 módulos · 49 unidades · Centro de contenido, servicios de Microsoft, Defender, Windows, CEF, Syslog e inteligencia sobre amenazas",
    focusAreas: [
      { title: "Incorporación de datos", description: "Seleccioná y configurá conectores para servicios de Microsoft, Defender, Windows, CEF y Syslog." },
      { title: "Confiabilidad de la recopilación", description: "Planificá agentes, DCR, reenvío, tablas de destino, indicadores y validación de ingesta." },
    ],
    modules: {
      "p6-module-1": {
        title: "Conectar datos a Microsoft Sentinel mediante conectores",
        focus: "Enfoque: Centro de contenido, páginas de conectores, proveedores, arquitectura de recopilación y validación de hosts.",
        units: {
          "p6m1-u1": { title: "Introducción", bodyHtml: `<p>Los conectores son el mecanismo principal para ingerir registros, alertas, incidentes, entidades e indicadores desde fuentes de Microsoft, terceros y personalizadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de conectores</small></span></a>` },
          "p6m1-u2": { title: "Ingerir datos de registro con conectores", bodyHtml: `<p>Instalá una solución del Centro de contenido antes de configurar su conector. La página muestra estado, último evento, tablas de destino en Tipos de datos, requisitos, instrucciones y próximos pasos. Las soluciones también instalan reglas, libros, búsquedas, analizadores y cuadernos. Los conectores se desconectan o desactivan, pero no se eliminan independientemente de la solución.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/2-ingest-log-data-with-data-connectors" target="_blank" rel="noopener"><span>Lección oficial<small>Centro y páginas de conectores</small></span></a>` },
          "p6m1-u3": { title: "Comprender los proveedores de conectores", bodyHtml: `<table><thead><tr><th>Proveedor</th><th>Enfoque</th></tr></thead><tbody><tr><td>Defender XDR</td><td>Incidentes, alertas, entidades y eventos opcionales.</td></tr><tr><td>Azure/Microsoft</td><td>API nativas, diagnósticos o Azure Policy.</td></tr><tr><td>Proveedores</td><td>CEF o Syslog mediante reenviador Linux.</td></tr><tr><td>Personalizado</td><td>API de ingesta/DCR, Logstash o integración.</td></tr></tbody></table><p>CEF es estructurado sobre Syslog y llega a <code>CommonSecurityLog</code>; Syslog simple llega a <code>Syslog</code> con <code>SyslogMessage</code> y suele requerir analizador. El reenviador puede estar en Azure, Arc, otra nube o local.</p><div class="takeaway"><strong>Clave:</strong> verificá Tipos de datos; la tabla determina KQL, análisis y costo.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/3-understand-data-connector-providers" target="_blank" rel="noopener"><span>Lección oficial<small>Proveedores y formatos</small></span></a>` },
          "p6m1-u4": { title: "Ver hosts conectados", bodyHtml: `<p>En Log Analytics, abrí Agentes y revisá Windows o Linux. Desde Defender, Sistema &gt; Configuración &gt; Microsoft Sentinel; desde Azure, Configuración &gt; Configuración &gt; Configuración del área. El estado del conector, datos reales y heartbeat validan mejor que el registro del host por sí solo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/4-view-connected-hosts" target="_blank" rel="noopener"><span>Lección oficial<small>Visibilidad de agentes y hosts</small></span></a>` },
          "p6m1-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá Centro de contenido, estado y tipos, proveedores, CEF frente a Syslog, ubicación del reenviador y validación de hosts.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Fundamentos de conectores</small></span></a>` },
          "p6m1-u6": { title: "Resumen y recursos", bodyHtml: `<p>Para cada fuente documentá solución, conector, permisos, transporte, tabla, volumen, señal de estado y detecciones posteriores.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-data-to-azure-sentinel-with-data-connectors/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-2": {
        title: "Conectar servicios de Microsoft a Microsoft Sentinel",
        focus: "Enfoque: Microsoft 365, Microsoft Entra, Identity Protection y Azure Activity.",
        units: {
          "p6m2-u1": { title: "Introducción", bodyHtml: `<p>Los conectores de Microsoft llevan señales de auditoría, identidad, riesgo y plano de control. Cada uno tiene permisos, tablas, costos y comportamiento de incidentes distintos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de conectores Microsoft</small></span></a>` },
          "p6m2-u2": { title: "Planificar conectores de servicios de Microsoft", bodyHtml: `<table><thead><tr><th>Conector</th><th>Salida</th></tr></thead><tbody><tr><td>Microsoft 365</td><td>Auditoría de Exchange, SharePoint y Teams en <code>OfficeActivity</code>.</td></tr><tr><td>Entra ID</td><td>Tablas separadas de auditoría e inicios.</td></tr><tr><td>Identity Protection</td><td>Alertas de riesgo en <code>SecurityAlert</code> e incidentes opcionales.</td></tr><tr><td>Azure Activity</td><td>Eventos ARM en <code>AzureActivity</code>.</td></tr></tbody></table><p>Elegí tipos requeridos por detección e investigación conservando suficiente contexto.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/2-plan-for-microsoft-services-connectors" target="_blank" rel="noopener"><span>Lección oficial<small>Planificación servicio-tabla</small></span></a>` },
          "p6m2-u3": { title: "Conectar Microsoft 365", bodyHtml: `<p>Instalá la solución, abrí el conector, verificá requisitos, elegí Exchange, SharePoint y/o Teams y aplicá. Esperá validación. Usá <code>OfficeActivity</code> para cambios de buzón, archivos, descargas, uso compartido, grupos, Teams y usuario responsable.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/3-connect-microsoft-365-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Ingesta de auditoría M365</small></span></a>` },
          "p6m2-u4": { title: "Conectar Microsoft Entra", bodyHtml: `<table><thead><tr><th>Tipo</th><th>Tabla</th></tr></thead><tbody><tr><td>Usuario interactivo</td><td><code>SigninLogs</code></td></tr><tr><td>No interactivo</td><td><code>AADNonInteractiveUserSignInLogs</code></td></tr><tr><td>Entidad de servicio</td><td><code>AADServicePrincipalSignInLogs</code></td></tr><tr><td>Identidad administrada</td><td><code>AADManagedIdentitySignInLogs</code></td></tr><tr><td>Aprovisionamiento</td><td><code>AADProvisioningLogs</code></td></tr><tr><td>AD FS</td><td><code>ADFSSignInLogs</code></td></tr><tr><td>Auditoría</td><td><code>AuditLogs</code></td></tr></tbody></table><p>Instalá la solución y seleccioná flujos independientemente. El alcance afecta costo y cobertura.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/4-connect-microsoft-entra-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Flujos de Entra</small></span></a>` },
          "p6m2-u5": { title: "Conectar Microsoft Entra ID Protection", bodyHtml: `<p>Instalá la solución y conectá alertas de riesgo. La creación automática activa la regla predeterminada que las convierte en incidentes. Aporta contexto de alerta, no toda la telemetría; combinalo con inicios y auditoría de Entra.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/5-connect-microsoft-entra-id-protection-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Alertas de riesgo e incidentes</small></span></a>` },
          "p6m2-u6": { title: "Conectar Azure Activity", bodyHtml: `<p>Azure Activity captura operaciones ARM de suscripción, escrituras, estado del servicio y resultados. El conector usa Azure Policy.</p><ol><li>Instalá Azure Activity.</li><li>Iniciá la asignación de Policy y elegí suscripción.</li><li>Elegí el área principal.</li><li>Creá una tarea de corrección para suscripciones existentes.</li></ol><p>La lección requiere Owner.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/6-connect-azure-activity-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Ingesta mediante Policy</small></span></a>` },
          "p6m2-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Relacioná servicios con tablas, permisos, flujos seleccionables, alertas frente a datos sin procesar y requisitos de Azure Policy.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de conectores Microsoft</small></span></a>` },
          "p6m2-u8": { title: "Resumen y recursos", bodyHtml: `<p>Conectá el mínimo de flujos que satisfaga auditoría y detección y validá estado y filas representativas en cada tabla.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-services-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-3": {
        title: "Conectar Microsoft Defender XDR a Microsoft Sentinel",
        focus: "Enfoque: integración unificada y en Azure, Defender for Cloud e IoT y reemplazo de conectores heredados.",
        units: {
          "p6m3-u1": { title: "Introducción", bodyHtml: `<p>Los conectores de Defender llevan incidentes y alertas entre dominios y pueden ingerir eventos sin procesar para búsqueda, correlación y análisis.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de conectores Defender</small></span></a>` },
          "p6m3-u2": { title: "Planificar conectores de Microsoft Defender XDR", bodyHtml: `<p>El conector principal cubre Endpoint, Identity, Office 365, Cloud Apps y otros proveedores. Decidí sincronización bidireccional, solo alertas, eventos de búsqueda o entidades. Los conectores individuales son heredados; preferí XDR unificado para evitar duplicados y obtener datos sin procesar.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/2-plan-for-microsoft-defender-xdr-connectors" target="_blank" rel="noopener"><span>Lección oficial<small>Decisiones de integración</small></span></a>` },
          "p6m3-u3": { title: "Conectar Microsoft Defender XDR", bodyHtml: `<p>Al incorporar Sentinel al portal de Defender, el conector se configura automáticamente y desconecta conectores individuales. En Azure, instalá la solución y conectá incidentes y alertas. Se sincronizan título, gravedad, etiquetas, metadatos y comentarios; eventos y entidades opcionales admiten búsqueda y UEBA. Deshabilitá reglas de creación duplicadas. Los incidentes suelen aparecer en cinco minutos; tablas pueden tardar más.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/3-connect-microsoft-defender-xdr-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Conexión y sincronización</small></span></a>` },
          "p6m3-u4": { title: "Conectar Microsoft Defender for Cloud", bodyHtml: `<p>Conectá suscripciones seleccionadas para transmitir alertas a Sentinel. Habilitá sincronización bidireccional cuando los cambios de estado deban fluir entre productos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/4-connect-microsoft-defender-for-cloud-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Alertas de cargas de nube</small></span></a>` },
          "p6m3-u5": { title: "Conectar Microsoft Defender for IoT", bodyHtml: `<p>Conectá la suscripción para ingerir alertas de IoT y usar contenido integrado sobre tendencias, gravedad, alertas principales y recomendaciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/5-connect-microsoft-defender-for-iot" target="_blank" rel="noopener"><span>Lección oficial<small>Alertas y recomendaciones IoT</small></span></a>` },
          "p6m3-u6": { title: "Conectar conectores heredados de Microsoft Defender", bodyHtml: `<p>Los conectores heredados enviaban solo alertas, no telemetría sin procesar, y podían crear incidentes separados. Reemplazalos por Microsoft Defender XDR cuando sea compatible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/6-connect-microsoft-defender-legacy-connectors" target="_blank" rel="noopener"><span>Lección oficial<small>Limitaciones y migración</small></span></a>` },
          "p6m3-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá integración automática/manual, sincronización, datos opcionales, prevención de duplicados, Cloud/IoT y limitaciones heredadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de Defender</small></span></a>` },
          "p6m3-u8": { title: "Resumen y recursos", bodyHtml: `<p>Usá XDR unificado como integración central y controlá deliberadamente incidentes, alertas, entidades y eventos para equilibrar cobertura y costo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-microsoft-365-defender-data-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-4": {
        title: "Conectar hosts de Windows a Microsoft Sentinel",
        focus: "Enfoque: AMA, DCR, Azure Arc, filtrado de eventos, recopilación heredada, WEF y Sysmon.",
        units: {
          "p6m4-u1": { title: "Introducción", bodyHtml: `<p>Los eventos de Windows y Sysmon aportan autenticación, privilegios, procesos, red, registro, archivos y sistema necesarios para detecciones e investigaciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de Windows</small></span></a>` },
          "p6m4-u2": { title: "Planificar el conector de eventos de seguridad de Windows", bodyHtml: `<p>Preferí Eventos de seguridad mediante AMA: usa DCR reutilizables, mejora rendimiento y admite filtrado. Máquinas fuera de Azure requieren Arc. El agente heredado se retiró el 31 de agosto de 2024. Para WEF centralizado, implementá Windows Forwarded Events y recopilá desde un Windows Event Collector.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/2-plan-for-windows-hosts-security-events-connector" target="_blank" rel="noopener"><span>Lección oficial<small>AMA, heredado y WEF</small></span></a>` },
          "p6m4-u3": { title: "Conectar mediante Eventos de seguridad de Windows con AMA", bodyHtml: `<p>Creá una DCR, elegí VM o servidores Arc y recopilación Todos, Comunes, Mínimos o Personalizada. Personalizada acepta XPath 1.0; la lección permite 20 expresiones por cuadro y 100 cuadros.</p><pre><code>$XPath = '*[System[EventID=1035]]'
Get-WinEvent -LogName 'Application' -FilterXPath $XPath</code></pre><p>Probá XPath localmente y filtrá en origen preservando eventos requeridos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/3-connect-using-windows-security-events-via-ama" target="_blank" rel="noopener"><span>Lección oficial<small>Alcance DCR y XPath</small></span></a>` },
          "p6m4-u4": { title: "Conectar mediante el agente heredado", bodyHtml: `<table><thead><tr><th>Conjunto</th><th>Cobertura</th></tr></thead><tbody><tr><td>Todos</td><td>Eventos de seguridad y AppLocker.</td></tr><tr><td>Comunes</td><td>Volumen manejable con auditoría de usuario.</td></tr><tr><td>Mínimos</td><td>Eventos de bajo volumen relevantes al compromiso; no auditoría completa.</td></tr><tr><td>Personalizados</td><td>Registros y XPath explícitos.</td></tr></tbody></table><p>Se consultan en <code>SecurityEvent</code>. Tratá lo heredado como excepción y migrá a AMA.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/4-connect-using-security-events-via-legacy-agent-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Conjuntos heredados</small></span></a>` },
          "p6m4-u5": { title: "Recopilar registros de Sysmon", bodyHtml: `<p>Sysmon registra procesos, conexiones, cambios de archivos y más. Instalalo por separado y usá WEF y una DCR AMA con ruta personalizada <code>Microsoft-Windows-Sysmon/Operational!*</code>. Windows Forwarded Events instala AMA cuando corresponde. Microsoft recomienda normalización ASIM.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/5-collect-sysmon-event-logs" target="_blank" rel="noopener"><span>Lección oficial<small>Sysmon mediante WEF y AMA</small></span></a>` },
          "p6m4-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá AMA frente a heredado, Arc, alcance DCR, conjuntos, XPath, arquitectura WEC, canal Sysmon y ASIM.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de Windows</small></span></a>` },
          "p6m4-u7": { title: "Resumen y recursos", bodyHtml: `<p>Estandarizá AMA y DCR, usá Arc fuera de Azure, filtrá deliberadamente y validá que los eventos necesarios lleguen a la tabla esperada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-windows-hosts-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-5": {
        title: "Conectar registros Common Event Format a Microsoft Sentinel",
        focus: "Enfoque: CEF mediante AMA, reenviador Linux, DCR, transporte seguro y prevención de duplicados.",
        units: {
          "p6m5-u1": { title: "Introducción", bodyHtml: `<p>CEF es un formato estructurado neutral transportado por Syslog. Sentinel analiza eventos en <code>CommonSecurityLog</code> con campos coherentes entre dispositivos compatibles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-common-event-format-logs-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de CEF</small></span></a>` },
          "p6m5-u2": { title: "Planificar el conector Common Event Format", bodyHtml: `<p>CEF mediante AMA usa un reenviador Linux de 64 bits en Azure, otra nube o local. Los dispositivos envían a rsyslog o syslog-ng y AMA transmite de forma segura al área. Protegé el reenviador, restringí red y configurá TLS cuando corresponda. Validá distribución, daemon, RFC 3164/5424, sudo, conectividad y capacidad con documentación actual.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-common-event-format-logs-to-azure-sentinel/2-plan-for-common-event-format-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura y requisitos</small></span></a>` },
          "p6m5-u3": { title: "Conectar una solución externa mediante CEF", bodyHtml: `<p>Abrí CEF mediante AMA y creá una DCR. Seleccioná el reenviador; AMA se instala si falta. Configurá facilities y gravedades mínimas. Dirigí dispositivos al puerto TCP/UDP 514 y validá <code>CommonSecurityLog</code>. Si maneja CEF y Syslog, excluí las facilities CEF de Syslog para evitar filas duplicadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-common-event-format-logs-to-azure-sentinel/3-connect-your-external-solution-using-common-event-format" target="_blank" rel="noopener"><span>Lección oficial<small>DCR y reenvío CEF</small></span></a>` },
          "p6m5-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá ubicación del reenviador, responsabilidades de AMA/DCR, requisitos Linux, TLS, puerto 514, facilities, gravedades, tabla y prevención de duplicados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-common-event-format-logs-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de CEF</small></span></a>` },
          "p6m5-u5": { title: "Resumen y recursos", bodyHtml: `<p>Preferí CEF cuando el proveedor lo admita porque los campos llegan normalizados. Protegé y monitoreá el reenviador como infraestructura crítica.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-common-event-format-logs-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-6": {
        title: "Conectar fuentes Syslog a Microsoft Sentinel",
        focus: "Enfoque: arquitectura Linux AMA, Azure Arc, filtros de facility/gravedad, validación y analizadores KQL.",
        units: {
          "p6m6-u1": { title: "Introducción", bodyHtml: `<p>Syslog simple admite hosts Linux y dispositivos que no emiten CEF. AMA y una DCR controlan alcance, facilities, gravedades y área de destino.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de Syslog</small></span></a>` },
          "p6m6-u2": { title: "Planificar la recopilación de Syslog", bodyHtml: `<p>rsyslog o syslog-ng recibe mensajes locales y los reenvía por un socket Unix a AMA; AMA los envía por HTTPS a Log Analytics y Sentinel los expone en <code>Syslog</code>. Usá distribuciones compatibles y decidí facilities y gravedades con valor de seguridad antes de recopilar ampliamente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/2-plan-for-syslog-data-collection" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura daemon-AMA</small></span></a>` },
          "p6m6-u3": { title: "Recopilar datos de fuentes Linux mediante Syslog", bodyHtml: `<p>Para VM de Azure, creá una DCR Linux, agregá la VM, elegí Linux Syslog y Azure Monitor Logs; AMA se instala como extensión. Fuera de Azure, ejecutá el script de Arc, conectá <code>azcmagent</code>, verificá Conectado y asociá la DCR.</p><div class="takeaway"><strong>Clave:</strong> Arc aporta identidad de recurso y administración de extensiones para implementar AMA y asociar DCR fuera de Azure.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/3-collect-data-from-linux-based-sources-using-syslog" target="_blank" rel="noopener"><span>Lección oficial<small>VM Azure y Linux con Arc</small></span></a>` },
          "p6m6-u4": { title: "Configurar la DCR para fuentes Syslog", bodyHtml: `<p>Editá el origen Linux Syslog para definir nivel mínimo por facility y confirmar destino. El valor LOG_DEBUG para todo puede generar gran volumen. Los cambios se envían a recursos asociados. Recopilá solo lo requerido, pero documentá exclusiones porque el filtrado agresivo crea brechas permanentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/4-configure-data-collection-rule-for-syslog-data-sources" target="_blank" rel="noopener"><span>Lección oficial<small>Facilities, gravedades y destino</small></span></a>` },
          "p6m6-u5": { title: "Analizar datos Syslog mediante KQL", bodyHtml: `<p>Syslog guarda el cuerpo en <code>SyslogMessage</code>. Extraé campos con <code>extract</code> o <code>parse</code> y guardá lógica estable como función KQL.</p><pre><code>Syslog
| where ProcessName contains "squid"
| extend SourceIP = extract(@"(\d{1,3}(?:\.\d{1,3}){3})", 1, SyslogMessage), Domain = extract(@"https?://([^/: ]+)", 1, SyslogMessage)</code></pre><div class="takeaway"><strong>Clave:</strong> CEF llega analizado a <code>CommonSecurityLog</code>; Syslog simple requiere análisis recurrente o una función guardada.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/5-parse-syslog-data-with-kql" target="_blank" rel="noopener"><span>Lección oficial<small>Análisis de SyslogMessage</small></span></a>` },
          "p6m6-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá flujo del daemon, roles AMA/DCR, incorporación Azure/Arc, filtros, tabla Syslog y funciones de análisis.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de Syslog</small></span></a>` },
          "p6m6-u7": { title: "Resumen y recursos", bodyHtml: `<p>Usá AMA/DCR para recopilación coherente, Arc fuera de Azure, filtros deliberados para costo y analizadores reutilizables para normalización.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-syslog-data-sources-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p6-module-7": {
        title: "Conectar indicadores de amenazas a Microsoft Sentinel",
        focus: "Enfoque: Defender Threat Intelligence, TAXII, API de carga, STIX, autenticación y tablas actuales.",
        units: {
          "p6m7-u1": { title: "Introducción", bodyHtml: `<p>Los conectores importan indicadores externos y de Microsoft para que análisis, búsqueda, libros y cuadernos correlacionen observables malintencionados con actividad organizacional.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de indicadores</small></span></a>` },
          "p6m7-u2": { title: "Planificar conectores de inteligencia", bodyHtml: `<p>Opciones: Defender Threat Intelligence estándar/premium, plataformas TI, TAXII y API de carga. Las soluciones pueden incluir análisis programados, libros, búsquedas y cuadernos. Elegí por origen, licencia, STIX/TAXII, autenticación, frecuencia, calidad e integración requerida.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/2-plan-for-threat-intelligence-connectors" target="_blank" rel="noopener"><span>Lección oficial<small>Opciones y contenido empaquetado</small></span></a>` },
          "p6m7-u3": { title: "Conectar Defender Threat Intelligence", bodyHtml: `<p>Instalá o actualizá la solución, abrí el conector estándar o premium, seleccioná Conectar y confirmá el estado. El feed aporta IoC públicos, abiertos y de alta fidelidad de Microsoft.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/3-connect-defender-threat-intelligence-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Feed de Microsoft Defender TI</small></span></a>` },
          "p6m7-u4": { title: "Conectar el conector TAXII", bodyHtml: `<p>Sentinel admite TAXII 2.0 y 2.1. Configurá nombre, URL raíz, ID de colección y credenciales y agregá el servidor. Monitoreá estado y último indicador. TAXII transporta objetos STIX; no determina calidad ni relevancia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/4-connect-threat-intelligence-taxii-connector" target="_blank" rel="noopener"><span>Lección oficial<small>Configuración TAXII</small></span></a>` },
          "p6m7-u5": { title: "Conectar la API de carga de inteligencia", bodyHtml: `<p>La API en vista previa acepta objetos STIX de una TIP o aplicación. Registrá una aplicación Entra, creá credencial, asigná Sentinel Contributor al área y configurá client ID, OAuth y workspace ID. Protegé secretos, aplicá privilegios mínimos, monitoreá fallos y considerá las condiciones de vista previa.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/5-connect-threat-intelligence-upload-api-connector" target="_blank" rel="noopener"><span>Lección oficial<small>API STIX e identidad</small></span></a>` },
          "p6m7-u6": { title: "Ver indicadores mediante KQL", bodyHtml: `<p>Usá <code>ThreatIntelIndicators</code> y <code>ThreatIntelObjects</code> para esquemas STIX actuales. La ingesta dual a <code>ThreatIntelligenceIndicator</code> terminó después del 31 de julio de 2025; migrá contenido personalizado.</p><pre><code>ThreatIntelIndicators
| where IsDeleted == false
| summarize Indicators = count() by Type</code></pre><p>Verificá campos actuales y filtrá estado y ventanas de validez.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/6-view-your-threat-indicators" target="_blank" rel="noopener"><span>Lección oficial<small>Tablas actuales y heredadas</small></span></a>` },
          "p6m7-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá opciones, MDTI, TAXII, identidad y roles de API, STIX, contenido empaquetado y migración de la tabla heredada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de indicadores</small></span></a>` },
          "p6m7-u8": { title: "Resumen y recursos", bodyHtml: `<p>Elegí feeds confiables, conectalos con seguridad, validá frescura y esquema, migrá consultas y operacionalizá indicadores mediante análisis y búsqueda.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/connect-threat-indicators-to-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-8": {
    title: "Realizar búsqueda de amenazas en Microsoft Sentinel",
    meta: "4 módulos · 25 unidades · Hipótesis, consultas, marcadores, livestream, trabajos de búsqueda, registros restaurados y notebooks",
    focusAreas: [
      { title: "Flujo de búsqueda", description: "Desarrollá hipótesis, administrá consultas, preservá evidencia con marcadores y monitoreá mediante livestream." },
      { title: "Investigación profunda", description: "Usá búsqueda y restauración, notebooks, MSTICPy, API y aprendizaje automático para búsquedas avanzadas." },
    ],
    modules: {
      "p8-module-1": {
        title: "Explicar los conceptos de búsqueda de amenazas en Microsoft Sentinel",
        focus: "Enfoque: búsqueda proactiva, ciclo de vida, hipótesis, documentación y MITRE ATT&CK.",
        units: {
          "p8m1-u1": { title: "Introducción", bodyHtml: `<p>La búsqueda de amenazas investiga proactivamente actividad malintencionada no identificada por las detecciones. Sentinel aporta datos, KQL, ATT&amp;CK y funciones para convertir una idea en evidencia repetible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de búsqueda</small></span></a>` },
          "p8m1-u2": { title: "Comprender las búsquedas de amenazas", bodyHtml: `<p>La búsqueda verdaderamente proactiva comienza sin alerta confirmada ni indicador conocido y prueba una hipótesis de comportamiento. Las búsquedas de indicadores o pivotes de incidentes son valiosas, pero parten de evidencia conocida.</p><div class="flow"><div class="flow-step"><strong>Hipótesis</strong>Definir comportamiento y alcance.</div><div class="flow-step"><strong>Plan</strong>Elegir datos y herramientas.</div><div class="flow-step"><strong>Ejecutar</strong>Consultar e investigar anomalías.</div><div class="flow-step"><strong>Mejorar</strong>Responder, documentar y crear detecciones.</div></div><p>Registrá qué, por qué, cómo, entradas, salidas, pasos, hallazgos y acciones incluso sin amenaza activa.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/2-understand-cybersecurity-threat-hunts" target="_blank" rel="noopener"><span>Lección oficial<small>Proceso continuo</small></span></a>` },
          "p8m1-u3": { title: "Desarrollar una hipótesis", bodyHtml: `<p>Una hipótesis útil es posible con telemetría y experiencia disponibles, tiene alcance limitado, plazo, eficiencia y relevancia para el modelo de amenazas. Ejemplo: cuentas ejecutaron <code>cmd.exe</code> hoy aunque no lo hicieron la semana anterior. Define comportamiento, comparación y ventana.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/3-develop-hypothesis" target="_blank" rel="noopener"><span>Lección oficial<small>Hipótesis comprobables</small></span></a>` },
          "p8m1-u4": { title: "Explorar MITRE ATT&CK", bodyHtml: `<p>ATT&amp;CK organiza objetivos como tácticas y comportamientos como técnicas/subtécnicas. Usalo para convertir inteligencia en hipótesis, identificar telemetría, evaluar brechas y comunicar cobertura. La cobertura no es binaria: validá datos, variaciones detectadas y capacidad de respuesta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/3a-explore-mitre-att-ck" target="_blank" rel="noopener"><span>Lección oficial<small>Búsqueda basada en ATT&amp;CK</small></span></a>` },
          "p8m1-u5": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá búsqueda proactiva frente a indicadores/incidentes, ciclo, documentación, calidad de hipótesis, modelo de amenazas y tácticas/técnicas ATT&amp;CK.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de conceptos</small></span></a>` },
          "p8m1-u6": { title: "Resumen y recursos", bodyHtml: `<p>Una búsqueda madura se guía por hipótesis, se basa en evidencia, es repetible y documentada y se convierte en mejoras de detección o monitoreo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/what-is-threat-hunting-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p8-module-2": {
        title: "Búsqueda de amenazas con Microsoft Sentinel",
        focus: "Enfoque: administración de consultas, marcadores, pivotes de entidades, livestream y flujo práctico.",
        units: {
          "p8m2-u1": { title: "Introducción", bodyHtml: `<p>Sentinel combina consultas KQL reutilizables con marcadores y livestream. Las consultas encuentran candidatos, los marcadores preservan evidencia y livestream observa continuamente nuevas coincidencias.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de herramientas</small></span></a>` },
          "p8m2-u2": { title: "Preparación del ejercicio", bodyHtml: `<p>Implementá el entorno, conectá la telemetría y verificá registros antes de buscar. Conservá recursos hasta el ejercicio final y eliminalos luego si no se necesitan.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/2-exercise-setup" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Preparar telemetría</small></span></a>` },
          "p8m2-u3": { title: "Explorar la creación y administración de consultas", bodyHtml: `<p>La página incluye consultas de Microsoft y personalizadas. Filtrá por origen, táctica, técnica, resultados o favoritos; ejecutá en un intervalo y revisá. Una consulta personalizada incluye nombre, descripción, KQL, tácticas, técnicas y asignaciones de entidades para habilitar pivotes y marcadores.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/3-query-management-creation" target="_blank" rel="noopener"><span>Lección oficial<small>Crear y administrar consultas</small></span></a>` },
          "p8m2-u4": { title: "Guardar hallazgos clave con marcadores", bodyHtml: `<p>Un marcador preserva filas seleccionadas, consulta, intervalo, entidades, notas y etiquetas. Sirve para registrar evidencia, agrupar hallazgos, volver a un pivote o promoverlos a incidente. Es una instantánea y no se actualiza con los datos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/4-bookmarks" target="_blank" rel="noopener"><span>Lección oficial<small>Preservar y promover hallazgos</small></span></a>` },
          "p8m2-u5": { title: "Observar amenazas a lo largo del tiempo con livestream", bodyHtml: `<p>Livestream ejecuta una consulta continuamente y notifica coincidencias. Usalo para monitoreo breve durante una investigación o validación. Optimizá la consulta, elegí período apropiado, evitá duplicados y detené sesiones innecesarias.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/5-livestream" target="_blank" rel="noopener"><span>Lección oficial<small>Monitoreo continuo</small></span></a>` },
          "p8m2-u6": { title: "Ejercicio: buscar amenazas con Microsoft Sentinel", bodyHtml: `<p>Ejecutá y ajustá consultas, investigá resultados, creá marcadores con entidades y notas, revisalos en investigación e iniciá livestream.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/6-exercise-hunt-for-threats" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Consulta, marcador y livestream</small></span></a>` },
          "p8m2-u7": { title: "Resumen", bodyHtml: `<p>Usá consultas para descubrir, marcadores para preservar/compartir y livestream para observar recurrencia. Convertí lógica repetible de alto valor en reglas de análisis.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/hunt-threats-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y evaluación</small></span></a>` },
        },
      },
      "p8-module-3": {
        title: "Usar trabajos de búsqueda en Microsoft Sentinel",
        focus: "Enfoque: búsquedas asincrónicas de períodos largos, tablas de resultados, datos archivados y restauración.",
        units: {
          "p8m3-u1": { title: "Introducción", bodyHtml: `<p>Los trabajos examinan grandes conjuntos y períodos de forma asincrónica cuando las consultas interactivas son imprácticas. Los registros restaurados hacen un intervalo histórico disponible para análisis interactivo de alto rendimiento.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-search-jobs-microsoft-sentinel/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos históricos</small></span></a>` },
          "p8m3-u2": { title: "Buscar con un trabajo de búsqueda", bodyHtml: `<p>Definí tabla, intervalo y filtro KQL, iniciá y monitoreá. Los resultados se escriben en una tabla <code>SearchResults_</code> con registros y metadatos. Sirve para recuperación dirigida de registros Basic o Analytics a largo plazo. Limitá tiempo y predicados para controlar duración y volumen.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-search-jobs-microsoft-sentinel/2-hunt-search-job" target="_blank" rel="noopener"><span>Lección oficial<small>Ejecutar e inspeccionar trabajos</small></span></a>` },
          "p8m3-u3": { title: "Restaurar datos históricos", bodyHtml: `<p>Un trabajo materializa un intervalo de registros Analytics archivados en una tabla restaurada, con KQL completo y alto rendimiento. Restaura un intervalo, no filas filtradas; estimá volumen. Es temporal y facturable: consultá, preservá evidencia y eliminá la tabla al terminar.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-search-jobs-microsoft-sentinel/3-restore-historical-data" target="_blank" rel="noopener"><span>Lección oficial<small>Restaurar registros archivados</small></span></a>` },
          "p8m3-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá casos, ejecución asincrónica, tablas <code>SearchResults_</code>, planes, búsqueda frente a restauración, ciclo, intervalos, costo y limpieza.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-search-jobs-microsoft-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de datos históricos</small></span></a>` },
          "p8m3-u5": { title: "Resumen y recursos", bodyHtml: `<p>Usá búsqueda para recuperación asincrónica dirigida y restauración cuando un intervalo histórico necesite investigación interactiva con KQL completo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-search-jobs-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p8-module-4": {
        title: "Buscar amenazas mediante notebooks en Microsoft Sentinel",
        focus: "Enfoque: API de Log Analytics, Kqlmagic, MSTICPy, Azure Machine Learning, creación y código reutilizable.",
        units: {
          "p8m4-u1": { title: "Introducción", bodyHtml: `<p>Los notebooks combinan Python ejecutable, KQL, visualizaciones y narrativa en una investigación reproducible. Sirven para enriquecimiento, fusión, estadísticas, grafos, ML y flujos que exceden el portal.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos avanzados</small></span></a>` },
          "p8m4-u2": { title: "Acceder a datos de Sentinel con herramientas externas", bodyHtml: `<p>Los datos residen en Log Analytics y se acceden por API estándar. <strong>Kqlmagic</strong> ejecuta KQL desde celdas. <strong>MSTICPy</strong> aporta adquisición, consultas, enriquecimiento, análisis y visualización para Sentinel, Defender y otras fuentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/2-access-azure-sentinel-data-with-external-tools" target="_blank" rel="noopener"><span>Lección oficial<small>Kqlmagic y MSTICPy</small></span></a>` },
          "p8m4-u3": { title: "Buscar mediante notebooks", bodyHtml: `<p>Jupyter separa interfaz y kernel. Las plantillas usan proceso de Azure ML y bibliotecas como pandas, matplotlib, Bokeh, scikit-learn y MSTICPy. Usá plantillas Microsoft como ejemplos, adaptalas al esquema local y revisá notebooks comunitarios como código antes de ejecutarlos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/3-hunt-with-notebooks" target="_blank" rel="noopener"><span>Lección oficial<small>Componentes y usos</small></span></a>` },
          "p8m4-u4": { title: "Crear un notebook", bodyHtml: `<ol><li>Configurá Azure ML desde Sentinel.</li><li>Creá desde Getting Started.</li><li>Abrí en ML Studio y aprovisioná proceso.</li><li>Elegí kernel Python y autenticá.</li><li>Inicializá MSTICPy y revisá <code>msticpyconfig.yaml</code>.</li><li>Consultá y detené proceso al finalizar.</li></ol><p>El proceso cuesta mientras se ejecuta; usá privilegios mínimos y protegé secretos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/4-create-notebook" target="_blank" rel="noopener"><span>Lección oficial<small>Configuración en Azure ML</small></span></a>` },
          "p8m4-u5": { title: "Explorar el código de un notebook", bodyHtml: `<p>El código autentica proveedores, ejecuta KQL, convierte a pandas, enriquece con TI o GeoIP, visualiza escalas o relaciones y registra conclusiones. Ejecutá celdas en orden, inspeccioná resultados, documentá versiones, quitá secretos y salidas sensibles y preservá narrativa reproducible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/5-explore-notebook-code" target="_blank" rel="noopener"><span>Lección oficial<small>Flujo del notebook</small></span></a>` },
          "p8m4-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá API, Kqlmagic, MSTICPy, interfaz/kernel, área y proceso de ML, autenticación, plantillas, ejecución, costo y reproducibilidad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de notebooks</small></span></a>` },
          "p8m4-u7": { title: "Resumen y recursos", bodyHtml: `<p>Los notebooks extienden Sentinel con adquisición, enriquecimiento, análisis y visualización programables. Gobernalos como código revisado, reproducible, de privilegios mínimos, consciente del costo y seguro para evidencia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/perform-threat-hunting-sentinel-with-notebooks/7-summary-resources" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-9": {
    title: "Mitigar amenazas mediante Microsoft Purview",
    meta: "4 módulos · 42 unidades · Alertas DLP, riesgo interno, Auditoría, eDiscovery, Defender XDR y flujos de investigación",
    focusAreas: [
      { title: "Respuesta ante riesgos de datos", description: "Investigá alertas DLP y de riesgo interno, correlacioná evidencia, corregí actividad y administrá casos." },
      { title: "Descubrimiento de evidencia", description: "Buscá, validá, retené y exportá evidencia con Microsoft Purview Audit y eDiscovery." },
    ],
    modules: {
      "p9-module-1": {
        title: "Investigar y responder a alertas de Prevención de pérdida de datos de Microsoft Purview",
        focus: "Enfoque: generación y ciclo de alertas DLP, investigaciones en Purview/Defender, corrección, responsables y ajuste de directivas.",
        units: {
          "p9m1-u1": { title: "Introducción", bodyHtml: `<p>Las alertas DLP generan ruido sin triage coherente. Un proceso confiable confirma el desencadenador, revisa usuario y contenido, correlaciona evidencia, registra decisiones, responde proporcionalmente y devuelve falsos positivos al diseño de la directiva.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de investigación DLP</small></span></a>` },
          "p9m1-u2": { title: "Comprender las alertas de prevención de pérdida de datos", bodyHtml: `<p>Una alerta se genera cuando la actividad coincide con una condición DLP en un evento o eventos agregados. Señala criterios, no intención malintencionada confirmada. Purview ofrece contexto de directiva, regla, contenido y cumplimiento; Defender XDR correlaciona con endpoints, identidad, aplicaciones, correo e incidentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/understand-data-loss-prevention-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Significado y roles de portales</small></span></a>` },
          "p9m1-u3": { title: "Comprender el ciclo de una alerta DLP", bodyHtml: `<div class="flow"><div class="flow-step"><strong>Desencadenar</strong>La actividad coincide.</div><div class="flow-step"><strong>Triage</strong>Validar gravedad, usuario, contenido y evento.</div><div class="flow-step"><strong>Investigar</strong>Correlacionar actividades e incidentes.</div><div class="flow-step"><strong>Resolver</strong>Corregir, documentar, cerrar y ajustar.</div></div><p>Asigná responsable pronto, preservá evidencia, actualizá estado y usá disposiciones coherentes para mantener métricas útiles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/data-loss-prevention-alert-lifecycle" target="_blank" rel="noopener"><span>Lección oficial<small>Ciclo de tratamiento</small></span></a>` },
          "p9m1-u4": { title: "Configurar directivas DLP para generar alertas", bodyHtml: `<p>El comportamiento depende de condiciones, ubicaciones, usuarios/grupos, umbrales de información confidencial, gravedad y agregación. Elegí alertas según riesgo y capacidad operativa. Usá modo de prueba, informes, sugerencias, invalidaciones y excepciones acotadas antes de aplicar ampliamente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/configure-data-loss-prevention-alert-generation" target="_blank" rel="noopener"><span>Lección oficial<small>Controles de generación</small></span></a>` },
          "p9m1-u5": { title: "Investigar alertas DLP en Microsoft Purview", bodyHtml: `<p>Revisá resumen, directiva, regla, gravedad, estado, responsable, eventos, usuario, ubicación, tipos de información, metadatos y actividad relacionada. Activity explorer coloca el evento en un patrón. Determiná si es uso legítimo, exposición accidental, error de clasificación o actividad potencialmente malintencionada.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/investigate-alerts-purview" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación en Purview</small></span></a>` },
          "p9m1-u6": { title: "Investigar alertas DLP en Microsoft Defender XDR", bodyHtml: `<p>Abrí la alerta o incidente para correlacionar alertas, dispositivos, identidades, aplicaciones, archivos y escalas de tiempo. Usá grafo, evidencia, entidades, búsqueda avanzada y Centro de acciones para determinar si forma parte de un ataque mayor.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/investigate-alerts-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación entre dominios</small></span></a>` },
          "p9m1-u7": { title: "Investigar alertas DLP con Security Copilot y agentes de IA", bodyHtml: `<p>Copilot puede resumir, interpretar actividad, destacar evidencia y sugerir pasos; los agentes ayudan con triage repetitivo. El analista debe validar contra fuentes, preservar privilegios mínimos y límites de datos y mantener aprobación humana para respuestas importantes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/investigate-alerts-security-copilot-agents" target="_blank" rel="noopener"><span>Lección oficial<small>Triage asistido por IA</small></span></a>` },
          "p9m1-u8": { title: "Responder a alertas DLP", bodyHtml: `<p>La respuesta puede contactar al usuario o gerente, quitar acceso, eliminar o poner contenido en cuarentena, contener dispositivo, escalar a riesgo interno/legal, actualizar estado y documentar. Para patrones benignos repetidos, ajustá alcance, umbrales, clasificadores, excepciones o agregación sin debilitar el riesgo real.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/respond-data-loss-prevention-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Corrección y retroalimentación</small></span></a>` },
          "p9m1-u9": { title: "Ejercicio: investigar una alerta DLP y su incidente", bodyHtml: `<p>Usá Purview para revisar regla, evento, datos y usuario; pasá a Defender XDR para incidente y evidencia. Asigná responsable, registrá hallazgos, elegí respuesta y cerrá con disposición defendible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/exercise-investigate-alert" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Investigación Purview-Defender</small></span></a>` },
          "p9m1-u10": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá generación/agregación, ciclo, roles de portales, evidencia, validación de Copilot, respuesta, responsables, cierre y ajuste.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación DLP</small></span></a>` },
          "p9m1-u11": { title: "Resumen", bodyHtml: `<p>Las operaciones DLP combinan contexto de Purview, correlación XDR, respuesta proporcional, documentación completa y ajuste continuo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-data-loss-prevention-alerts/summary" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen del módulo</small></span></a>` },
        },
      },
      "p9-module-2": {
        title: "Investigar alertas de riesgo interno y actividad relacionada",
        focus: "Enfoque: prioridad de alertas, ajuste de directivas, factores, escalas de actividad, correlación con Defender y casos.",
        units: {
          "p9m2-u1": { title: "Introducción", bodyHtml: `<p>Insider Risk Management correlaciona señales de daño accidental o intencional por personas con acceso legítimo. La investigación equilibra seguridad, privacidad, requisitos legales y acceso por necesidad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de riesgo interno</small></span></a>` },
          "p9m2-u2": { title: "Comprender las alertas e investigaciones de riesgo interno", bodyHtml: `<p>Las directivas combinan desencadenadores, indicadores, usuarios, ventanas y umbrales. Las alertas representan patrones puntuados, no prueba de mala conducta. El triage debe probar contexto y evidencia preservando privacidad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/understand-insider-risk-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Señales, directivas y alertas</small></span></a>` },
          "p9m2-u3": { title: "Administrar el volumen de alertas de riesgo interno", bodyHtml: `<p>Controlá volumen mediante alcance, indicadores, umbrales, desencadenadores, ventanas, exclusiones y recomendaciones de estado. Ajustá desde falsos positivos y riesgos omitidos, no suprimiendo fuentes de gran volumen sin análisis.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/manage-alert-volume" target="_blank" rel="noopener"><span>Lección oficial<small>Umbrales y calidad de cola</small></span></a>` },
          "p9m2-u4": { title: "Investigar y realizar triage en Microsoft Purview", bodyHtml: `<p>Priorizá por gravedad, puntuación, directiva, tiempo y estado. Abrí para inspeccionar indicadores, desencadenadores, usuario, cronología y contenido. Descartá alertas benignas o creá un caso para análisis profundo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/investigate-triage-alerts" target="_blank" rel="noopener"><span>Lección oficial<small>Panel y triage</small></span></a>` },
          "p9m2-u5": { title: "Investigar riesgo interno con Security Copilot y agentes", bodyHtml: `<p>Copilot resume alertas, patrones y factores; los agentes aceleran análisis repetible. Confirmá resultados contra registros, respetá privacidad y mantené responsabilidad humana.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/investigate-alerts-security-copilot-agents" target="_blank" rel="noopener"><span>Lección oficial<small>Investigación asistida por IA</small></span></a>` },
          "p9m2-u6": { title: "Analizar el contexto con Todos los factores de riesgo", bodyHtml: `<p>La pestaña agrega indicadores y eventos para explicar el aumento de puntuación, comparar categorías e identificar pivotes valiosos. Distinguí un evento aislado de un patrón sostenido con varias señales.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/all-risk-factors-tab" target="_blank" rel="noopener"><span>Lección oficial<small>Contexto de factores</small></span></a>` },
          "p9m2-u7": { title: "Investigar detalles con Activity explorer", bodyHtml: `<p>Activity explorer muestra eventos con filtros de fecha, tipo, aplicación, dispositivo, dominio y más. Validá operaciones exactas e identificá archivos, destinos, volumen y secuencias.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/activity-explorer-tab" target="_blank" rel="noopener"><span>Lección oficial<small>Análisis de eventos</small></span></a>` },
          "p9m2-u8": { title: "Revisar patrones con la pestaña Actividad del usuario", bodyHtml: `<p>La vista ubica alertas, indicadores y eventos en una escala. Buscá desvíos, ráfagas antes de una salida, movimiento entre canales y acciones repetidas que juntas son significativas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/user-activity-tab" target="_blank" rel="noopener"><span>Lección oficial<small>Escala de comportamiento</small></span></a>` },
          "p9m2-u9": { title: "Investigar alertas de riesgo interno en Microsoft Defender XDR", bodyHtml: `<p>Pasá a Defender XDR cuando pueda conectarse con identidad comprometida, malware, abuso de aplicaciones u otro incidente. Correlacioná usuario, dispositivos, alertas, archivos, red y escala antes de atribuir intención.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/investigate-alerts-defender" target="_blank" rel="noopener"><span>Lección oficial<small>Correlación con XDR</small></span></a>` },
          "p9m2-u10": { title: "Administrar y actuar sobre casos de riesgo interno", bodyHtml: `<p>Creá un caso, asigná colaboradores, agregá alertas/evidencia, documentá notas y coordiná acciones permitidas: notificación, escalamiento, RR. HH., legal o respuesta de seguridad. Resolvé con clasificación y auditoría precisas. Usá grupos de roles, privacidad y seudonimización cuando corresponda.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/insider-risk-cases" target="_blank" rel="noopener"><span>Lección oficial<small>Ciclo y acciones del caso</small></span></a>` },
          "p9m2-u11": { title: "Ejercicio: investigar posible robo de datos", bodyHtml: `<p>Realizá triage, inspeccioná factores y actividad, revisá la escala del usuario, correlacioná contexto, creá o actualizá un caso y documentá un resultado proporcional.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/exercise-investigate-alert" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Investigación de robo potencial</small></span></a>` },
          "p9m2-u12": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá desencadenadores, indicadores, puntuación, umbrales, ajuste de cola, pestañas, Copilot, pivotes XDR, privacidad y acciones de casos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de riesgo interno</small></span></a>` },
          "p9m2-u13": { title: "Resumen", bodyHtml: `<p>Las investigaciones requieren evidencia contextual, atribución cuidadosa, acceso consciente de privacidad, gobernanza entre equipos, acción proporcional y ajuste basado en resultados.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-insider-risk-investigate-alerts/summary" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen del módulo</small></span></a>` },
        },
      },
      "p9-module-3": {
        title: "Buscar e investigar con Microsoft Purview Audit",
        focus: "Enfoque: capacidades Standard/Premium, configuración, búsquedas, eventos de Copilot, exportaciones, PowerShell y retención.",
        units: {
          "p9m3-u1": { title: "Introducción", bodyHtml: `<p>Purview Audit registra actividades de usuarios y administradores de Microsoft 365 para investigaciones, solución de problemas, análisis de seguridad y evidencia normativa.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de auditoría</small></span></a>` },
          "p9m3-u2": { title: "Introducción a Microsoft Purview Audit", bodyHtml: `<table><thead><tr><th>Capacidad</th><th>Standard</th><th>Premium</th></tr></thead><tbody><tr><td>Búsqueda, CSV, PowerShell y API</td><td>Sí</td><td>Sí</td></tr><tr><td>Retención predeterminada</td><td>Normalmente 180 días</td><td>Un año para cargas clave</td></tr><tr><td>Directivas personalizadas</td><td>No</td><td>Sí; más tiempo con licencia</td></tr><tr><td>Conclusiones de alto valor/mayor API</td><td>No</td><td>Sí</td></tr></tbody></table><p>Las funciones y retención pueden cambiar; verificá derechos actuales del tenant.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-overview" target="_blank" rel="noopener"><span>Lección oficial<small>Standard frente a Premium</small></span></a>` },
          "p9m3-u3": { title: "Configurar y administrar Microsoft Purview Audit", bodyHtml: `<p>Asigná grupos de roles con privilegios mínimos, verificá auditoría, comprendé cobertura y esquema y usá portal, PowerShell, API o Graph según corresponda. Protegé las exportaciones como datos sensibles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-configure-manage" target="_blank" rel="noopener"><span>Lección oficial<small>Permisos y administración</small></span></a>` },
          "p9m3-u4": { title: "Realizar búsquedas con Audit (Standard)", bodyHtml: `<p>Definí intervalo UTC, usuarios, cargas y actividades; nombrá y ejecutá. Revisá operación, tipo, actor, destino, IP y campos de la carga. Refiná o usá <code>Search-UnifiedAuditLog</code>. Guardá/exportá con notas. Las búsquedas amplias pueden requerir paginación; documentá parámetros.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-standard-search" target="_blank" rel="noopener"><span>Lección oficial<small>Búsquedas en portal y PowerShell</small></span></a>` },
          "p9m3-u5": { title: "Auditar interacciones de Microsoft Copilot para Microsoft 365", bodyHtml: `<p>Las interacciones de Copilot y aplicaciones compatibles aparecen en el registro unificado con operaciones y tipos de evento. Los campos incluyen aplicación, usuario, hilo/sesión y recursos accedidos. Son metadatos de actividad, no necesariamente prompts y respuestas completos; interpretá según licencias, carga y privacidad.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-copilot" target="_blank" rel="noopener"><span>Lección oficial<small>Eventos de Copilot</small></span></a>` },
          "p9m3-u6": { title: "Investigar actividades con Audit (Premium)", bodyHtml: `<p>Premium ofrece mayor retención y eventos forenses de alto valor, como acceso granular al correo y búsquedas. Construí escala, identificá elementos y actores, correlacioná IP/sesión y distinguí acceso normal de patrones sospechosos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-premium-investigate" target="_blank" rel="noopener"><span>Lección oficial<small>Eventos forenses de alto valor</small></span></a>` },
          "p9m3-u7": { title: "Exportar datos del registro de auditoría", bodyHtml: `<p>Exportá a CSV o usá PowerShell/API para recopilación repetible y paginada. Preservá criterios, hora, zona, filas, hashes cuando se requieran y controles de acceso para integridad de evidencia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-export" target="_blank" rel="noopener"><span>Lección oficial<small>Exportar y preservar evidencia</small></span></a>` },
          "p9m3-u8": { title: "Configurar retención con Audit (Premium)", bodyHtml: `<p>Las directivas definen usuarios, tipos, actividad, duración y prioridad. Gana la de mayor prioridad cuando se superponen. Afectan registros nuevos, no extienden retroactivamente los existentes. Alineá con investigaciones, obligaciones, licencias, minimización y estrategia de almacenamiento/API.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/audit-premium-retention" target="_blank" rel="noopener"><span>Lección oficial<small>Directivas y prioridad</small></span></a>` },
          "p9m3-u9": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá diferencias Standard/Premium, roles, filtros, PowerShell, Copilot, eventos de alto valor, exportación y retención con prioridad y comportamiento no retroactivo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de Audit</small></span></a>` },
          "p9m3-u10": { title: "Resumen", bodyHtml: `<p>Audit permite investigaciones defendibles cuando el acceso está gobernado, las búsquedas son reproducibles, las exportaciones conservan contexto y la retención se planifica antes del incidente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-audit-search-investigate/summary" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen del módulo</small></span></a>` },
        },
      },
      "p9-module-4": {
        title: "Buscar contenido con Microsoft Purview eDiscovery",
        focus: "Enfoque: roles, casos, custodios y fuentes, diseño de consultas, validación y exportación.",
        units: {
          "p9m4-u1": { title: "Introducción", bodyHtml: `<p>Purview eDiscovery busca contenido de Microsoft 365 para investigaciones legales, normativas, de RR. HH. y seguridad. Los casos organizan usuarios autorizados, búsquedas, fuentes, retenciones, revisión y exportaciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de eDiscovery</small></span></a>` },
          "p9m4-u2": { title: "Comprender eDiscovery y búsqueda de contenido", bodyHtml: `<p>Busca buzones de Exchange, archivos SharePoint/OneDrive, contenido de Teams y otros datos. eDiscovery agrega permisos por caso, preservación, revisión, análisis y exportación según licencia. La búsqueda encuentra elementos potencialmente relevantes; la relevancia legal sigue siendo humana.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/understand-ediscovery" target="_blank" rel="noopener"><span>Lección oficial<small>Ubicaciones y capacidades</small></span></a>` },
          "p9m4-u3": { title: "Requisitos previos para usar eDiscovery", bodyHtml: `<p>Asigná roles apropiados, confirmá licencia, creá el caso, agregá miembros autorizados e identificá custodios, fuentes no custodiadas, ubicaciones, fechas y preservación. Separá administración, investigación, revisión y exportación cuando corresponda. El acceso expone contenido muy sensible.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/ediscovery-prerequisites" target="_blank" rel="noopener"><span>Lección oficial<small>Roles, licencias y caso</small></span></a>` },
          "p9m4-u4": { title: "Crear una búsqueda de eDiscovery", bodyHtml: `<p>Creá o abrí un caso y agregá miembros. Seleccioná custodios, buzones, sitios y fuentes. Definí palabras, propiedades, condiciones y fechas. Usá asistencia de Copilot solo como borrador. Nombrá, guardá y documentá propósito y versión. Usá paréntesis y lógica booleana con cuidado.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/create-ediscovery-search" target="_blank" rel="noopener"><span>Lección oficial<small>Fuentes y construcción</small></span></a>` },
          "p9m4-u5": { title: "Realizar una búsqueda de eDiscovery", bodyHtml: `<p>Ejecutá y usá estadísticas, informes de palabras, conteos y muestras aleatorias para validar la población. Refiná conservando versiones y motivos. Revisá falsos positivos, sinónimos, fechas, zonas, tipos, participantes, duplicados y cobertura antes de exportar.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/conduct-ediscovery-search" target="_blank" rel="noopener"><span>Lección oficial<small>Ejecutar y validar</small></span></a>` },
          "p9m4-u6": { title: "Exportar resultados de eDiscovery", bodyHtml: `<p>Configurá contenido y metadatos, iniciá, monitoreá y descargá mediante el flujo autorizado. Preservá caso, versión, configuración, conteos, errores, tiempos y cadena de custodia. Restringí almacenamiento, transferencia, revisión y retención.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/export-results" target="_blank" rel="noopener"><span>Lección oficial<small>Exportación y evidencia</small></span></a>` },
          "p9m4-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá roles/licencias, miembros, custodios/fuentes, sintaxis y Copilot, estadísticas/muestras, validación iterativa, exportación y protección.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de eDiscovery</small></span></a>` },
          "p9m4-u8": { title: "Resumen y recursos", bodyHtml: `<p>Una búsqueda defendible está autorizada, acotada, versionada, validada con estadísticas y muestras, exportada con metadatos y protegida durante todo el ciclo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/purview-ediscovery-search/summary" target="_blank" rel="noopener"><span>Lección oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
  "path-7": {
    title: "Crear detecciones y realizar investigaciones con Microsoft Sentinel",
    meta: "8 módulos · 56 unidades · Análisis, automatización, cuadernos de estrategias, incidentes, UEBA, ASIM, libros y administración de contenido",
    focusAreas: [
      { title: "Detección y respuesta", description: "Creá reglas de análisis, automatizá el triage, ejecutá cuadernos de estrategias y administrá incidentes de seguridad." },
      { title: "Análisis y contenido", description: "Aplicá UEBA, ASIM, KQL, libros, soluciones del Centro de contenido e implementación basada en repositorios." },
    ],
    modules: {
      "p7-module-1": {
        title: "Detección de amenazas con análisis de Microsoft Sentinel",
        focus: "Enfoque: tipos de reglas, plantillas, lógica personalizada, creación de incidentes, entidades y administración del ciclo de vida.",
        units: {
          "p7m1-u1": { title: "Introducción", bodyHtml: `<p>Los análisis de Sentinel convierten la telemetría ingerida en alertas e incidentes. Elegí un método de detección, definí una lógica accionable, asigná entidades, ajustá el ruido y mantené la regla a medida que evolucionan las amenazas y las fuentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos y requisitos previos</small></span></a>` },
          "p7m1-u2": { title: "Ejercicio: detectar amenazas con los análisis de Microsoft Sentinel", bodyHtml: `<p>Implementá un área de trabajo de Sentinel y una VM de prueba, instalá la solución Azure Activity y conectá la actividad de la suscripción mediante Azure Policy. Conservá los recursos para el ejercicio posterior y monitoreá los costos de Azure.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/2-exercise-setup" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Preparar el laboratorio</small></span></a>` },
          "p7m1-u3": { title: "¿Qué son los análisis de Microsoft Sentinel?", bodyHtml: `<p>Los análisis correlacionan señales de endpoints, identidades, redes, servicios en la nube e inteligencia sobre amenazas. Los casos de uso incluyen cuentas comprometidas, comportamientos sospechosos, filtración, amenazas internas, investigación y búsqueda de amenazas. Filtrá las plantillas por gravedad, tipo, tácticas de ATT&amp;CK y origen.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/3-azure-sentinel-analytics-overview" target="_blank" rel="noopener"><span>Lección oficial<small>Propósito y página de análisis</small></span></a>` },
          "p7m1-u4": { title: "Tipos de reglas de análisis", bodyHtml: `<table><thead><tr><th>Tipo</th><th>Uso</th></tr></thead><tbody><tr><td>Programada / NRT</td><td>KQL personalizado con una programación o casi en tiempo real.</td></tr><tr><td>Fusion</td><td>Correlación mediante ML de señales de baja fidelidad en incidentes de varias etapas.</td></tr><tr><td>Seguridad de Microsoft</td><td>Incidentes provenientes de alertas de seguridad de Microsoft conectadas.</td></tr><tr><td>ML / anomalía</td><td>Detecciones de comportamiento administradas por Microsoft.</td></tr><tr><td>Inteligencia sobre amenazas</td><td>Coincidencias de observables con eventos de la organización.</td></tr></tbody></table><div class="takeaway"><strong>Clave para el examen:</strong> las reglas programadas se pueden personalizar; la lógica administrada de Fusion y ML no.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/4-analytics-rules" target="_blank" rel="noopener"><span>Lección oficial<small>Familias de reglas de análisis</small></span></a>` },
          "p7m1-u5": { title: "Crear una regla de análisis a partir de plantillas", bodyHtml: `<p>Las plantillas muestran la gravedad, las fuentes necesarias, la asignación de ATT&amp;CK y el tipo de regla. Las plantillas programadas y de seguridad de Microsoft permiten ajustar la consulta o los filtros de alertas; las de Fusion y ML generalmente solo se habilitan o deshabilitan. Si Crear regla está deshabilitado, suele faltar un conector.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/5-create-rule-from-templates" target="_blank" rel="noopener"><span>Lección oficial<small>Flujo con plantillas</small></span></a>` },
          "p7m1-u6": { title: "Crear una regla de análisis con el asistente", bodyHtml: `<ol><li>Definí metadatos, gravedad y asignación de ATT&amp;CK.</li><li>Ingresá KQL y configurá frecuencia, período de búsqueda, umbral y agrupación.</li><li>Asigná columnas de la consulta a entidades y detalles personalizados.</li><li>Configurá incidentes y respuesta automatizada.</li><li>Validá y monitoreá la regla.</li></ol><p>La asignación de entidades habilita correlación, grafos, escalas de tiempo y pivotes de investigación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/6-create-rule-from-wizard" target="_blank" rel="noopener"><span>Lección oficial<small>Asistente de reglas personalizadas</small></span></a>` },
          "p7m1-u7": { title: "Administrar reglas de análisis", bodyHtml: `<p>Habilitá, deshabilitá, editá, duplicá, exportá, eliminá y monitoreá reglas. Ajustá KQL, umbrales, agrupación, supresión y exclusiones con evidencia de falsos positivos y detecciones omitidas. Documentá responsables, dependencias de datos, volumen esperado e historial de cambios.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/7-manage-analytics-rules" target="_blank" rel="noopener"><span>Lección oficial<small>Ciclo de vida y ajuste de reglas</small></span></a>` },
          "p7m1-u8": { title: "Ejercicio: detectar amenazas con los análisis de Microsoft Sentinel", bodyHtml: `<p>Creá una detección para la eliminación exitosa de una VM de Azure, asigná las entidades del autor y la IP, generá actividad de prueba y verificá la alerta y el incidente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/8-exercise-detect-threats" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Crear y validar una detección</small></span></a>` },
          "p7m1-u9": { title: "Resumen", bodyHtml: `<p>Un análisis efectivo comienza con los datos correctos, usa el tipo de regla apropiado, asigna entidades, crea incidentes accionables y se mide y ajusta continuamente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/analyze-data-in-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y evaluación</small></span></a>` },
        },
      },
      "p7-module-2": {
        title: "Automatización en Microsoft Sentinel",
        focus: "Enfoque: desencadenadores de automatización, condiciones, acciones ordenadas, vencimiento y orquestación de incidentes.",
        units: {
          "p7m2-u1": { title: "Introducción", bodyHtml: `<p>La automatización reduce el triage repetitivo y coordina un tratamiento coherente de incidentes. Las reglas de automatización administran propiedades del incidente e invocan cuadernos de estrategias para una respuesta más amplia.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/automation-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de automatización</small></span></a>` },
          "p7m2-u2": { title: "Comprender las opciones de automatización", bodyHtml: `<p>Las reglas se desencadenan al crear o actualizar un incidente o al crear una alerta. Las condiciones pueden inspeccionar proveedor, regla, gravedad, estado, etiquetas y propietario. Las acciones nativas asignan propietarios, cambian estado o gravedad, agregan etiquetas y ejecutan cuadernos de estrategias. Usá estos últimos para API, enriquecimiento, notificaciones, tickets o contención.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/automation-microsoft-sentinel/2-understand-automation-options" target="_blank" rel="noopener"><span>Lección oficial<small>Reglas frente a cuadernos de estrategias</small></span></a>` },
          "p7m2-u3": { title: "Crear reglas de automatización", bodyHtml: `<ol><li>Seleccioná un desencadenador y condiciones acotadas.</li><li>Agregá las acciones en el orden previsto.</li><li>Definí el orden respecto de otras reglas.</li><li>Opcionalmente, configurá el vencimiento.</li><li>Habilitá, probá y monitoreá.</li></ol><p>El orden importa porque una regla anterior puede cambiar propiedades que evalúa una regla posterior.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/automation-microsoft-sentinel/3-create-automation-rules" target="_blank" rel="noopener"><span>Lección oficial<small>Crear y priorizar reglas</small></span></a>` },
          "p7m2-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá desencadenadores, condiciones, acciones nativas, ejecución de cuadernos de estrategias, orden, vencimiento y el límite entre la automatización de Sentinel y Logic Apps.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/automation-microsoft-sentinel/4-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de automatización</small></span></a>` },
          "p7m2-u5": { title: "Resumen y recursos", bodyHtml: `<p>Usá reglas de automatización explícitas para cambios deterministas y cuadernos de estrategias gobernados cuando un flujo atraviesa varios servicios o requiere lógica compleja.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/automation-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p7-module-3": {
        title: "Respuesta ante amenazas con cuadernos de estrategias de Microsoft Sentinel",
        focus: "Enfoque: SOAR con Logic Apps, desencadenadores de Sentinel, permisos y ejecución en tiempo real o a petición.",
        units: {
          "p7m3-u1": { title: "Introducción", bodyHtml: `<p>Los cuadernos de estrategias son flujos de Logic Apps para enriquecimiento, notificaciones, tickets, contención y corrección más allá de los cambios nativos en las propiedades del incidente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de SOAR</small></span></a>` },
          "p7m3-u2": { title: "Ejercicio: crear un cuaderno de estrategias de Microsoft Sentinel", bodyHtml: `<p>Implementá Sentinel y los recursos de prueba, conectá Azure Activity y creá una regla NRT para la eliminación exitosa de VM que genere incidentes para el ejercicio.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/2-exercise-setup" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Preparar los análisis y datos de prueba</small></span></a>` },
          "p7m3-u3": { title: "¿Qué son los cuadernos de estrategias de Microsoft Sentinel?", bodyHtml: `<p>Un cuaderno de estrategias tiene un desencadenador de Logic Apps seguido por condiciones y acciones. Los desencadenadores de Sentinel operan sobre incidentes, alertas o entidades; los conectores llaman servicios de Microsoft y de terceros. Preferí identidades administradas y RBAC con privilegios mínimos frente a credenciales personales.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/3-playbook-overview" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura de cuadernos de estrategias</small></span></a>` },
          "p7m3-u4": { title: "Desencadenar un cuaderno de estrategias en tiempo real", bodyHtml: `<p>Usá una regla de automatización para ejecutar un cuaderno desencadenado por incidentes o alertas. Otorgá a Sentinel permiso para ejecutar Logic Apps y a su identidad solo los permisos necesarios. Diseñá teniendo en cuenta idempotencia, reintentos, límites de velocidad, fallos parciales, registro y comentarios visibles en el incidente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/4-playbook-trigger" target="_blank" rel="noopener"><span>Lección oficial<small>Ejecución automatizada</small></span></a>` },
          "p7m3-u5": { title: "Ejecutar cuadernos de estrategias a petición", bodyHtml: `<p>Ejecutá manualmente los cuadernos aptos desde incidentes, alertas o entidades cuando el criterio del analista deba preceder a la respuesta. Esto es apropiado para enriquecimiento y contención de alto impacto que no debería ser automática.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/5-playbook-on-demand" target="_blank" rel="noopener"><span>Lección oficial<small>Respuesta manual</small></span></a>` },
          "p7m3-u6": { title: "Ejercicio: crear un cuaderno de estrategias de Microsoft Sentinel", bodyHtml: `<p>Creá una Logic App desencadenada por incidentes, agregá acciones de respuesta, autorizá las conexiones, vinculala mediante automatización, generá un incidente de prueba e inspeccioná el historial de ejecución.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/6-exercise-create-playbook" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Crear y probar un cuaderno de estrategias</small></span></a>` },
          "p7m3-u7": { title: "Resumen", bodyHtml: `<p>Una implementación segura de SOAR requiere privilegios mínimos, desencadenadores explícitos, reglas de automatización controladas, flujos resistentes y resultados de ejecución visibles.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/threat-response-sentinel-playbooks/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y evaluación</small></span></a>` },
        },
      },
      "p7-module-4": {
        title: "Administración de incidentes de seguridad en Microsoft Sentinel",
        focus: "Enfoque: estructura del incidente, evidencia, entidades, responsables, estado, gravedad, tareas y resolución.",
        units: {
          "p7m4-u1": { title: "Introducción", bodyHtml: `<p>Un incidente agrupa alertas, evidencia y entidades relacionadas en un caso. Los analistas realizan el triage, establecen el alcance, documentan hallazgos, responden y cierran con una clasificación precisa.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de incidentes</small></span></a>` },
          "p7m4-u2": { title: "Ejercicio: configurar el entorno de Azure", bodyHtml: `<p>Implementá el laboratorio, conectá Azure Activity, conservá el entorno y validá la llegada real de registros antes de depender del flujo de investigación.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/2-exercise-setup" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Preparar el laboratorio de investigación</small></span></a>` },
          "p7m4-u3": { title: "Comprender los incidentes", bodyHtml: `<p>Las alertas de análisis se convierten en incidentes cuando su creación está habilitada. Las alertas relacionadas pueden agruparse por entidades, tácticas, tiempo o configuración de la regla. Gravedad, estado, propietario, etiquetas, origen y marcas de tiempo ayudan al triage.</p><div class="takeaway"><strong>Clave para el examen:</strong> una alerta es una señal de detección; un incidente es el caso del analista que contiene una o más alertas.</div><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/3-describe-incident-management" target="_blank" rel="noopener"><span>Lección oficial<small>Alertas e incidentes</small></span></a>` },
          "p7m4-u4": { title: "Evidencia y entidades del incidente", bodyHtml: `<p>La evidencia incluye eventos, consultas, escalas de tiempo, comentarios, tareas, marcadores y entidades. La asignación de entidades crea pivotes como cuenta, host, IP, URL, archivo, proceso y recurso. Usá el grafo de investigación y las páginas de entidad para seguir relaciones y establecer una ruta de ataque.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/4-incident-evidence-entities" target="_blank" rel="noopener"><span>Lección oficial<small>Evidencia y pivotes del grafo</small></span></a>` },
          "p7m4-u5": { title: "Administración de incidentes", bodyHtml: `<ol><li>Asigná un responsable y validá la gravedad.</li><li>Definí el estado como Nuevo, Activo o Cerrado.</li><li>Usá etiquetas, comentarios y tareas para el traspaso.</li><li>Investigá alertas, entidades, escalas de tiempo e incidentes similares.</li><li>Ejecutá acciones de respuesta y cerrá con motivo y clasificación.</li></ol><p>Una clasificación precisa mejora las métricas y el ajuste.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/5-manage-incidents" target="_blank" rel="noopener"><span>Lección oficial<small>Desde el triage hasta el cierre</small></span></a>` },
          "p7m4-u6": { title: "Ejercicio: investigar un incidente", bodyHtml: `<p>Generá actividad sospechosa, encontrá el incidente, asignalo y activalo, examiná alertas y entidades, consultá los registros, documentá los hallazgos y resolvelo con la clasificación correcta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/6-exercise-investigate-incident" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Investigación integral</small></span></a>` },
          "p7m4-u7": { title: "Resumen", bodyHtml: `<p>Un flujo disciplinado preserva la evidencia, permite auditar las decisiones, acelera la respuesta y devuelve mejoras de calidad a las detecciones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/incident-management-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y evaluación</small></span></a>` },
        },
      },
      "p7-module-5": {
        title: "Identificar amenazas mediante análisis de comportamiento",
        focus: "Enfoque: líneas base de UEBA, entidades, escalas de tiempo, conclusiones de comportamiento, prioridad de investigación y anomalías.",
        units: {
          "p7m5-u1": { title: "Introducción", bodyHtml: `<p>El análisis de comportamiento de usuarios y entidades agrega contexto a usuarios, hosts, IP, aplicaciones y otras entidades para priorizar actividad que las reglas estáticas podrían omitir.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de UEBA</small></span></a>` },
          "p7m5-u2": { title: "Comprender el análisis de comportamiento", bodyHtml: `<p>Sentinel crea líneas base a partir del historial de entidades, grupos de pares, comportamiento de la organización, tiempo, ubicación, dispositivos y entornos. ML agrega contexto anómalo, sensibilidad, relaciones y posible radio de impacto. La puntuación de prioridad de investigación de 0 a 10 sirve para priorizar, no prueba un compromiso.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/2-understand-user-entity-behavior-analytics" target="_blank" rel="noopener"><span>Lección oficial<small>Líneas base y puntuación</small></span></a>` },
          "p7m5-u3": { title: "Explorar entidades", bodyHtml: `<p>Sentinel combina identificadores como GUID, UPN, nombre de cuenta y dominio cuando existe contexto suficiente. Las páginas de entidad reúnen datos identificativos, una escala de tiempo de alertas, marcadores y actividades, y conclusiones de Signin, Audit, Office, Syslog, SecurityEvent y BehaviorAnalytics.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/3-explore-entities" target="_blank" rel="noopener"><span>Lección oficial<small>Identidad y escalas de tiempo de entidades</small></span></a>` },
          "p7m5-u4": { title: "Mostrar información del comportamiento de entidades", bodyHtml: `<p>Buscá entidades y revisá el contexto de riesgo, las tendencias de actividad, los pares, las alertas relacionadas y las anomalías. Pasá desde incidentes o resultados de búsqueda a la misma vista de entidad para conservar conectado el contexto.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/4-display-entity-behavior-information" target="_blank" rel="noopener"><span>Lección oficial<small>Vistas de comportamiento de entidades</small></span></a>` },
          "p7m5-u5": { title: "Usar plantillas de reglas de análisis para detectar anomalías", bodyHtml: `<p>Las plantillas de anomalías usan ML administrado por Microsoft. Revisá fuentes necesarias, detalles de la anomalía, eventos contribuyentes y contexto de entidades; combiná la evidencia con otras señales en lugar de tratarla como un veredicto.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/4a-use-anomaly-detection-analytical-rule-templates" target="_blank" rel="noopener"><span>Lección oficial<small>Detecciones de anomalías administradas</small></span></a>` },
          "p7m5-u6": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá líneas base, comparación con pares, puntuación de prioridad, identificadores y combinación de entidades, páginas, escalas de tiempo, conclusiones e interpretación de anomalías.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/5-knowledge-check" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de análisis de comportamiento</small></span></a>` },
          "p7m5-u7": { title: "Resumen y recursos", bodyHtml: `<p>UEBA depende de una telemetría completa, una asignación correcta de entidades y la validación del contexto anómalo por parte del analista.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/use-entity-behavior-analytics-azure-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p7-module-6": {
        title: "Normalización de datos en Microsoft Sentinel",
        focus: "Enfoque: esquemas y analizadores ASIM, KQL parametrizado, analizadores personalizados y transformaciones de DCR.",
        units: {
          "p7m6-u1": { title: "Introducción", bodyHtml: `<p>La normalización asigna esquemas específicos de proveedores a un modelo semántico común para que una detección, búsqueda o libro funcione entre distintas fuentes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de ASIM</small></span></a>` },
          "p7m6-u2": { title: "Comprender la normalización de datos", bodyHtml: `<p>ASIM define esquemas, campos, valores, alias y analizadores para dominios como autenticación, red, DNS, procesos, archivos y actividad web. Los analizadores específicos traducen tablas nativas y los analizadores unificadores combinan las fuentes habilitadas.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/2-understand" target="_blank" rel="noopener"><span>Lección oficial<small>Arquitectura de ASIM</small></span></a>` },
          "p7m6-u3": { title: "Usar analizadores ASIM", bodyHtml: `<p>Llamá un analizador unificador ASIM como una función KQL y aplicá pronto los parámetros admitidos. Filtrar dentro del analizador suele ser más eficiente que hacerlo después de unir todas las fuentes.</p><pre><code>_Im_Authentication(starttime=ago(1d)) | where EventResult == "Failure" | summarize Attempts=count() by TargetUsername, SrcIpAddr</code></pre><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/3-use-asim-parsers" target="_blank" rel="noopener"><span>Lección oficial<small>Consultar datos normalizados</small></span></a>` },
          "p7m6-u4": { title: "Comprender las funciones KQL parametrizadas", bodyHtml: `<p>Las funciones almacenadas aceptan parámetros con tipo y devuelven datos tabulares. Usá parámetros para filtros de tiempo, origen, usuario, IP o gravedad. La lógica centralizada mejora la reutilización, pero los cambios afectan todas las reglas, libros y consultas dependientes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/4-understand-parameterized-kql-functions" target="_blank" rel="noopener"><span>Lección oficial<small>Funciones KQL reutilizables</small></span></a>` },
          "p7m6-u5": { title: "Crear un analizador ASIM", bodyHtml: `<ol><li>Seleccioná el esquema y asigná los campos nativos.</li><li>Normalizá valores y tipos.</li><li>Agregá parámetros de filtro y metadatos.</li><li>Probá registros representativos, incompletos y mal formados.</li><li>Incluí el analizador en el unificador apropiado.</li></ol><p>La calidad implica corrección semántica, cobertura, rendimiento y compatibilidad con contenido ASIM.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/5-create-asim-parser" target="_blank" rel="noopener"><span>Lección oficial<small>Crear un analizador personalizado</small></span></a>` },
          "p7m6-u6": { title: "Configurar reglas de recopilación de datos de Azure Monitor", bodyHtml: `<p>Las transformaciones de DCR usan KQL durante la ingesta para filtrar, remodelar, enriquecer o enrutar registros. La consulta comienza con <code>source</code> y debe devolver columnas compatibles con el destino. Filtrar puede reducir costos, pero los datos descartados no se recuperan.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/6-configure-azure-monitor-data-collection-rules" target="_blank" rel="noopener"><span>Lección oficial<small>Transformaciones de ingesta</small></span></a>` },
          "p7m6-u7": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá esquemas, analizadores de origen y unificadores, campos normalizados, funciones parametrizadas, creación de analizadores, transformaciones de DCR y filtrado permanente durante la ingesta.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de normalización</small></span></a>` },
          "p7m6-u8": { title: "Resumen y recursos", bodyHtml: `<p>ASIM vuelve portátil el contenido; los analizadores parametrizados mejoran el rendimiento y las transformaciones de DCR controlan los datos antes de almacenarlos en el área de trabajo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/data-normalization-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
      "p7-module-7": {
        title: "Consultar, visualizar y monitorear datos en Microsoft Sentinel",
        focus: "Enfoque: Registros, KQL, plantillas de libros, visualizaciones personalizadas y parámetros.",
        units: {
          "p7m7-u1": { title: "Introducción", bodyHtml: `<p>Registros permite el análisis ad hoc; los libros convierten KQL en vistas interactivas reutilizables para monitoreo, investigación e informes.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Objetivos de consulta y visualización</small></span></a>` },
          "p7m7-u2": { title: "Ejercicio: consultar y visualizar datos con libros de Microsoft Sentinel", bodyHtml: `<p>Implementá el laboratorio de Sentinel y el conector Azure Activity. Confirmá los registros en <code>AzureActivity</code> antes de crear elementos del libro.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/2-exercise-setup" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Preparar datos para el libro</small></span></a>` },
          "p7m7-u3": { title: "Monitorear y visualizar datos", bodyHtml: `<p>Los libros combinan texto, parámetros, KQL, métricas, vínculos, pestañas y visualizaciones. Usá gráficos para comparaciones y tendencias, cuadrículas para registros exactos y conservá el acceso a la evidencia subyacente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/3-monitor-visualize-data" target="_blank" rel="noopener"><span>Lección oficial<small>Capacidades de los libros</small></span></a>` },
          "p7m7-u4": { title: "Consultar datos mediante Kusto Query Language", bodyHtml: `<p>Comenzá con la tabla y el intervalo de tiempo correctos, filtrá pronto, proyectá las columnas necesarias, derivá campos, agregá y ordená resultados. Validá el costo y el significado antes de incorporar consultas al contenido.</p><pre><code>AzureActivity | where TimeGenerated &gt; ago(24h) | summarize Operations=count() by Caller, ActivityStatusValue</code></pre><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/4-query-data" target="_blank" rel="noopener"><span>Lección oficial<small>KQL en Registros</small></span></a>` },
          "p7m7-u5": { title: "Usar libros predeterminados de Microsoft Sentinel", bodyHtml: `<p>Las soluciones del Centro de contenido instalan plantillas de libros. Guardá una plantilla, confirmá que las tablas necesarias tengan datos y revisá los parámetros y consultas antes de confiar en sus visualizaciones. Las copias guardadas son recursos de Azure editables.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/5-workbooks" target="_blank" rel="noopener"><span>Lección oficial<small>Plantillas de libros</small></span></a>` },
          "p7m7-u6": { title: "Crear un nuevo libro de Microsoft Sentinel", bodyHtml: `<ol><li>Definí la audiencia y la pregunta.</li><li>Agregá parámetros de tiempo o selección.</li><li>Agregá KQL y visualizaciones adecuadas.</li><li>Referenciá los parámetros de forma segura.</li><li>Guardá con una ubicación de recurso y control de acceso apropiados.</li></ol><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/6-create-new-workbook" target="_blank" rel="noopener"><span>Lección oficial<small>Libros personalizados</small></span></a>` },
          "p7m7-u7": { title: "Ejercicio: visualizar datos con libros de Microsoft Sentinel", bodyHtml: `<p>Explorá los registros de Azure Activity, guardá su plantilla de libro, usá filtros y tablas, entrá en modo de edición y agregá un parámetro respaldado por KQL para impulsar el análisis interactivo.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/7-exercise-visualize-data" target="_blank" rel="noopener"><span>Ejercicio oficial<small>Vista interactiva de un libro</small></span></a>` },
          "p7m7-u8": { title: "Resumen", bodyHtml: `<p>Los libros confiables usan KQL validado, parámetros relevantes, una codificación visual apropiada, acceso a la evidencia y gobernanza de recursos de Azure.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/query-data-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y evaluación</small></span></a>` },
        },
      },
      "p7-module-8": {
        title: "Administrar contenido en Microsoft Sentinel",
        focus: "Enfoque: soluciones del Centro de contenido e implementación de contenido basada en repositorios.",
        units: {
          "p7m8-u1": { title: "Introducción", bodyHtml: `<p>El contenido de Sentinel incluye conectores, análisis, consultas de búsqueda de amenazas, libros, analizadores, listas de seguimiento, automatización y cuadernos de estrategias. El Centro de contenido empaqueta soluciones y los repositorios permiten implementarlas con control de versiones.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-content-microsoft-sentinel/1-introduction" target="_blank" rel="noopener"><span>Lección oficial<small>Objetivos de contenido</small></span></a>` },
          "p7m8-u2": { title: "Usar soluciones del Centro de contenido", bodyHtml: `<p>Buscá por producto, proveedor, modelo de soporte, tipo o estado. Instalá una solución, revisá contenido y dependencias, configurá conectores y habilitá solamente las reglas necesarias. Revisá las notas de versión y personalizaciones antes de actualizar o quitar.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-content-microsoft-sentinel/2-use-solutions-from-content-hub" target="_blank" rel="noopener"><span>Lección oficial<small>Ciclo de vida de soluciones</small></span></a>` },
          "p7m8-u3": { title: "Usar repositorios para la implementación", bodyHtml: `<p>Conectá GitHub o Azure DevOps, seleccioná rutas de contenido y usá el flujo o pipeline generado para validar e implementar contenido compatible. Protegé branches, exigí revisión, separá desarrollo y producción, mantené secretos fuera del código fuente y monitoreá fallos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-content-microsoft-sentinel/3-use-repositories-for-deployment" target="_blank" rel="noopener"><span>Lección oficial<small>Contenido de Sentinel como código</small></span></a>` },
          "p7m8-u4": { title: "Evaluación del módulo", bodyHtml: `<p>Revisá el descubrimiento y ciclo de vida del Centro de contenido, las dependencias de soluciones, los tipos de contenido, las conexiones a repositorios, la implementación automatizada y la gobernanza del control de código fuente.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-content-microsoft-sentinel/" target="_blank" rel="noopener"><span>Evaluación oficial<small>Comprobación de contenido</small></span></a>` },
          "p7m8-u5": { title: "Resumen y recursos", bodyHtml: `<p>Usá el Centro de contenido para paquetes compatibles y repositorios para implementar contenido personalizado de forma controlada y repetible entre entornos.</p><a class="resource" href="https://learn.microsoft.com/en-us/training/modules/manage-content-microsoft-sentinel/" target="_blank" rel="noopener"><span>Módulo oficial<small>Resumen y recursos</small></span></a>` },
        },
      },
    },
  },
};

